const request = require('supertest');
const express = require('express');

jest.mock('../db', () => {
  const insert = jest.fn().mockResolvedValue([1]);
  const db = jest.fn(() => ({ insert }));
  db._insert = insert;
  return db;
});

jest.mock('../proxy-config', () => ({
  authServiceUrl: 'http://auth-mock:5010'
}));

global.fetch = jest.fn();

const { startImpersonation, stopImpersonation, getImpersonationTargets, getImpersonationLog } = require('../controllers/impersonation.controller');

function makeApp(handler, user = { id: 'admin-1', email: 'admin@test.com' }) {
  const app = express();
  app.use(express.json());
  app.use((req, res, next) => { req.user = user; next(); });
  app.post('/test', handler);
  app.get('/test', handler);
  return app;
}

beforeEach(() => {
  jest.clearAllMocks();
  process.env.INTERNAL_SERVICE_KEY = 'test-internal-key';
});

describe('startImpersonation', () => {
  it('returns 400 when targetUserId is missing', async () => {
    const res = await request(makeApp(startImpersonation)).post('/test').send({});
    expect(res.status).toBe(400);
    expect(res.body.error).toMatch(/targetUserId/i);
  });

  it('returns 400 when admin tries to impersonate themselves', async () => {
    const res = await request(makeApp(startImpersonation)).post('/test').send({ targetUserId: 'admin-1' });
    expect(res.status).toBe(400);
    expect(res.body.error).toMatch(/yourself/i);
  });

  it('proxies to auth-service and returns token on success', async () => {
    const authResp = {
      access_token: 'imp-tok',
      expires_in: 3600,
      impersonating: { id: 'u2', email: 'user@test.com', name: 'User' }
    };
    global.fetch.mockResolvedValueOnce({
      ok: true,
      text: async () => JSON.stringify(authResp)
    });

    const res = await request(makeApp(startImpersonation))
      .post('/test')
      .send({ targetUserId: 'u2', reason: 'support' });

    expect(res.status).toBe(200);
    expect(res.body.accessToken).toBe('imp-tok');
    expect(res.body.impersonating.id).toBe('u2');
    const db = require('../db');
    expect(db._insert).toHaveBeenCalledWith(expect.objectContaining({
      admin_user_id: 'admin-1',
      target_user_id: 'u2',
      action: 'start_impersonation'
    }));
  });

  it('returns 503 when auth-service is unreachable', async () => {
    global.fetch.mockRejectedValueOnce(new Error('connection refused'));
    const res = await request(makeApp(startImpersonation))
      .post('/test')
      .send({ targetUserId: 'u2' });
    expect(res.status).toBe(503);
  });

  it('forwards 4xx errors from auth-service', async () => {
    global.fetch.mockResolvedValueOnce({
      ok: false,
      status: 403,
      text: async () => JSON.stringify({ error: 'Cannot impersonate admin users' })
    });
    const res = await request(makeApp(startImpersonation))
      .post('/test')
      .send({ targetUserId: 'u2' });
    expect(res.status).toBe(403);
  });
});

describe('stopImpersonation', () => {
  it('records audit row and returns message', async () => {
    const res = await request(makeApp(stopImpersonation)).post('/test').send({});
    expect(res.status).toBe(200);
    expect(res.body.message).toBeDefined();
    const db = require('../db');
    expect(db._insert).toHaveBeenCalledWith(expect.objectContaining({
      admin_user_id: 'admin-1',
      action: 'stop_impersonation'
    }));
  });
});

describe('getImpersonationTargets', () => {
  function makeTargetsDb(users = [], count = 0) {
    const db = require('../db');
    // Build a clone object that handles clearSelect().count()
    const makeClone = () => ({
      clearSelect: jest.fn().mockReturnThis(),
      count: jest.fn().mockResolvedValue([{ count }]),
      where: jest.fn().mockReturnThis(),
    });
    const chain = {
      select: jest.fn().mockReturnThis(),
      where: jest.fn().mockReturnThis(),
      orderBy: jest.fn().mockReturnThis(),
      limit: jest.fn().mockReturnThis(),
      offset: jest.fn().mockResolvedValue(users),
      clone: jest.fn(makeClone),
    };
    db.mockReturnValueOnce(chain);
    return chain;
  }

  it('returns paginated users', async () => {
    makeTargetsDb([{ id: 'u1', email: 'a@test.com', created_at: '2026-01-01' }], 1);
    const res = await request(makeApp(getImpersonationTargets)).get('/test');
    expect(res.status).toBe(200);
    expect(res.body.users).toHaveLength(1);
    expect(res.body.pagination.total).toBe(1);
    expect(res.body.pagination.hasMore).toBe(false);
  });

  it('clamps limit to 100', async () => {
    makeTargetsDb([], 0);
    const res = await request(makeApp(getImpersonationTargets)).get('/test?limit=500&offset=0');
    expect(res.status).toBe(200);
    expect(res.body.pagination.limit).toBe(100);
  });

  it('enforces minimum limit of 1 for limit=0', async () => {
    makeTargetsDb([], 0);
    const res = await request(makeApp(getImpersonationTargets)).get('/test?limit=0&offset=0');
    expect(res.status).toBe(200);
    expect(res.body.pagination.limit).toBe(1);
  });
});

/**
 * StriveRS backend — Express application
 */

const express = require('express');
const compression = require('compression');
const helmet = require('helmet');
const cors = require('cors');
const cookieParser = require('cookie-parser');
const bodyParser = require('body-parser');
const morgan = require('morgan');
const rateLimit = require('express-rate-limit');
const { maybeRedisStore } = require('./lib/rate-limit-store');

const { createLogger } = require('@resume-optimizer/lib-logger');
const logger = createLogger('app');

const taskRoutes = require('./routes/task.routes');
const configRoutes = require('./routes/config.routes');
const projectRoutes = require('./routes/project.routes');
const locationRoutes = require('./routes/location.routes');
const toolRoutes = require('./routes/tool.routes');
const dataRoutes = require('./routes/data.routes');
const gcalRoutes = require('./routes/gcal.routes');
const msftCalRoutes = require('./routes/msft-cal.routes');
const appleCalRoutes = require('./routes/apple-cal.routes');
const calSyncRoutes = require('./routes/cal-sync.routes');
const scheduleRoutes = require('./routes/schedule.routes');
const healthRoutes = require('./routes/health.routes');
const aiRoutes = require('./routes/ai.routes');
const weatherRoutes = require('./routes/weather.routes');
const impersonationRoutes = require('./routes/impersonation.routes');

// MCP + OAuth (shared module — auth-service handles OAuth, we proxy)
const { createOAuthProxyRoutes } = require('auth-client/mcp-auth');
const mcpTransport = require('./mcp/transport');

const app = express();

// Trust proxy for Cloud Run
app.set('trust proxy', 1);

// Middleware
app.use(helmet());
app.use(compression({
  filter: (req, res) => {
    if (res.getHeader('Content-Type') === 'text/event-stream') return false;
    return compression.filter(req, res);
  }
}));

// CORS. Allow configured FRONTEND_URL entries (trimmed, comma-split) +
// any localhost/127.0.0.1/[::1] origin (dev loopback is never reachable
// from outside the dev machine) + *.localdev.test + explicit
// CORS_ALLOW_ANY_ORIGIN=true opt-in.
const allowedOrigins = (process.env.FRONTEND_URL || 'http://localhost:3000')
  .split(',')
  .map(s => s.trim())
  .filter(Boolean);
const LOOPBACK_ORIGIN = /^https?:\/\/(localhost|127\.0\.0\.1|\[::1\])(?::\d+)?$/i;
app.use(cors({
  origin: function (origin, callback) {
    if (!origin) return callback(null, true);
    if (allowedOrigins.indexOf(origin) !== -1) return callback(null, true);
    if (LOOPBACK_ORIGIN.test(origin) || origin.includes('localdev')) return callback(null, true);
    if (process.env.CORS_ALLOW_ANY_ORIGIN === 'true' && process.env.NODE_ENV !== 'production') return callback(null, true);
    return callback(null, false);
  },
  credentials: true
}));

app.use(cookieParser());

// Raw body capture for billing webhook HMAC — must be before bodyParser.json
app.use('/api/billing-webhooks', express.raw({ type: 'application/json' }), function(req, res, next) {
  if (!Buffer.isBuffer(req.body)) {
    return res.status(415).json({ error: 'Content-Type must be application/json' });
  }
  req.rawBody = req.body;
  try {
    req.body = JSON.parse(req.body.toString('utf8'));
  } catch (e) {
    return res.status(400).json({ error: 'Invalid JSON body' });
  }
  next();
});

app.use(bodyParser.json({ limit: '1mb' }));
app.use(bodyParser.urlencoded({ extended: true }));
// NOTE: GET /api/events accepts JWT via ?token= query param (EventSource limitation).
// In dev, morgan logs the full URL including ?token=. This is acceptable in local dev
// but ensure production log export destinations are secure.
app.use(morgan('dev', {
  skip: function(req) {
    return req.path === '/api/events' && req.query.token;
  }
}));

// Sanitize error responses in production
if (process.env.NODE_ENV === 'production') {
  app.use((req, res, next) => {
    const originalJson = res.json.bind(res);
    res.json = function(body) {
      if (res.statusCode >= 500 && body && body.message) {
        body.message = 'An error occurred processing your request';
      }
      return originalJson(body);
    };
    next();
  });
}

// Without Redis, SSE fan-out degrades to local-only and the AI rate limiter
// falls back to per-instance counters.
if (!process.env.REDIS_URL) {
  logger.warn('[startup] REDIS_URL not set - SSE fan-out and AI rate limiter will be local-only (single-instance safe, not multi-instance safe)');
}

// Broad limiters stay per-instance by design (Category 4f — shared counters
// across instances would synchronize on every request at 1000/min with no
// meaningful protection gain). Only the strict AI limiter uses Redis.
const LIMITER_DEFAULTS = { windowMs: 60 * 1000, standardHeaders: true, legacyHeaders: false };
const apiLimiter = rateLimit({ ...LIMITER_DEFAULTS, max: 1000 });
const aiLimiter = rateLimit({ ...LIMITER_DEFAULTS, max: 20, store: maybeRedisStore('jugrl-ai:') });
const mcpLimiter = rateLimit({ ...LIMITER_DEFAULTS, max: 300 });
const oauthCallbackLimiter = rateLimit({ ...LIMITER_DEFAULTS, max: 20, message: { error: 'Too many requests, please wait.' } });
const billingWebhookLimiter = rateLimit({ ...LIMITER_DEFAULTS, max: 120, message: { error: 'Too many webhook calls.' } });
const healthLimiter = rateLimit({ ...LIMITER_DEFAULTS, max: 300 });
// Per-user write limiter — keys by user ID so shared NAT/proxies don't hit a common bucket.
// skip() passes through safe read-only methods so GETs aren't throttled.
const writeRateLimiter = rateLimit({
  ...LIMITER_DEFAULTS,
  max: 300,
  keyGenerator: (req) => (req.user && req.user.id) ? String(req.user.id) : req.ip,
  message: { error: 'Too many write requests, please slow down.' },
  skip: (req) => req.method === 'GET' || req.method === 'HEAD' || req.method === 'OPTIONS',
});

// OAuth proxy + discovery routes (auth-service handles Google SSO, etc.)
// Dev mode: auto-approve OAuth for MCP client testing
if (process.env.NODE_ENV === 'development') {
  app.get('/oauth/authorize', (req, res) => {
    const redirectUri = req.query.redirect_uri;
    const state = req.query.state;
    const code = 'dev-code-' + Date.now();
    if (!redirectUri) {
      return res.status(400).json({ error: 'invalid_request', error_description: 'redirect_uri required' });
    }
    var allowedHosts = ['localhost', '127.0.0.1'];
    var parsedUri;
    try { parsedUri = new URL(redirectUri); } catch (e) {
      return res.status(400).json({ error: 'invalid_request', error_description: 'redirect_uri is not a valid URL' });
    }
    if (!allowedHosts.includes(parsedUri.hostname)) {
      return res.status(400).json({ error: 'invalid_request', error_description: 'redirect_uri host not permitted' });
    }
    const sep = redirectUri.includes('?') ? '&' : '?';
    res.redirect(`${redirectUri}${sep}code=${encodeURIComponent(code)}&state=${encodeURIComponent(state || '')}`);
  });

  app.post('/oauth/token', (req, res) => {
    const code = req.body?.code || req.query?.code;
    if (code && code.startsWith('dev-code-')) {
      return res.json({
        access_token: 'dev-token',
        token_type: 'Bearer',
        expires_in: 3600
      });
    }
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Invalid authorization code' });
  });

  // Dev: static client registration (bypass auth-service rate limits)
  app.post('/oauth/register', (req, res) => {
    res.json({
      client_id: 'dev-client',
      client_secret: 'dev-secret',
      client_name: 'dev-client',
      redirect_uris: req.body?.redirect_uris,
      grant_types: ['authorization_code'],
      response_types: ['code'],
      token_endpoint_auth_method: 'client_secret_post'
    });
  });
}
createOAuthProxyRoutes(app, { mcpEndpoint: '/mcp' });

// MCP Streamable HTTP (stateless, own rate limit)
app.post('/mcp', mcpLimiter, mcpTransport.handlePost);
app.get('/mcp', mcpTransport.handleMethodNotAllowed);
app.delete('/mcp', mcpTransport.handleMethodNotAllowed);

// Minimal auth profile endpoint (auth handled by auth-service, but frontend needs /auth/me)
const { authenticateJWT } = require('./middleware/jwt-auth');
const db = require('./db');
app.get('/api/auth/me', authenticateJWT, async (req, res) => {
  // Load full user from DB (auth-client only puts id/email/name on req.user from JWT)
  const user = await db('users').where('id', req.user.id).first();
  if (!user) return res.status(404).json({ error: 'User not found' });
  res.json({
    user: {
      id: user.id,
      email: user.email,
      name: user.name,
      picture: user.picture_url
    }
  });
});

// SSE endpoint — real-time event stream for connected frontends
// EventSource doesn't support custom headers, so accept token as query param
const sseEmitter = require('./lib/sse-emitter');
app.get('/api/events', (req, res, next) => {
  // Accept token from query param (EventSource limitation) or Authorization header
  if (req.query.token && !req.headers.authorization) {
    req.headers.authorization = 'Bearer ' + req.query.token;
  }
  next();
}, authenticateJWT, (req, res) => {
  res.writeHead(200, {
    'Content-Type': 'text/event-stream',
    'Cache-Control': 'no-cache',
    'Connection': 'keep-alive',
    'X-Accel-Buffering': 'no' // disable nginx/Cloud Run buffering
  });
  // Send initial heartbeat so client knows connection is alive
  res.write('event: connected\ndata: {}\n\n');

  sseEmitter.addClient(req.user.id, res);

  // Heartbeat every 30s to keep connection alive through proxies
  const heartbeat = setInterval(() => {
    try { res.write(':\n\n'); } catch (e) { clearInterval(heartbeat); }
  }, 30000);

  req.on('close', () => clearInterval(heartbeat));
});

// Routes
// /health stays un-prefixed for load-balancer / infra probes.
// /api/health is the same router re-mounted so the authenticated frontend
// apiClient (baseURL=/api) can reach /api/health/detailed without bypassing
// its bearer-token interceptor.
// Mount-level auth guard on /api/health ensures defense-in-depth;
// individual routes that need user context still validate JWT per-route.
app.use('/health', healthLimiter, healthRoutes);
app.use('/api/health', authenticateJWT, healthLimiter, healthRoutes);
app.use('/api/ai', aiLimiter, aiRoutes);
app.use('/api/data/import', bodyParser.json({ limit: '2mb' }));
app.use('/api', apiLimiter);
app.use('/api/tasks', authenticateJWT, writeRateLimiter, taskRoutes);
app.use('/api/config', authenticateJWT, writeRateLimiter, configRoutes);
app.use('/api/projects', authenticateJWT, writeRateLimiter, projectRoutes);
app.use('/api/locations', authenticateJWT, writeRateLimiter, locationRoutes);
app.use('/api/tools', authenticateJWT, writeRateLimiter, toolRoutes);
app.use('/api/data', dataRoutes);
app.use('/api/gcal/callback', oauthCallbackLimiter);
app.use('/api/gcal', gcalRoutes);
app.use('/api/msft-cal/callback', oauthCallbackLimiter);
app.use('/api/msft-cal', msftCalRoutes);
app.use('/api/apple-cal', appleCalRoutes);
app.use('/api/cal', calSyncRoutes);
app.use('/api/schedule', scheduleRoutes);
app.use('/api/feature-catalog', require('./routes/feature-catalog.routes'));
app.use('/api/feature-events', require('./routes/feature-events.routes'));
app.use('/api/my-plan', require('./routes/my-plan.routes'));
app.use('/api/billing-webhooks', billingWebhookLimiter, require('./routes/billing-webhooks.routes'));
app.use('/api/weather', weatherRoutes);
app.use('/api/impersonation', impersonationRoutes);

// 404 handler
app.use((req, res) => {
  res.status(404).json({ error: 'Not found', path: req.path });
});

// Global error handler
app.use((err, req, res, _next) => {
  logger.error('Unhandled error:', { error: err });
  res.status(500).json({
    error: 'Internal server error',
    message: process.env.NODE_ENV === 'development' ? err.message : 'Something went wrong'
  });
});

module.exports = app;

/**
 * AI Controller — Gemini-powered natural language task commands
 *
 * Supports two backends:
 *   1. Vertex AI (USE_VERTEX_AI=true) — GCP service account, no rate limits
 *   2. Gemini API (default) — API key, has rate limits
 *
 * Per-user throttle:
 *   - 2 requests/minute (enforced by express-rate-limit in routes/ai.routes.js)
 *   - 50 requests/day  (enforced here via ai_command_log table)
 */

const db = require('../db');
const { trackedGeminiCall } = require('../services/gemini-tracked-call');
const AI_USE_CASES = require('../constants/ai-use-cases');

const GEMINI_API_KEY = process.env.GEMINI_API_KEY || '';
const GEMINI_MODEL = process.env.GEMINI_MODEL || 'gemini-2.5-flash';
const USE_VERTEX_AI = process.env.USE_VERTEX_AI === 'true';
const AI_DAILY_LIMIT = 50;

let _genAIClient = null;

function getGenAIClient() {
  if (_genAIClient) return _genAIClient;

  const { GoogleGenAI } = require('@google/genai');

  if (USE_VERTEX_AI) {
    const project = process.env.GOOGLE_CLOUD_PROJECT;
    const location = process.env.VERTEX_AI_LOCATION || 'us-central1';
    if (!project) throw new Error('GOOGLE_CLOUD_PROJECT required for Vertex AI');
    _genAIClient = new GoogleGenAI({ vertexai: true, project, location });
    logger.info('🤖 Juggler AI: Using Vertex AI (project:', project + ')');
  } else {
    if (!GEMINI_API_KEY) throw new Error('GEMINI_API_KEY not configured');
    _genAIClient = new GoogleGenAI({ apiKey: GEMINI_API_KEY });
    logger.info('🤖 Juggler AI: Using Gemini API with API key');
  }

  return _genAIClient;
}

async function callGemini(prompt, systemPrompt) {
  const client = getGenAIClient();

  const result = await trackedGeminiCall(
    db,
    client,
    GEMINI_MODEL,
    systemPrompt + '\n\n---\nUser request:\n' + prompt,
    { temperature: 0.2, topP: 0.8, topK: 40, maxOutputTokens: 8192 },
    {
      useCase:       AI_USE_CASES.TASK_AI,
      userId:        null,
      correlationId: null,
    }
  );

  if (result.text) {
    return result.text;
  }

  if (result.candidates?.[0]?.content?.parts) {
    return result.candidates[0].content.parts.map(p => p.text || '').join('');
  }

  throw new Error('Unexpected Gemini response structure');
}

/**
 * Check and record the per-user daily AI command quota.
 * Returns { allowed: true } or { allowed: false, remaining: 0 }.
 * Inserts a log row when allowed — counts the attempt regardless of Gemini outcome.
 */
async function checkAndLogDailyQuota(userId) {
  var windowStart = new Date(Date.now() - 24 * 60 * 60 * 1000);
  var row = await db('ai_command_log')
    .where('user_id', userId)
    .where('created_at', '>=', windowStart)
    .count('id as cnt')
    .first();
  var count = Number(row && row.cnt) || 0;
  if (count >= AI_DAILY_LIMIT) {
    return { allowed: false };
  }
  await db('ai_command_log').insert({ user_id: userId });
  return { allowed: true };
}

exports.handleCommand = async (req, res) => {
  try {
    const userId = req.user.id;
    const { command, tasks, statuses, config } = req.body;

    if (!command || !command.trim()) {
      return res.status(400).json({ error: 'No command provided' });
    }

    // Daily quota check (2/min handled by route-level rate limiter)
    var quota = await checkAndLogDailyQuota(userId);
    if (!quota.allowed) {
      return res.status(429).json({ error: 'Daily AI limit reached (' + AI_DAILY_LIMIT + '/day). Try again tomorrow.' });
    }

    // Build system prompt (same structure as original JSX)
    const todayStr = new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric', year: 'numeric' });

    const DAY_NAMES = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];

    // Build task lines
    const taskLines = (tasks || []).map(t => {
      var st = (statuses || {})[t.id] || 'open';
      var deps = t.dependsOn || [];
      return t.id + '|' + (t.date || 'TBD') + '|' + (t.time || '') + '|' + st + '|' + (t.project || '') + '|' + t.text + '|' + (t.where || '') + '|' + (t.when || '') + '|' + (t.pri || '') + (t.recurring ? '|recurring' : '') + '|' + (t.dur || 30) + 'm' + (t.deadline ? '|deadline:' + t.deadline : '') + (t.startAfter ? '|start:' + t.startAfter : '') + (deps.length ? '|deps:' + deps.join(',') : '');
    }).join('\n');

    // Build schedule info
    var locSchedules = (config && config.locSchedules) || {};
    var locScheduleDefaults = (config && config.locScheduleDefaults) || {};
    var locScheduleOverrides = (config && config.locScheduleOverrides) || {};
    var timeBlocks = (config && config.timeBlocks) || {};
    var locations = (config && config.locations) || [];
    var tools = (config && config.tools) || [];
    var toolMatrix = (config && config.toolMatrix) || {};

    var schedTemplateStr = 'Schedule templates: ' + Object.keys(locSchedules).map(function(k) { var t = locSchedules[k]; return k + ' (' + t.name + ')' + (t.system ? ' [system]' : ''); }).join(', ');
    schedTemplateStr += '. Day defaults: ' + DAY_NAMES.map(function(d) { return d + '=' + (locScheduleDefaults[d] || 'weekday'); }).join(', ');
    var ovKeys = Object.keys(locScheduleOverrides);
    if (ovKeys.length > 0) schedTemplateStr += '. Overrides: ' + ovKeys.map(function(dk) { return dk + '=' + locScheduleOverrides[dk]; }).join(', ');

    // Scope constraint prepended — must appear before all other instructions so
    // the model sees it first and treats it as the highest-priority rule.
    const scopeConstraint = 'SCOPE RESTRICTION — HIGHEST PRIORITY RULE: You are ONLY a Juggler task management assistant. You may ONLY perform operations that are supported by the JSON ops format below (add/edit/delete tasks, set status, configure schedule, manage locations/tools/blocks). You MUST NOT answer general questions, provide information, write code, do math, summarize web content, or help with anything unrelated to managing the user\'s Juggler tasks and schedule. If the user\'s request cannot be fulfilled with the available ops, respond with ONLY this JSON and nothing else: {"ops":[],"msg":"I can only help with Juggler tasks and scheduling. Try: \'add a task to buy milk\', \'mark email task done\', or \'reschedule my afternoon tasks\'.","unsupported":true}\n\n';

    const sysPrompt = scopeConstraint + 'You are an AI assistant embedded in a task tracker called Juggler. Today is ' + todayStr + '. Respond with ONLY valid JSON (no markdown, no code fences).\n\nOpen tasks (id|date|time|status|project|text|where|when|pri|dur|due|start|deps):\n' + taskLines + '\n\nLocation: ' + schedTemplateStr + '\n\nCurrent config:\n- Locations: ' + locations.map(function(l) { return l.id + '(' + l.name + ')'; }).join(', ') + '\n- Tools: ' + tools.map(function(t) { return t.id + '(' + t.name + ')'; }).join(', ') + '\n- Tool matrix: ' + JSON.stringify(toolMatrix) + '\n- Time blocks (per day): ' + DAY_NAMES.map(function(dn) { var bl = timeBlocks[dn] || []; return dn + ': ' + bl.map(function(b) { return b.tag + '@' + (b.loc || 'home') + '(' + Math.floor(b.start / 60) + '-' + Math.floor(b.end / 60) + ')'; }).join(','); }).join('; ') + '\n\nJSON format: {"ops":[...],"msg":"summary"}\nTask ops:\n- {"op":"status","id":"ID","value":"done|cancel|wip|open|skip|"}\n- {"op":"edit","id":"ID","fields":{"date":"M/D","time":"H:MM AM/PM","dur":60,"due":"M/D","startAfter":"M/D","when":"morning,biz","pri":"P1","recurring":true,"dependsOn":["t01","t02"]}}\n- {"op":"add","task":{"id":"ai001","date":"M/D","day":"Mon","text":"desc","time":"H:MM AM/PM","project":"X","pri":"P2","where":"anywhere","when":"anytime","dayReq":"any","section":"","notes":"","dur":30,"due":"","startAfter":"","recurring":false,"dependsOn":[]}}\n- {"op":"delete","id":"ID"}\nConfig ops:\n- {"op":"set_weekly","day":"Mon","location":"work"} (sets biz+lunch blocks)\n- {"op":"set_block_loc","day":"Mon","blockTag":"morning","location":"home"} (set one block)\n- {"op":"add_location","id":"gym","name":"Gym","icon":"\\ud83c\\udfcb\\ufe0f"}\n- {"op":"add_tool","id":"tablet","name":"Tablet","icon":"\\ud83d\\udcf1"}\n- {"op":"set_tool_matrix","location":"home","tools":["phone","personal_pc"]}\n- {"op":"set_blocks","day":"Mon","blocks":[{"id":"b1","tag":"morning","name":"Morning","start":360,"end":480,"color":"#F59E0B","icon":"\\u2600\\ufe0f"}]}\n- {"op":"clone_blocks","from":"Mon","to":["Tue","Wed","Thu","Fri"]}\nDependencies: dependsOn is an array of task IDs that must be done before this task can start.\nOnly include needed ops. dur is in minutes. Due dates are HARD deadlines. startAfter delays scheduling until that date. Keep msg short.\n\n## Project Creation\nWhen the user asks to create a project, plan, or breakdown:\n1. Create multiple tasks with the SAME project name using "add" ops\n2. Use temporary IDs like ai001, ai002, ai003 etc.\n3. Link tasks with dependsOn referencing these temp IDs. Example: ai003.dependsOn=["ai001","ai002"] means ai003 cannot start until ai001 and ai002 are done.\n4. Set realistic durations (dur in minutes), priorities (P1=critical, P2=important, P3=normal, P4=low), and reasonable date ranges\n5. Leave date as "" and time as "" to let the scheduler place them automatically\n6. Structure as a proper dependency chain: early tasks have no deps, later tasks depend on earlier ones\n7. Include a due date on the final milestone task if the user specifies a deadline\n\nExample — "create a project to launch a website":\n{"ops":[\n{"op":"add","task":{"id":"ai001","date":"","day":"","text":"Design wireframes","time":"","project":"Website Launch","pri":"P1","where":"anywhere","when":"morning,lunch,afternoon,evening,night","dayReq":"any","section":"","notes":"","dur":120,"due":"","startAfter":"","recurring":false,"dependsOn":[]}},\n{"op":"add","task":{"id":"ai002","date":"","day":"","text":"Write copy and content","time":"","project":"Website Launch","pri":"P2","where":"anywhere","when":"morning,lunch,afternoon,evening,night","dayReq":"any","section":"","notes":"","dur":90,"due":"","startAfter":"","recurring":false,"dependsOn":[]}},\n{"op":"add","task":{"id":"ai003","date":"","day":"","text":"Build frontend","time":"","project":"Website Launch","pri":"P1","where":"anywhere","when":"morning,lunch,afternoon,evening,night","dayReq":"any","section":"","notes":"","dur":240,"due":"","startAfter":"","recurring":false,"dependsOn":["ai001"]}},\n{"op":"add","task":{"id":"ai004","date":"","day":"","text":"Integrate content","time":"","project":"Website Launch","pri":"P2","where":"anywhere","when":"morning,lunch,afternoon,evening,night","dayReq":"any","section":"","notes":"","dur":60,"due":"","startAfter":"","recurring":false,"dependsOn":["ai002","ai003"]}},\n{"op":"add","task":{"id":"ai005","date":"","day":"","text":"Test and QA","time":"","project":"Website Launch","pri":"P1","where":"anywhere","when":"morning,lunch,afternoon,evening,night","dayReq":"any","section":"","notes":"","dur":90,"due":"","startAfter":"","recurring":false,"dependsOn":["ai004"]}},\n{"op":"add","task":{"id":"ai006","date":"","day":"","text":"Deploy to production","time":"","project":"Website Launch","pri":"P1","where":"anywhere","when":"morning,lunch,afternoon,evening,night","dayReq":"any","section":"","notes":"","dur":30,"due":"","startAfter":"","recurring":false,"dependsOn":["ai005"]}}\n],"msg":"Created Website Launch project with 6 linked tasks"}';

    // Sanitize user input
    var safeCmd = command.replace(/[‘’]/g, "'").replace(/[“”]/g, '"').replace(/—/g, '--').replace(/–/g, '-').replace(/…/g, '...');

    const raw = await callGemini(safeCmd, sysPrompt);

    // Parse JSON from response
    var cleaned = raw.replace(/```json|```/g, '').trim();
    var result;
    try {
      result = JSON.parse(cleaned);
    } catch (pe) {
      var jsonMatch = cleaned.match(/\{[\s\S]*\}/);
      if (jsonMatch) {
        try { result = JSON.parse(jsonMatch[0]); } catch (pe2) { /* fall through */ }
      }
      if (!result) {
        return res.status(422).json({ error: 'Bad JSON from AI', raw: cleaned.substring(0, 500).replace(/[<>&"']/g, '') });
      }
    }

    // Model flagged the request as outside Juggler scope
    if (result.unsupported) {
      return res.json({ ops: [], msg: result.msg || 'That request is outside what I can help with in Juggler.', unsupported: true });
    }

    res.json({ ops: result.ops || [], msg: result.msg || 'Done.' });
  } catch (err) {
    logger.error('AI command error:', err);
    res.status(500).json({ error: err.message || 'AI command failed' });
  }
};

/**
 * Apple Calendar Controller — CalDAV connection, status, and management.
 *
 * Unlike Google/Microsoft which use OAuth, Apple Calendar uses CalDAV
 * with basic auth (Apple ID + app-specific password). The connection
 * flow is: enter credentials → discover calendars → toggle selection.
 */

var db = require('../db');
var appleCalApi = require('../lib/apple-cal-api');
var { encrypt, decrypt } = require('../lib/credential-encrypt');

/**
 * GET /api/apple-cal/status — connection status
 */
async function getStatus(req, res) {
  try {
    // Check if credentials are stored — that's enough to be "connected"
    var hasCredentials = !!req.user.apple_cal_username && !!req.user.apple_cal_password;

    // Load all calendars (enabled + disabled) for the toggle UI
    var allCalendars = [];
    try {
      allCalendars = await db('user_calendars')
        .where({ user_id: req.user.id, provider: 'apple' });
    } catch (e) {
      // Table may not exist if migration hasn't run yet
    }

    var connected = hasCredentials && (allCalendars.length > 0 || !!req.user.apple_cal_calendar_url);

    var lastSyncedAt = req.user.apple_cal_last_synced_at || null;

    var autoSyncRow = await db('user_config')
      .where({ user_id: req.user.id, config_key: 'apple_cal_auto_sync' })
      .first();
    var autoSync = false;
    if (autoSyncRow) {
      var val = typeof autoSyncRow.config_value === 'string'
        ? JSON.parse(autoSyncRow.config_value) : autoSyncRow.config_value;
      autoSync = !!val;
    }

    res.json({
      connected: connected,
      username: connected ? req.user.apple_cal_username : null,
      calendarUrl: connected ? req.user.apple_cal_calendar_url : null,
      calendars: allCalendars.length > 0 ? allCalendars : null,
      lastSyncedAt: lastSyncedAt,
      autoSync: autoSync
    });
  } catch (error) {
    logger.error('Apple Calendar status error:', error);
    res.status(500).json({ error: 'Failed to get Apple Calendar status' });
  }
}

/**
 * POST /api/apple-cal/connect — validate credentials and discover calendars.
 * Body: { username, password, serverUrl? }
 * Returns: { calendars: [{ url, displayName }] }
 */
async function connect(req, res) {
  try {
    var { username, password, serverUrl } = req.body;
    if (!username || !password) {
      return res.status(400).json({ error: 'Apple ID email and app-specific password are required' });
    }

    var url = serverUrl || appleCalApi.DEFAULT_SERVER_URL;

    // Validate credentials by attempting to discover calendars
    var client;
    try {
      client = await appleCalApi.createClient(url, username, password);
    } catch (e) {
      logger.error('Apple Calendar connect failed:', e.message);
      return res.status(401).json({
        error: 'Failed to connect. Check your Apple ID and app-specific password.',
        detail: e.message
      });
    }

    var calendars;
    try {
      calendars = await appleCalApi.discoverCalendars(client);
    } catch (e) {
      logger.error('Apple Calendar discovery failed:', e.message);
      return res.status(401).json({
        error: 'Connected but failed to discover calendars. Check your credentials.',
        detail: e.message
      });
    }

    if (calendars.length === 0) {
      return res.status(404).json({ error: 'No calendars found on this account' });
    }

    // Store encrypted credentials (calendar selection done separately)
    await db('users').where('id', req.user.id).update({
      apple_cal_server_url: url,
      apple_cal_username: username,
      apple_cal_password: encrypt(password),
      updated_at: db.fn.now()
    });

    // Load existing selections so frontend can show current state
    var existingSelections = [];
    try {
      existingSelections = await db('user_calendars')
        .where({ user_id: req.user.id, provider: 'apple' });
    } catch (e) {
      // Table may not exist if migration hasn't run yet — graceful fallback
      logger.warn('user_calendars table not available:', e.message);
    }

    var selectionMap = {};
    existingSelections.forEach(function(s) {
      selectionMap[s.calendar_id] = s;
    });

    res.json({
      calendars: calendars.map(function(c) {
        var existing = selectionMap[c.url];
        return {
          url: c.url,
          displayName: c.displayName,
          description: c.description,
          enabled: existing ? existing.enabled : false,
          syncDirection: existing ? existing.sync_direction : 'full'
        };
      })
    });
  } catch (error) {
    logger.error('Apple Calendar connect error:', error);
    res.status(500).json({ error: 'Failed to connect Apple Calendar' });
  }
}

/**
 * POST /api/apple-cal/select-calendar — legacy single-calendar selection.
 * Body: { calendarUrl }
 * Kept for backward compatibility — prefer select-calendars for multi-select.
 */
async function selectCalendar(req, res) {
  try {
    var { calendarUrl } = req.body;
    if (!calendarUrl) {
      return res.status(400).json({ error: 'calendarUrl is required' });
    }

    if (!req.user.apple_cal_username || !req.user.apple_cal_password) {
      return res.status(400).json({ error: 'Not connected to Apple Calendar. Connect first.' });
    }

    await db('users').where('id', req.user.id).update({
      apple_cal_calendar_url: calendarUrl,
      updated_at: db.fn.now()
    });

    // Also upsert into user_calendars for forward compat
    var existing = await db('user_calendars')
      .where({ user_id: req.user.id, provider: 'apple', calendar_id: calendarUrl })
      .first();

    if (existing) {
      await db('user_calendars').where('id', existing.id).update({ enabled: true, updated_at: db.fn.now() });
    } else {
      await db('user_calendars').insert({
        user_id: req.user.id,
        provider: 'apple',
        calendar_id: calendarUrl,
        enabled: true,
        sync_direction: 'full'
      });
    }

    res.json({ calendarUrl: calendarUrl });
  } catch (error) {
    logger.error('Apple Calendar select error:', error);
    res.status(500).json({ error: 'Failed to select calendar' });
  }
}

/**
 * POST /api/apple-cal/select-calendars — multi-calendar selection.
 * Body: { calendars: [{ url, displayName, enabled, syncDirection }] }
 */
async function selectCalendars(req, res) {
  try {
    var { calendars } = req.body;
    if (!Array.isArray(calendars) || calendars.length === 0) {
      return res.status(400).json({ error: 'calendars array is required' });
    }

    if (!req.user.apple_cal_username || !req.user.apple_cal_password) {
      return res.status(400).json({ error: 'Not connected to Apple Calendar. Connect first.' });
    }

    var userId = req.user.id;

    // Upsert each calendar selection
    for (var i = 0; i < calendars.length; i++) {
      var cal = calendars[i];
      var existing = await db('user_calendars')
        .where({ user_id: userId, provider: 'apple', calendar_id: cal.url })
        .first();

      if (existing) {
        await db('user_calendars').where('id', existing.id).update({
          display_name: cal.displayName || existing.display_name,
          enabled: cal.enabled !== undefined ? cal.enabled : existing.enabled,
          sync_direction: cal.syncDirection || existing.sync_direction,
          ingest_mode: cal.ingestMode || existing.ingest_mode,
          updated_at: db.fn.now()
        });
      } else {
        await db('user_calendars').insert({
          user_id: userId,
          provider: 'apple',
          calendar_id: cal.url,
          display_name: cal.displayName || null,
          enabled: cal.enabled !== undefined ? cal.enabled : false,
          sync_direction: cal.syncDirection || 'full',
          ingest_mode: cal.ingestMode || 'task'
        });
      }
    }

    // Update legacy single-calendar field to first enabled calendar (backward compat)
    var firstEnabled = await db('user_calendars')
      .where({ user_id: userId, provider: 'apple', enabled: true })
      .first();

    await db('users').where('id', userId).update({
      apple_cal_calendar_url: firstEnabled ? firstEnabled.calendar_id : null,
      updated_at: db.fn.now()
    });

    var savedCalendars = await db('user_calendars')
      .where({ user_id: userId, provider: 'apple' });

    res.json({ calendars: savedCalendars });
  } catch (error) {
    logger.error('Apple Calendar select-calendars error:', error);
    res.status(500).json({ error: 'Failed to save calendar selections' });
  }
}

/**
 * GET /api/apple-cal/calendars — get saved calendar selections.
 */
async function getCalendars(req, res) {
  try {
    var calendars = await db('user_calendars')
      .where({ user_id: req.user.id, provider: 'apple' });

    res.json({ calendars: calendars });
  } catch (error) {
    logger.error('Apple Calendar get-calendars error:', error);
    res.status(500).json({ error: 'Failed to get calendars' });
  }
}

/**
 * PUT /api/apple-cal/calendars/:id — update a single calendar's settings.
 * Body: { enabled?, syncDirection? }
 */
async function updateCalendar(req, res) {
  try {
    var calendarId = req.params.id;
    var row = await db('user_calendars')
      .where({ id: calendarId, user_id: req.user.id })
      .first();

    if (!row) {
      return res.status(404).json({ error: 'Calendar not found' });
    }

    var updates = { updated_at: db.fn.now() };
    if (req.body.enabled !== undefined) updates.enabled = req.body.enabled;
    if (req.body.syncDirection) updates.sync_direction = req.body.syncDirection;
    if (req.body.ingestMode) updates.ingest_mode = req.body.ingestMode;

    await db('user_calendars').where('id', calendarId).update(updates);

    // Update legacy field
    var firstEnabled = await db('user_calendars')
      .where({ user_id: req.user.id, provider: 'apple', enabled: true })
      .first();

    await db('users').where('id', req.user.id).update({
      apple_cal_calendar_url: firstEnabled ? firstEnabled.calendar_id : null,
      updated_at: db.fn.now()
    });

    var updated = await db('user_calendars').where('id', calendarId).first();
    res.json({ calendar: updated });
  } catch (error) {
    logger.error('Apple Calendar update-calendar error:', error);
    res.status(500).json({ error: 'Failed to update calendar' });
  }
}

/**
 * POST /api/apple-cal/disconnect — clear all Apple Calendar credentials.
 */
async function disconnect(req, res) {
  try {
    // Remove all calendar selections
    await db('user_calendars')
      .where({ user_id: req.user.id, provider: 'apple' })
      .del();

    await db('users').where('id', req.user.id).update({
      apple_cal_server_url: null,
      apple_cal_username: null,
      apple_cal_password: null,
      apple_cal_calendar_url: null,
      apple_cal_sync_token: null,
      apple_cal_last_synced_at: null,
      updated_at: db.fn.now()
    });

    // Clear auto-sync setting
    await db('user_config')
      .where({ user_id: req.user.id, config_key: 'apple_cal_auto_sync' })
      .del()
      .catch(function() {});

    res.json({ disconnected: true });
  } catch (error) {
    logger.error('Apple Calendar disconnect error:', error);
    res.status(500).json({ error: 'Failed to disconnect Apple Calendar' });
  }
}

/**
 * POST /api/apple-cal/auto-sync — toggle auto-sync.
 * Body: { enabled: boolean }
 */
async function setAutoSync(req, res) {
  try {
    var userId = req.user.id;
    var value = !!req.body.enabled;

    var existing = await db('user_config')
      .where({ user_id: userId, config_key: 'apple_cal_auto_sync' })
      .first();

    if (existing) {
      await db('user_config')
        .where({ user_id: userId, config_key: 'apple_cal_auto_sync' })
        .update({ config_value: JSON.stringify(value) });
    } else {
      await db('user_config').insert({
        user_id: userId,
        config_key: 'apple_cal_auto_sync',
        config_value: JSON.stringify(value)
      });
    }

    res.json({ autoSync: value });
  } catch (error) {
    logger.error('Apple Calendar auto-sync error:', error);
    res.status(500).json({ error: 'Failed to update auto-sync setting' });
  }
}

/**
 * GET /api/apple-cal/refresh-calendars — re-discover calendars from iCloud
 * using stored credentials. Upserts new calendars (enabled=false), updates
 * display names on existing ones. Does NOT require re-entering credentials.
 */
async function refreshCalendars(req, res) {
  try {
    var userId = req.user.id;

    if (!req.user.apple_cal_username || !req.user.apple_cal_password) {
      return res.status(400).json({ error: 'Apple Calendar not connected. Please connect first.' });
    }

    var password = decrypt(req.user.apple_cal_password);
    var serverUrl = req.user.apple_cal_server_url || appleCalApi.DEFAULT_SERVER_URL;

    var client;
    try {
      client = await appleCalApi.createClient(serverUrl, req.user.apple_cal_username, password);
    } catch (e) {
      return res.status(401).json({
        error: 'Failed to connect. Your credentials may have expired.',
        detail: e.message
      });
    }

    var remoteCalendars;
    try {
      remoteCalendars = await appleCalApi.discoverCalendars(client);
    } catch (e) {
      return res.status(500).json({ error: 'Failed to discover calendars.', detail: e.message });
    }

    // Load existing rows
    var existingRows = await db('user_calendars')
      .where({ user_id: userId, provider: 'apple' });
    var existingByUrl = {};
    existingRows.forEach(function(r) { existingByUrl[r.calendar_id] = r; });

    // Upsert: new calendars → insert enabled=false, existing → update display_name
    var remoteUrls = new Set();
    for (var i = 0; i < remoteCalendars.length; i++) {
      var rc = remoteCalendars[i];
      remoteUrls.add(rc.url);

      if (existingByUrl[rc.url]) {
        // Update display name if changed
        if (existingByUrl[rc.url].display_name !== rc.displayName) {
          await db('user_calendars').where('id', existingByUrl[rc.url].id)
            .update({ display_name: rc.displayName, updated_at: db.fn.now() });
        }
      } else {
        // New calendar — insert as disabled
        await db('user_calendars').insert({
          user_id: userId,
          provider: 'apple',
          calendar_id: rc.url,
          display_name: rc.displayName,
          enabled: false,
          sync_direction: 'full',
          created_at: db.fn.now(),
          updated_at: db.fn.now()
        });
      }
    }

    // Return the full list with current state
    var allCalendars = await db('user_calendars')
      .where({ user_id: userId, provider: 'apple' });

    res.json({
      calendars: allCalendars.map(function(c) {
        return {
          id: c.id,
          url: c.calendar_id,
          displayName: c.display_name,
          enabled: !!c.enabled,
          syncDirection: c.sync_direction,
          availableRemotely: remoteUrls.has(c.calendar_id)
        };
      })
    });
  } catch (error) {
    logger.error('Apple Calendar refresh error:', error);
    res.status(500).json({ error: 'Failed to refresh calendars' });
  }
}

module.exports = {
  getStatus,
