                      eventId: event._url || ledger.provider_event_id,
                      task: task,
                      ledgerId: ledger.id,
                      newHash: newHash
                    });
                    pStats.pushed++;
                    stats.pushed++;
                    logSyncAction(pid, 'conflict_juggler', {
                      taskId: task.id, taskText: task.text, eventId: ledger.provider_event_id,
