};

/**
 * Google Calendar Controller — OAuth flow, status, and auto-sync settings.
 * Sync is handled by the unified cal-sync.controller.js.
 */

var { SignJWT, jwtVerify } = require('jose');
var db = require('../db');
var gcalApi = require('../lib/gcal-api');

// --- Token management (canonical implementation in adapter) ---

var { getJwtSecret } = require('../lib/jwt-secret');
var { getValidAccessToken } = require('../lib/cal-adapters/gcal.adapter');

// --- Endpoints ---

async function getStatus(req, res) {
  try {
    var hasToken = !!req.user.gcal_refresh_token;
    var lastSyncedAt = req.user.gcal_last_synced_at || null;
    var connected = false;
    var tokenExpired = false;

    if (hasToken) {
      // Don't refresh the token on status check — just verify it exists.
      // Token refresh happens lazily when sync actually needs it.
      // This makes the status endpoint instant instead of blocking on
      // Google's auth server (which can take seconds or timeout).
      connected = true;
      if (req.user.gcal_token_expiry) {
        var expiryStr = String(req.user.gcal_token_expiry);
        var expiry = new Date(expiryStr.endsWith('Z') ? expiryStr : expiryStr + 'Z');
        if (expiry.getTime() < Date.now()) {
          // Token expired but refresh token exists — still "connected",
          // will refresh lazily on next sync
          connected = true;
        }
      }
    }

    var autoSyncRow = await db('user_config')
      .where({ user_id: req.user.id, config_key: 'gcal_auto_sync' })
      .first();
    var autoSync = false;
    if (autoSyncRow) {
      var val = typeof autoSyncRow.config_value === 'string'
        ? JSON.parse(autoSyncRow.config_value) : autoSyncRow.config_value;
      autoSync = !!val;
    }

    res.json({
      connected: connected,
      tokenExpired: tokenExpired,
      email: req.user.email,
      lastSyncedAt: lastSyncedAt,
      autoSync: autoSync
    });
  } catch (error) {
    logger.error('GCal status error:', error);
    res.status(500).json({ error: 'Failed to check GCal status' });
  }
}

async function connect(req, res) {
  try {
    var oauth2Client = gcalApi.createOAuth2Client();
    var state = await new SignJWT({ userId: req.user.id })
      .setProtectedHeader({ alg: 'HS256' })
      .setExpirationTime('10m')
      .sign(getJwtSecret());
    var authUrl = gcalApi.getAuthUrl(oauth2Client, state);
    res.json({ authUrl: authUrl });
  } catch (error) {
    logger.error('GCal connect error:', error);
    res.status(500).json({ error: 'Failed to generate auth URL' });
  }
}

async function callback(req, res) {
  try {
    var code = req.query.code;
    var state = req.query.state;

    if (!code || !state) {
      return res.status(400).send('Missing code or state parameter');
    }

    var decoded;
    try {
      var result = await jwtVerify(state, getJwtSecret());
      decoded = result.payload;
    } catch (e) {
      return res.status(400).send('Invalid or expired state parameter');
    }

    var userId = decoded.userId;
    // Verify the OAuth flow is for the authenticated user (prevent IDOR)
    if (req.user && req.user.id !== userId) {
      return res.status(403).send('OAuth state does not match authenticated user');
    }
    var oauth2Client = gcalApi.createOAuth2Client();
    var tokens = await gcalApi.getTokensFromCode(oauth2Client, code);

    var update = {
      gcal_access_token: tokens.access_token,
      updated_at: db.fn.now()
    };
    if (tokens.refresh_token) {
      update.gcal_refresh_token = tokens.refresh_token;
    }
    if (tokens.expiry_date) {
      update.gcal_token_expiry = new Date(tokens.expiry_date);
    }

    await db('users').where('id', userId).update(update);

    var frontendUrl = require('../proxy-config').services.juggler.frontend;
    res.redirect(frontendUrl + '/?gcal=connected');
  } catch (error) {
    logger.error('GCal callback error:', error);
    res.status(500).send('Failed to complete Google Calendar authorization');
  }
}

async function disconnect(req, res) {
  try {
    await db('users').where('id', req.user.id).update({
      gcal_access_token: null,
      gcal_refresh_token: null,
      gcal_token_expiry: null,
      updated_at: db.fn.now()
    });
    res.json({ disconnected: true });
  } catch (error) {
    logger.error('GCal disconnect error:', error);
    res.status(500).json({ error: 'Failed to disconnect GCal' });
  }
}

async function setAutoSync(req, res) {
  try {
    var enabled = req.body.enabled;
    var userId = req.user.id;
    var value = !!enabled;

    var existing = await db('user_config')
      .where({ user_id: userId, config_key: 'gcal_auto_sync' })
      .first();

    if (existing) {
      await db('user_config')
        .where({ user_id: userId, config_key: 'gcal_auto_sync' })
        .update({ config_value: JSON.stringify(value), updated_at: db.fn.now() });
    } else {
      await db('user_config').insert({
        user_id: userId,
        config_key: 'gcal_auto_sync',
        config_value: JSON.stringify(value)
      });
    }

    res.json({ autoSync: value });
  } catch (error) {
    logger.error('GCal auto-sync error:', error);
    res.status(500).json({ error: 'Failed to update auto-sync setting' });
  }
}

module.exports = {
  getStatus,
  connect,
  callback,
  disconnect,
  setAutoSync
};

const db = require('../db');
const { authServiceUrl } = require('../proxy-config');

async function callAuthServiceImpersonate(adminUserId, targetUserId, reason) {
  const key = process.env.INTERNAL_SERVICE_KEY;
  if (!key) throw new Error('INTERNAL_SERVICE_KEY is not set');

  const url = `${authServiceUrl}/internal/auth/impersonate`;
  const response = await fetch(url, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'X-Internal-Key': key },
    body: JSON.stringify({ admin_user_id: adminUserId, target_user_id: targetUserId, reason: reason || null }),
    signal: AbortSignal.timeout(30000),
  });
  const text = await response.text();
  const payload = text ? JSON.parse(text) : {};
  if (!response.ok) {
    const err = new Error(payload.error || `auth-service returned ${response.status}`);
    err.status = response.status;
    err.body = payload;
    throw err;
  }
  return payload;
}

async function insertAuditRow(adminUserId, targetUserId, action, req) {
  try {
    await db('impersonation_log').insert({
      admin_user_id: adminUserId,
      target_user_id: targetUserId || null,
      action,
      ip_address: req.ip,
      user_agent: req.get('User-Agent'),
      created_at: new Date(),
      updated_at: new Date(),
    });
  } catch (auditErr) {
    logger.warn('[juggler/impersonation] audit insert failed:', auditErr.message);
  }
}

const startImpersonation = async (req, res) => {
  try {
    const { targetUserId, reason } = req.body || {};
    const admin = req.user;

    if (!targetUserId) {
      return res.status(400).json({ error: 'targetUserId is required' });
    }
    if (targetUserId === admin.id) {
      return res.status(400).json({ error: 'Cannot impersonate yourself' });
    }

    let result;
    try {
      result = await callAuthServiceImpersonate(admin.id, targetUserId, reason);
    } catch (err) {
      if (err.status && err.status < 500) {
        return res.status(err.status).json(err.body || { error: err.message });
      }
      logger.error('[juggler/impersonation] auth-service call failed:', err);
      return res.status(503).json({ error: 'Impersonation service unavailable' });
    }

    await insertAuditRow(admin.id, targetUserId, 'start_impersonation', req);

    return res.json({
      message: 'Impersonation started',
      accessToken: result.access_token,
      expiresIn: result.expires_in,
      impersonating: result.impersonating,
    });
  } catch (err) {
    logger.error('[juggler/impersonation] unexpected error:', err);
    return res.status(500).json({ error: 'Internal server error' });
  }
};

const stopImpersonation = async (req, res) => {
  try {
    // With an impersonation token: sub=target, acting_as_admin=admin ID.
    const actingAsAdmin = req.auth?.actingAsAdmin;
    const adminUserId = actingAsAdmin || req.user.id;
    const targetUserId = actingAsAdmin ? req.user.id : null;
    await insertAuditRow(adminUserId, targetUserId, 'stop_impersonation', req);
    return res.json({ message: 'Impersonation stopped. Discard the impersonation token client-side.' });
  } catch (err) {
    logger.error('[juggler/impersonation] stop error:', err);
    return res.status(500).json({ error: 'Internal server error' });
  }
};

const getImpersonationTargets = async (req, res) => {
  try {
    const { search, limit = 50, offset = 0 } = req.query;
    const parsedLimit = parseInt(limit);
    const lim = Math.min(Math.max(1, Number.isNaN(parsedLimit) ? 50 : parsedLimit), 100);
    const off = Math.max(0, parseInt(offset) || 0);

    let query = db('users').select('id', 'email', 'created_at');
    if (search) {
      const escaped = String(search).replace(/\\/g, '\\\\').replace(/%/g, '\\%').replace(/_/g, '\\_');
      query = query.where('email', 'like', `%${escaped}%`);
    }

    const countQuery = query.clone().clearSelect().count('* as count');
    const [{ count }] = await countQuery;

    const users = await query.orderBy('email').limit(lim).offset(off);

    return res.json({
      users,
      pagination: { total: parseInt(count), limit: lim, offset: off, hasMore: off + lim < parseInt(count) }
    });
  } catch (err) {
    logger.error('[juggler/impersonation] targets error:', err);
    return res.status(500).json({ error: 'Internal server error' });
  }
};

const getImpersonationLog = async (req, res) => {
  try {
    const { limit = 50, offset = 0, adminUserId, targetUserId } = req.query;
    const parsedLimit = parseInt(limit);
    const lim = Math.min(Math.max(1, Number.isNaN(parsedLimit) ? 50 : parsedLimit), 100);
    const off = Math.max(0, parseInt(offset) || 0);

    let query = db('impersonation_log')
      .select(
        'impersonation_log.*',
        'admin_users.email as admin_email'
      )
      .leftJoin('users as admin_users', 'impersonation_log.admin_user_id', 'admin_users.id')
      .orderBy('impersonation_log.created_at', 'desc');

    if (adminUserId) query = query.where('impersonation_log.admin_user_id', adminUserId);
    if (targetUserId) query = query.where('impersonation_log.target_user_id', targetUserId);

    const countQuery = query.clone().clearSelect().clearOrder().count('impersonation_log.id as count');
    const [{ count }] = await countQuery;

    const logs = await query.limit(lim).offset(off);

    return res.json({
      logs,
      pagination: { total: parseInt(count), limit: lim, offset: off, hasMore: off + lim < parseInt(count) }
    });
  } catch (err) {
    logger.error('[juggler/impersonation] log error:', err);
    return res.status(500).json({ error: 'Internal server error' });
  }
};

module.exports = { startImpersonation, stopImpersonation, getImpersonationTargets, getImpersonationLog };

/**
 * Microsoft Calendar Controller — OAuth flow, status, and auto-sync settings.
 * Sync is handled by the unified cal-sync.controller.js.
 */

var { SignJWT, jwtVerify } = require('jose');
var db = require('../db');
var msftCalApi = require('../lib/msft-cal-api');

// --- Token management (canonical implementation in adapter) ---

var { getJwtSecret } = require('../lib/jwt-secret');
var { getValidAccessToken } = require('../lib/cal-adapters/msft.adapter');

// Guard against duplicate callback hits (browser retries).
//
// FIX-03 — Multi-instance safe OAuth code dedup.
// Replaces the former per-instance in-memory `usedCodes` Set with a
// DB-backed nonce table (oauth_code_nonces).
//
// RESEARCH.md Category 4g + Pitfall 5: if the browser retries the OAuth
// redirect and Cloud Run routes the retry to a different instance, the
// old in-memory Set would have missed the duplicate. The DB row is visible
// to all instances, so INSERT IGNORE provides atomic cross-instance dedup.
//
// Security notes:
//   - The raw OAuth code is never stored. We hash the first 40 chars
//     (matching the original truncation) with SHA-256 before writing to DB.
//   - INSERT IGNORE: succeeds (affectedRows=1) on first hit; silently
//     no-ops (affectedRows=0) if the PK already exists — i.e. duplicate.
//   - Best-effort sweep: DELETE WHERE expires_at < NOW() before each INSERT
//     keeps the table bounded. Wrap in .catch() so a sweep failure never
//     blocks the OAuth flow (table grows by at most one extra row).
//   - 2-minute TTL matches the OAuth code lifetime + browser retry window.
async function markCodeUsed(code) {
  var key = code.substring(0, 40);
  var hash = require('crypto').createHash('sha256').update(key).digest('hex');

  // Best-effort sweep of expired rows (keeps table naturally bounded)
  await db.raw('DELETE FROM oauth_code_nonces WHERE expires_at < NOW()').catch(function() {});

  // INSERT IGNORE: atomic "claim this nonce or detect duplicate"
  var result = await db.raw(
    'INSERT IGNORE INTO oauth_code_nonces (code_hash, expires_at) ' +
    'VALUES (?, DATE_ADD(NOW(), INTERVAL 2 MINUTE))',
    [hash]
  );
  return result[0].affectedRows === 1;
}

// --- Endpoints ---

async function getStatus(req, res) {
  try {
    var hasToken = !!req.user.msft_cal_refresh_token;
    var lastSyncedAt = req.user.msft_cal_last_synced_at || null;
    var connected = false;
    var tokenExpired = false;

    if (hasToken) {
      // Don't refresh the token on status check — just verify it exists.
      // Token refresh happens lazily when sync actually needs it.
      connected = true;
    }

    var autoSyncRow = await db('user_config')
      .where({ user_id: req.user.id, config_key: 'msft_cal_auto_sync' })
      .first();
    var autoSync = false;
    if (autoSyncRow) {
      var val = typeof autoSyncRow.config_value === 'string'
        ? JSON.parse(autoSyncRow.config_value) : autoSyncRow.config_value;
      autoSync = !!val;
    }

    res.json({
      connected: connected,
      tokenExpired: tokenExpired,
      email: req.user.email,
