  var [row, ledgerRows] = await Promise.all([
    dbOrTrx('tasks_v').where({ id: id, user_id: userId }).first(),
    dbOrTrx('cal_sync_ledger')
      .where({ task_id: id, status: 'active' })
      .select('provider', 'provider_event_id', 'origin', 'event_url')
  ]);
