}

function buildSourceMap(rows) {
  var map = {};
  rows.forEach(function(r) {
    if (r.task_type === 'recurring_template') {
      map[r.id] = r;
    } else if (r.recurring && r.task_type !== 'recurring_instance') {
      map[r.id] = r;
