  // to updated_at (completion time) or now, whichever is earlier.
  if (row.scheduled_at && (row.status === 'done' || row.status === 'cancel' || row.status === 'skip' || row.status === 'missed')) {
    var sa = new Date(row.scheduled_at);
    var now = new Date();
    if (sa > now) {
