        // new Date('2026-05-15T10:00:00') on a UTC production server reads as UTC, not New York local.
        if (dtstart.zone && dtstart.zone !== ICAL.Timezone.utcTimezone && dtstart.zone.tzid !== 'floating') {
          var utcStart = dtstart.convertToZone(ICAL.Timezone.utcTimezone);
          startStr = formatICALDateTime(utcStart) + 'Z';
        } else {
          startStr = formatICALDateTime(dtstart);
          if (dtstart.zone === ICAL.Timezone.utcTimezone) startStr += 'Z';
        }
        if (dtend) {
          if (dtend.zone && dtend.zone !== ICAL.Timezone.utcTimezone && dtend.zone.tzid !== 'floating') {
            var utcEnd = dtend.convertToZone(ICAL.Timezone.utcTimezone);
            endStr = formatICALDateTime(utcEnd) + 'Z';
          } else {
            endStr = formatICALDateTime(dtend);
            if (dtend.zone === ICAL.Timezone.utcTimezone) endStr += 'Z';
          }
          durationMinutes = Math.round((dtend.toUnixTime() - dtstart.toUnixTime()) / 60);
        } else if (duration) {
          durationMinutes = Math.round(duration.toSeconds() / 60);
          var endTime = dtstart.clone();
          endTime.addDuration(duration);
          if (endTime.zone && endTime.zone !== ICAL.Timezone.utcTimezone && endTime.zone.tzid !== 'floating') {
            var utcEndTime = endTime.convertToZone(ICAL.Timezone.utcTimezone);
            endStr = formatICALDateTime(utcEndTime) + 'Z';
          } else {
            endStr = formatICALDateTime(endTime);
            if (endTime.zone === ICAL.Timezone.utcTimezone) endStr += 'Z';
          }
        }
      }
    }

    // Detect transparency (free/busy)
    var transp = vevent.getFirstPropertyValue('transp');
    var isTransparent = transp && transp.toUpperCase() === 'TRANSPARENT';

    var lastModified = vevent.getFirstPropertyValue('last-modified');
    var lastModStr = lastModified ? formatICALDateTime(lastModified) : null;

    results.push({
      id: eventId,
      title: summary,
      description: description,
      startDateTime: startStr,
      endDateTime: endStr,
      startTimezone: dtstart && dtstart.zone ? dtstart.zone.tzid : null,
      isAllDay: isAllDay,
      durationMinutes: durationMinutes > 0 ? durationMinutes : 30,
      lastModified: lastModStr,
      isTransparent: !!isTransparent,
      _url: url || null,
      _etag: etag || null,
      _raw: icsData
    });
  }

  return results;
}

/**
 * Build a UTC ICAL.Time from a JS Date or MySQL datetime string.
 * MySQL datetime strings lack a timezone indicator — always interpret as UTC.
 */
function toUtcICALTime(input) {
  var d;
  if (input instanceof Date) {
    d = input;
  } else {
    // MySQL "YYYY-MM-DD HH:MM:SS" — append Z so Date() parses as UTC
    var s = String(input);
    if (!s.includes('Z') && !s.includes('+') && s.includes(' ')) {
      s = s.replace(' ', 'T') + 'Z';
    }
    d = new Date(s);
  }
  return new ICAL.Time({
    year: d.getUTCFullYear(), month: d.getUTCMonth() + 1, day: d.getUTCDate(),
    hour: d.getUTCHours(), minute: d.getUTCMinutes(), second: d.getUTCSeconds(),
    isDate: false
  }, ICAL.Timezone.utcTimezone);
}

/**
 * Build an iCalendar (ICS) string from a task.
 */
function buildVEvent(task, year, tz) {
  var cal = new ICAL.Component(['vcalendar', [], []]);
  cal.addPropertyWithValue('prodid', '-//Raike & Sons//Juggler//EN');
  cal.addPropertyWithValue('version', '2.0');

  var vevent = new ICAL.Component('vevent');
  var uid = 'juggler-' + task.id + '@raikeandsons.com';
  vevent.addPropertyWithValue('uid', uid);

  var isDone = task.status === 'done';
  var cleanText = task.text.replace(/^(✓\s+)+/, '');
  var summaryText = isDone ? '✓ ' + cleanText : task.text;
  vevent.addPropertyWithValue('summary', summaryText);

  // Description with metadata
  var descParts = [];
  if (task.project) descParts.push('Project: ' + task.project);
  if (task.pri) descParts.push('Priority: ' + task.pri);
  if (task.notes) descParts.push('Notes: ' + task.notes);
  if (task.url) descParts.push('Link: ' + task.url);
  descParts.push('', 'Synced from Raike & Sons');
  vevent.addPropertyWithValue('description', descParts.join('\n'));

  // Phase 15: Migrated to placement_mode='all_day' exclusively
  var isAllDay = task.placementMode === PLACEMENT_MODES.ALL_DAY ||
                 task.placement_mode === PLACEMENT_MODES.ALL_DAY;

  // Parse date — handle both YYYY-MM-DD (from utcToLocal) and legacy M/D format
  var dateStr = task.date || '';
  var y, month, day;
  var isoMatch = dateStr.match(/^(\d{4})-(\d{2})-(\d{2})/);
  if (isoMatch) {
    y = parseInt(isoMatch[1], 10);
    month = parseInt(isoMatch[2], 10);
    day = parseInt(isoMatch[3], 10);
  } else {
    var dateParts = dateStr.split('/');
    month = parseInt(dateParts[0], 10) || 1;
    day = parseInt(dateParts[1], 10) || 1;
    y = year || new Date().getFullYear();
  }

  if (isAllDay) {
    var startDate = new ICAL.Time({ year: y, month: month, day: day, isDate: true });
    var endDate = startDate.clone();
    endDate.addDuration(new ICAL.Duration({ days: 1 }));
    vevent.addPropertyWithValue('dtstart', startDate);
    vevent.addPropertyWithValue('dtend', endDate);
  } else {
    var startTime, endTime;

    // Use _scheduled_at (UTC) when available — avoids floating-time issues from missing VTIMEZONE.
    // Fall back to constructing from date+time fields, also emitted as UTC.
    if (task._scheduled_at) {
      // toUtcICALTime handles MySQL "YYYY-MM-DD HH:MM:SS" strings (no timezone indicator)
      // by appending Z before parsing, ensuring getUTC* methods return the correct UTC values.
      startTime = toUtcICALTime(task._scheduled_at);
    } else {
      var timeMatch = (task.time || '12:00 PM').match(/(\d+):(\d+)\s*(AM|PM)/i);
      var hours = 12, mins = 0;
      if (timeMatch) {
        hours = parseInt(timeMatch[1], 10);
        var ampm = timeMatch[3].toUpperCase();
        if (ampm === 'PM' && hours !== 12) hours += 12;
        if (ampm === 'AM' && hours === 12) hours = 0;
        mins = parseInt(timeMatch[2], 10);
      }
      startTime = new ICAL.Time({
        year: y, month: month, day: day,
        hour: hours, minute: mins, second: 0,
        isDate: false
      }, ICAL.Timezone.utcTimezone);
    }

    var dur = task.dur || 30;
    endTime = startTime.clone();
    endTime.addDuration(new ICAL.Duration({ minutes: dur }));

    vevent.addPropertyWithValue('dtstart', startTime);
    vevent.addPropertyWithValue('dtend', endTime);
  }

  // Transparency
  if (task.marker || isDone) {
    vevent.addPropertyWithValue('transp', 'TRANSPARENT');
  }

  // DTSTAMP — RFC 5545 requires UTC (Z suffix). ICAL.Time.now() returns floating
  // local time which violates the spec and causes Apple Calendar to silently
  // discard the event. Use toUtcICALTime(new Date()) for a proper UTC timestamp.
  vevent.addPropertyWithValue('dtstamp', toUtcICALTime(new Date()));

  cal.addSubcomponent(vevent);
  return cal.toString();
}

/**
 * Create a calendar event.
 * Returns { providerEventId, etag, url }
 */
async function createEvent(client, calendarUrl, task, year, tz) {
  var icsData = buildVEvent(task, year, tz);
  var filename = 'juggler-' + task.id + '.ics';
  var baseUrl = calendarUrl.endsWith('/') ? calendarUrl : calendarUrl + '/';
  var expectedUrl = baseUrl + filename;

  var result = await client.createCalendarObject({
    calendar: { url: calendarUrl },
    filename: filename,
    iCalString: icsData
  });

  if (result && result.status === 412) {
    // Event already exists at this URL (stale ledger) — fetch current ETag and overwrite
    var currentEtag = null;
    try {
      var existing = await client.fetchCalendarObjects({
        calendar: { url: calendarUrl },
        objectUrls: [expectedUrl]
      });
      if (existing && existing[0] && existing[0].etag) {
        currentEtag = existing[0].etag;
      }
    } catch (fetchErr) {
      // proceed without ETag — server may accept unconditional overwrite
    }
    var updateResponse = await client.updateCalendarObject({
      calendarObject: { url: expectedUrl, data: icsData, etag: currentEtag || undefined }
    });
    if (updateResponse && updateResponse.status >= 300) {
      var upErr = new Error('CalDAV PUT failed: HTTP ' + updateResponse.status);
      upErr.statusCode = updateResponse.status;
      throw upErr;
    }
    return { providerEventId: expectedUrl, etag: currentEtag, url: expectedUrl };
  }

  if (result && result.status >= 300) {
    var err = new Error('CalDAV PUT failed: HTTP ' + result.status);
    err.statusCode = result.status;
    throw err;
  }

  var eventUrl = result.url || expectedUrl;
  return {
    providerEventId: eventUrl,
    etag: result.etag || null,
    url: eventUrl
  };
}

/**
 * Update an existing calendar event.
 */
async function updateEvent(client, eventUrl, task, year, tz, etag) {
  var icsData = buildVEvent(task, year, tz);

  var response = await client.updateCalendarObject({
    calendarObject: {
      url: eventUrl,
      data: icsData,
      etag: etag || undefined
    }
  });

  if (response && response.status === 412) {
    // Stale ETag — fetch current ETag from server and retry once
    var calUrl = eventUrl.substring(0, eventUrl.lastIndexOf('/') + 1);
    var freshEtag = null;
    try {
      var existing = await client.fetchCalendarObjects({
        calendar: { url: calUrl },
        objectUrls: [eventUrl]
      });
      if (existing && existing[0] && existing[0].etag) {
        freshEtag = existing[0].etag;
      }
    } catch (fetchErr) {
      // proceed without ETag
    }
    var retryResponse = await client.updateCalendarObject({
      calendarObject: { url: eventUrl, data: icsData, etag: freshEtag || undefined }
    });
    if (retryResponse && retryResponse.status >= 300 && retryResponse.status !== 404 && retryResponse.status !== 410) {
      var retryErr = new Error('CalDAV PUT failed: HTTP ' + retryResponse.status);
      retryErr.statusCode = retryResponse.status;
      throw retryErr;
    }
    return;
  }

  if (response && response.status >= 300 && response.status !== 404 && response.status !== 410) {
    var err = new Error('CalDAV PUT failed: HTTP ' + response.status);
    err.statusCode = response.status;
    throw err;
  }
}

/**
 * Delete a calendar event.
 * tsdav returns the HTTP Response without throwing on non-2xx — check it.
 */
async function deleteEvent(client, eventUrl, etag) {
  var response = await client.deleteCalendarObject({
    calendarObject: { url: eventUrl, etag: etag || undefined }
  });

  if (response && response.status >= 300 && response.status !== 404 && response.status !== 410) {
    var err = new Error('CalDAV DELETE failed: HTTP ' + response.status);
    err.statusCode = response.status;
    throw err;
  }
}

/**
 * Check for changes using sync-token or ctag comparison.
 * Returns { hasChanges, syncToken }
 */
async function checkForChanges(client, calendarUrl, storedSyncToken) {
  if (!storedSyncToken) return { hasChanges: true };

  try {
    var calendars = await client.fetchCalendars();
    var normalizeUrl = function(u) { return u ? u.replace(/\/$/, '') : u; };
    var cal = calendars.find(function(c) { return normalizeUrl(c.url) === normalizeUrl(calendarUrl); });
    if (!cal) return { hasChanges: true };

    var currentToken = cal.syncToken || cal.ctag || '';
    if (currentToken !== storedSyncToken) {
      return { hasChanges: true, syncToken: currentToken };
    }
    return { hasChanges: false, syncToken: currentToken };
  } catch (e) {
    // If check fails, assume changes
    return { hasChanges: true };
  }
}

// ── Internal helpers ─────────────────────────────────────────────

function formatICALDate(icalTime) {
  return icalTime.year + '-' +
    String(icalTime.month).padStart(2, '0') + '-' +
    String(icalTime.day).padStart(2, '0');
}

function formatICALDateTime(icalTime) {
  return icalTime.year + '-' +
    String(icalTime.month).padStart(2, '0') + '-' +
    String(icalTime.day).padStart(2, '0') + 'T' +
    String(icalTime.hour).padStart(2, '0') + ':' +
    String(icalTime.minute).padStart(2, '0') + ':' +
    String(icalTime.second || 0).padStart(2, '0');
}

module.exports = {
  DEFAULT_SERVER_URL,
  createClient,
  discoverCalendars,
  listEvents,
  parseVEvents,
  buildVEvent,
  createEvent,
  updateEvent,
  deleteEvent,
  checkForChanges
};

/**
 * Apple Calendar (iCloud CalDAV) adapter for unified sync engine.
 * Implements the provider adapter interface.
 *
 * Uses CalDAV protocol via tsdav with basic auth (app-specific password).
 * Credentials are stored encrypted in the users table.
 * Supports multi-calendar: reads enabled calendars from user_calendars table.
 */

var crypto = require('crypto');
var db = require('../../db');
var appleCalApi = require('../apple-cal-api');
var { decrypt } = require('../credential-encrypt');
var { jugglerDateToISO, isoToJugglerDate, computeDurationMinutes } = require('../../controllers/cal-sync-helpers');
var { localToUtc } = require('../../scheduler/dateHelpers');
var { PLACEMENT_MODES } = require('../placementModes');
var { calAdapterAppleLogger } = require('../logger');

var providerId = 'apple';

function isConnected(user) {
  return !!user.apple_cal_username && !!user.apple_cal_password && !!user.apple_cal_calendar_url;
}

/**
 * Get credentials for CalDAV. Unlike OAuth providers, CalDAV uses basic auth
 * so there's no token refresh — we decrypt the stored password each time.
 * Returns a tsdav DAV client (ready to use).
 */
async function getValidAccessToken(user) {
  if (!user.apple_cal_username || !user.apple_cal_password) {
    throw new Error('Apple Calendar not connected');
  }
  var password = decrypt(user.apple_cal_password);
  var serverUrl = user.apple_cal_server_url || appleCalApi.DEFAULT_SERVER_URL;
  return appleCalApi.createClient(serverUrl, user.apple_cal_username, password);
}

/**
 * Get enabled calendars from user_calendars table, falling back to legacy single URL.
 */
async function getEnabledCalendars(userId) {
  var calendars = await db('user_calendars')
    .where({ user_id: userId, provider: 'apple', enabled: true });

  if (calendars.length > 0) {
    return calendars;
  }

  // Fallback: legacy single-calendar from users table
  var user = await db('users').where('id', userId).first();
  if (user && user.apple_cal_calendar_url) {
    return [{
      id: null,
      calendar_id: user.apple_cal_calendar_url,
      display_name: null,
      sync_direction: 'full',
      ingest_mode: 'task'
    }];
  }

  return [];
}

/**
 * Get the default write calendar (first enabled full-sync calendar).
 */
async function getWriteCalendar(userId) {
  var calendars = await getEnabledCalendars(userId);
  // Prefer full-sync calendars for writing
  var fullSync = calendars.filter(function(c) { return c.sync_direction === 'full'; });
  return fullSync.length > 0 ? fullSync[0] : null;
}

/**
 * Fetch events from all enabled Apple Calendars and normalize to unified shape.
 */
async function listEvents(client, timeMin, timeMax, userId) {
  var calendars = await getEnabledCalendars(userId);
  if (calendars.length === 0) {
    throw new Error('Apple Calendar: no calendars enabled');
  }

  var allEvents = [];
  var hasPartialFailure = false;
  for (var i = 0; i < calendars.length; i++) {
    var cal = calendars[i];
    try {
      var events = await appleCalApi.listEvents(client, cal.calendar_id, timeMin, timeMax);
      var normalized = events.map(function(e) {
        var ne = normalizeEvent(e);
        ne._calendarId = cal.calendar_id;
        return ne;
      });
      allEvents = allEvents.concat(normalized);
    } catch (e) {
      hasPartialFailure = true;
      calAdapterAppleLogger.error('Error fetching calendar', { 
        calendarId: cal.display_name || cal.calendar_id, 
        error: e 
      });
    }
  }

  // Update sync tokens for all calendars
  try {
    var fetchedCalendars = await client.fetchCalendars();
    for (var j = 0; j < calendars.length; j++) {
      var userCal = calendars[j];
      var remoteCal = fetchedCalendars.find(function(c) { return c.url === userCal.calendar_id; });
      if (remoteCal && (remoteCal.syncToken || remoteCal.ctag)) {
        // Store sync token per calendar — use the first one for legacy compat
        if (j === 0) {
          await db('users').where('id', userId).update({
            apple_cal_sync_token: remoteCal.syncToken || remoteCal.ctag
          });
        }
      }
    }
  } catch (e) {
    calAdapterAppleLogger.error('Sync token update failed', { error: e });
  }

  if (hasPartialFailure) {
    allEvents._hasPartialFailure = true;
  }
  return allEvents;
}

/**
 * Lightweight check: has anything changed since last sync?
 */
async function hasChanges(client, user) {
  var syncToken = user.apple_cal_sync_token;
  if (!syncToken) return { hasChanges: true };

  // Check the primary calendar (legacy field) for changes
  var calendarUrl = user.apple_cal_calendar_url;
  if (!calendarUrl) return { hasChanges: true };

  var result = await appleCalApi.checkForChanges(
    client, calendarUrl, syncToken
  );

  if (!result.hasChanges && result.syncToken && result.syncToken !== syncToken) {
    await db('users').where('id', user.id).update({
      apple_cal_sync_token: result.syncToken
    });
  }

  return result;
}

/**
 * Normalize a parsed CalDAV event to the unified NormalizedEvent shape.
 * The events from apple-cal-api.js are already partially normalized;
 * this ensures full compatibility with the sync engine.
 */
function normalizeEvent(event) {
  return {
    id: event.id || event._url || '',
    title: event.title || '(No title)',
    description: event.description || '',
    startDateTime: event.startDateTime || '',
    endDateTime: event.endDateTime || '',
    startTimezone: event.startTimezone || null,
    isAllDay: !!event.isAllDay,
    durationMinutes: event.durationMinutes || 30,
    lastModified: event.lastModified || null,
    isTransparent: !!event.isTransparent,
    _url: event._url || null,
    _etag: event._etag || null,
    _raw: event._raw || null
  };
}

/**
 * Create a calendar event from a task.
 * Writes to the default write calendar (first enabled full-sync calendar).
 */
async function createEvent(client, task, year, tz) {
  var userId = task.userId || task.user_id;
  var writeCal = await getWriteCalendar(userId);
  if (!writeCal) throw new Error('No Apple calendar available for writing (all ingest-only?)');

  var calendarUrl = writeCal.calendar_id;
  var result = await appleCalApi.createEvent(client, calendarUrl, task, year, tz);
  return {
    providerEventId: result.providerEventId,
    calendarId: calendarUrl,
    raw: result
  };
}

/**
 * Update an existing calendar event.
 */
async function updateEvent(client, eventUrl, task, year, tz) {
  await appleCalApi.updateEvent(client, eventUrl, task, year, tz);
}

/**
 * Delete a calendar event.
 */
async function deleteEvent(client, eventUrl) {
  await appleCalApi.deleteEvent(client, eventUrl);
}

/**
 * Compute DB update fields from a normalized event.
 */
function applyEventToTaskFields(event, tz, currentTask) {
  var isAllDay = event.isAllDay;
  var jd = isoToJugglerDate(event.startDateTime, tz);

  var fields = {
    text: event.title,
    dur: event.durationMinutes,
    updated_at: db.fn.now()
  };

  if (jd.date) {
    if (isAllDay) {
      fields.scheduled_at = localToUtc(jd.date, '12:00 AM', tz);
    } else if (jd.time) {
      fields.scheduled_at = localToUtc(jd.date, jd.time, tz);
    }
  }

  if (isAllDay) {
    fields.placement_mode = PLACEMENT_MODES.ALL_DAY;
    // Phase 15: Removed legacy when='allday' tag — all downstream sites now
    // use placement_mode='all_day' exclusively (see ROADMAP 999.011).
  }

  if (event.isTransparent) {
    fields.placement_mode = PLACEMENT_MODES.REMINDER;
  }

  // Reset to ANYTIME if no longer transparent (was REMINDER) — must run before
  // FIXED promotion so a same-sync date/time change still wins.
  if (!event.isTransparent && currentTask?.placement_mode === PLACEMENT_MODES.REMINDER) {
    fields.placement_mode = PLACEMENT_MODES.ANYTIME;
  }

  // Set FIXED if date/time changed — wins over ANYTIME reset above.
  if (!isAllDay) {
    var dateChanged = jd.date && jd.date !== currentTask?.date;
    var timeChanged = jd.time && jd.time !== currentTask?.time;
    if (dateChanged || timeChanged) {
      fields.placement_mode = PLACEMENT_MODES.FIXED;
    }
  }

  return fields;
}

/**
 * Hash a normalized event for change detection.
 */
function eventHash(event) {
  var str = [
    event.title || '',
    event.startDateTime || '',
    event.endDateTime || '',
    event.description || '',
    event.isTransparent ? 'transparent' : 'opaque',
    event.isAllDay ? 'allday' : 'timed'
  ].join('|');
  return crypto.createHash('sha256').update(str).digest('hex');
}

function getEventIdColumn() {
  return 'apple_event_id';
}

function getLastSyncedColumn() {
  return 'apple_cal_last_synced_at';
}

/**
 * Batch create events. CalDAV has no batch API, so we do sequential creates.
 */
async function batchCreateEvents(client, taskEventPairs, year, tz) {
  var results = [];
  for (var i = 0; i < taskEventPairs.length; i++) {
    var pair = taskEventPairs[i];
    try {
      var result = await createEvent(client, pair.task, year, tz);
      results.push({
        taskId: pair.task.id,
        providerEventId: result.providerEventId,
        raw: result.raw,
        error: null
      });
    } catch (e) {
      results.push({
        taskId: pair.task.id,
        providerEventId: null,
        raw: null,
        error: e.message
      });
    }
  }
  return results;
}

/**
 * Batch delete events. Sequential deletes (no CalDAV batch API).
 */
async function batchDeleteEvents(client, eventUrls) {
  var results = [];
  for (var i = 0; i < eventUrls.length; i++) {
    try {
      await deleteEvent(client, eventUrls[i]);
      results.push({ eventId: eventUrls[i], error: null });
    } catch (e) {
      // Treat 404/410 as success (event already gone)
      if (e.message && (e.message.includes('404') || e.message.includes('410'))) {
        results.push({ eventId: eventUrls[i], error: null });
      } else {
        results.push({ eventId: eventUrls[i], error: e.message });
      }
    }
  }
  return results;
}

