/**
 * credential-encrypt.js — AES-256-GCM encryption for stored credentials.
 *
 * Used to encrypt app-specific passwords (e.g., Apple CalDAV) at rest.
 * Key is read from CREDENTIAL_ENCRYPTION_KEY env var (64-char hex = 32 bytes).
 *
 * Generate a key: node -e "logger.info(require('crypto').randomBytes(32).toString('hex'))"
 */

var crypto = require('crypto');

var ALGORITHM = 'aes-256-gcm';
var IV_LENGTH = 12;
var TAG_LENGTH = 16;

function getKey() {
  var hex = process.env.CREDENTIAL_ENCRYPTION_KEY;
  if (!hex || hex.length !== 64) {
    throw new Error('CREDENTIAL_ENCRYPTION_KEY must be a 64-char hex string (32 bytes). Generate with: node -e "logger.info(require(\'crypto\').randomBytes(32).toString(\'hex\'))"');
  }
  return Buffer.from(hex, 'hex');
}

/**
 * Encrypt plaintext. Returns a JSON string containing iv, tag, and ciphertext (all hex).
 */
function encrypt(plaintext) {
  var key = getKey();
  var iv = crypto.randomBytes(IV_LENGTH);
  var cipher = crypto.createCipheriv(ALGORITHM, key, iv);
  var encrypted = Buffer.concat([cipher.update(plaintext, 'utf8'), cipher.final()]);
  var tag = cipher.getAuthTag();
  return JSON.stringify({
    iv: iv.toString('hex'),
    tag: tag.toString('hex'),
    ct: encrypted.toString('hex')
  });
}

/**
 * Decrypt a JSON string produced by encrypt(). Returns plaintext.
 */
function decrypt(json) {
  var key = getKey();
  var data = typeof json === 'string' ? JSON.parse(json) : json;
  var iv = Buffer.from(data.iv, 'hex');
  var tag = Buffer.from(data.tag, 'hex');
  var ct = Buffer.from(data.ct, 'hex');
  var decipher = crypto.createDecipheriv(ALGORITHM, key, iv);
  decipher.setAuthTag(tag);
  var decrypted = Buffer.concat([decipher.update(ct), decipher.final()]);
  return decrypted.toString('utf8');
}

module.exports = { encrypt, decrypt };

/**
 * Google Calendar API wrapper using google-auth-library OAuth2Client
 * Makes REST calls to Calendar API v3 — no googleapis package needed.
 */

const { OAuth2Client } = require('google-auth-library');
const { libGcalLogger } = require('./logger');

const logger = libGcalLogger;

const CALENDAR_BASE = 'https://www.googleapis.com/calendar/v3';

function createOAuth2Client() {
  return new OAuth2Client(
    process.env.GOOGLE_CLIENT_ID,
    process.env.GOOGLE_CLIENT_SECRET,
    process.env.GCAL_REDIRECT_URI || 'http://localhost:5002/api/gcal/callback'
  );
}

function getAuthUrl(oauth2Client, state) {
  return oauth2Client.generateAuthUrl({
    access_type: 'offline',
    prompt: 'consent',
    scope: ['https://www.googleapis.com/auth/calendar.events'],
    state
  });
}

async function getTokensFromCode(oauth2Client, code) {
  const { tokens } = await oauth2Client.getToken(code);
  return tokens;
}

async function refreshAccessToken(oauth2Client, refreshToken) {
  oauth2Client.setCredentials({ refresh_token: refreshToken });
  const { credentials } = await oauth2Client.refreshAccessToken();
  return credentials;
}

async function calendarFetch(accessToken, path, options = {}) {
  const url = CALENDAR_BASE + path;
  const headers = {
    'Authorization': 'Bearer ' + accessToken,
    'Content-Type': 'application/json'
  };

  const fetchOpts = { method: options.method || 'GET', headers };
  if (options.body) {
    fetchOpts.body = JSON.stringify(options.body);
  }

  var maxRetries = 3;
  for (var attempt = 0; attempt <= maxRetries; attempt++) {
    const res = await fetch(url, fetchOpts);
    if (res.status === 429 || res.status === 503) {
      if (attempt === maxRetries) {
        const text = await res.text();
        throw new Error('Calendar API rate limited (status ' + res.status + ' after ' + (maxRetries + 1) + ' attempts): ' + text);
      }
      var retryAfter = parseInt(res.headers.get('Retry-After'), 10);
      var delayMs = Math.min((retryAfter && retryAfter > 0 ? retryAfter * 1000 : Math.pow(2, attempt) * 1000), 30000);
      logger.warn('GCal API rate limited, retrying', { 
        status: res.status, 
        method: options.method || 'GET', 
        path, 
        attempt: attempt + 1, 
        maxRetries,
        delayMs 
      });
      await new Promise(function(r) { setTimeout(r, delayMs); });
      continue;
    }
    if (!res.ok) {
      const text = await res.text();
      throw new Error('Calendar API error ' + res.status + ': ' + text);
    }
    if (res.status === 204) return null;
    return res.json();
  }
}

async function listEvents(accessToken, timeMin, timeMax) {
  var allItems = [];
  var pageToken = null;
  var nextSyncToken = null;

  var maxPages = 20; // Cap to prevent runaway pagination
  var page = 0;
  do {
    var params = new URLSearchParams({
      timeMin,
      timeMax,
      singleEvents: 'true',
      orderBy: 'startTime',
      maxResults: '250'
    });
    if (pageToken) params.append('pageToken', pageToken);

    var data = await calendarFetch(accessToken, '/calendars/primary/events?' + params.toString());
    if (data && data.items) {
      allItems = allItems.concat(data.items);
    }
    pageToken = data && data.nextPageToken ? data.nextPageToken : null;
    if (data && data.nextSyncToken) nextSyncToken = data.nextSyncToken;
    page++;
  } while (pageToken && page < maxPages);

  return { items: allItems, nextSyncToken: nextSyncToken };
}

/**
 * Lightweight check: use a sync token to ask Google if anything changed.
 * Returns { hasChanges, changedCount, nextSyncToken, items }.
 * If the sync token is invalid/expired (410), returns { hasChanges: true, tokenInvalid: true }.
 */
async function checkForChanges(accessToken, syncToken) {
  try {
    var params = new URLSearchParams({ syncToken: syncToken, maxResults: '1' });
    var data = await calendarFetch(accessToken, '/calendars/primary/events?' + params.toString());

    var items = (data && data.items) || [];
    return {
      hasChanges: items.length > 0,
      changedCount: items.length,
      nextSyncToken: data && data.nextSyncToken ? data.nextSyncToken : syncToken
    };
  } catch (err) {
    // 410 Gone = sync token expired, need full sync
    if (err.message && err.message.includes('410')) {
      return { hasChanges: true, tokenInvalid: true };
    }
    throw err;
  }
}

async function insertEvent(accessToken, event) {
  return calendarFetch(accessToken, '/calendars/primary/events', {
    method: 'POST',
    body: event
  });
}

async function patchEvent(accessToken, eventId, patch) {
  return calendarFetch(accessToken, '/calendars/primary/events/' + encodeURIComponent(eventId), {
    method: 'PATCH',
    body: patch
  });
}

async function deleteEvent(accessToken, eventId) {
  return calendarFetch(accessToken, '/calendars/primary/events/' + encodeURIComponent(eventId), {
    method: 'DELETE'
  });
}

/**
 * Batch API: send up to 50 requests in a single HTTP call.
 * Google uses multipart/mixed with a boundary for batch requests.
 *
 * @param {string} accessToken
 * @param {Array<{method, path, body?, id?}>} requests — each is one sub-request
 * @returns {Array<{id, status, body}>} — parsed responses in order
 */
async function batchRequest(accessToken, requests) {
  if (requests.length === 0) return [];

  var boundary = 'batch_' + Date.now();
  var parts = requests.map(function(req, i) {
    var id = req.id || String(i);
    var method = req.method || 'GET';
    var path = req.path.startsWith('http') ? req.path : CALENDAR_BASE + req.path;
    var lines = [
      '--' + boundary,
      'Content-Type: application/http',
      'Content-ID: <' + id + '>',
      '',
      method + ' ' + path + ' HTTP/1.1'
    ];
    if (req.body) {
      lines.push('Content-Type: application/json');
      lines.push('');
      lines.push(JSON.stringify(req.body));
    } else {
      lines.push('');
    }
    return lines.join('\r\n');
  });

  var payload = parts.join('\r\n') + '\r\n--' + boundary + '--';

  var res = await fetch('https://www.googleapis.com/batch/calendar/v3', {
    method: 'POST',
    headers: {
      'Authorization': 'Bearer ' + accessToken,
      'Content-Type': 'multipart/mixed; boundary=' + boundary
    },
    body: payload
  });

  var responseText = await res.text();

  // Parse multipart response
  var respBoundary = res.headers.get('content-type').match(/boundary=(.+)/);
  var sep = respBoundary ? respBoundary[1] : boundary;
  var responseParts = responseText.split('--' + sep).filter(function(p) {
    return p.trim() && p.trim() !== '--';
  });

  return responseParts.map(function(part) {
    // Extract Content-ID
    var idMatch = part.match(/Content-ID:\s*<?\s*response-([^>\s]+)/i);
    var id = idMatch ? idMatch[1] : null;

    // Find the HTTP response line
    var httpMatch = part.match(/HTTP\/1\.1\s+(\d+)/);
    var status = httpMatch ? parseInt(httpMatch[1], 10) : 0;

    // Extract JSON body (everything after the blank line following headers)
    var bodyMatch = part.match(/\r?\n\r?\n\{[\s\S]*$/);
    var body = null;
    if (bodyMatch) {
      try { body = JSON.parse(bodyMatch[0].trim()); } catch (e) { /* not JSON */ }
    }

    return { id: id, status: status, body: body };
  });
}

module.exports = {
  createOAuth2Client,
  getAuthUrl,
  getTokensFromCode,
  refreshAccessToken,
  listEvents,
  checkForChanges,
  insertEvent,
  patchEvent,
  deleteEvent,
  batchRequest
};

/**
 * Shared JWT secret for OAuth state tokens.
 * Used by calendar controllers (gcal, msft).
 */
function getJwtSecret() {
  var secret = process.env.JWT_SECRET;
  if (!secret) {
    if (process.env.NODE_ENV === 'production') throw new Error('JWT_SECRET required in production');
    secret = 'local-dev-jwt-secret-juggler';
  }
  return new TextEncoder().encode(secret);
}

module.exports = { getJwtSecret };

/**
 * lib-logger - Structured logging utilities for Juggler
 *
 * Factory-based logger utilities replacing console.* calls with structured logging.
 * Provides:
 * - createLogger(name, config): Factory function for named loggers
 * - Named loggers per slice/module
 * - Structured output with timestamps, level, module context
 * - Configurable log levels and output formats
 *
 * @module lib/logger
 */

/**
 * Log levels in order of severity (most severe first)
 * @type {string[]}
 */
const LOG_LEVELS = ['error', 'warn', 'info', 'debug', 'trace'];

/**
 * Default log level - can be overridden via LOG_LEVEL or NODE_ENV
 * @type {string}
 */
const DEFAULT_LOG_LEVEL = process.env.LOG_LEVEL || 
  (process.env.NODE_ENV === 'production' ? 'info' : 'debug');

/**
 * ANSI color codes for terminal output (production uses plaintext)
 */
const COLORS = {
  reset: '\x1b[0m',
  red: '\x1b[31m',
  yellow: '\x1b[33m',
  green: '\x1b[32m',
  blue: '\x1b[34m',
  gray: '\x1b[90m',
  cyan: '\x1b[36m'
};

/**
 * Level color mapping for terminal output
 */
const LEVEL_COLORS = {
  error: COLORS.red,
  warn: COLORS.yellow,
  info: COLORS.green,
  debug: COLORS.blue,
  trace: COLORS.gray
};

/**
 * Check if the current environment supports colors
 * @returns {boolean}
 */
function supportsColors() {
  // No colors in production or when running in a non-TTY environment
  if (process.env.NODE_ENV === 'production') return false;
  // Check for CI environments
  if (process.env.CI || process.env.NO_COLOR || process.env.TERM === 'dumb') return false;
  // Check for TTY
  if (!process.stdout.isTTY) return false;
  return true;
}

/**
 * Format a log timestamp in ISO8601 format
 * @returns {string}
 */
function formatTimestamp() {
  return new Date().toISOString();
}

/**
 * Get the numeric level index (higher = more verbose)
 * @param {string} level
 * @returns {number}
 */
function getLevelIndex(level) {
  return LOG_LEVELS.indexOf(level.toLowerCase());
}

/**
 * Check if current log level allows the given level
 * @param {string} currentLevel
 * @param {string} messageLevel
 * @returns {boolean}
 */
function shouldLog(currentLevel, messageLevel) {
  return getLevelIndex(messageLevel) <= getLevelIndex(currentLevel);
}

/**
 * Safely serialize an error object to a loggable structure
 * @param {Error} err
 * @returns {Object}
 */
function serializeError(err) {
  if (!err || typeof err !== 'object') return err;
  return {
    name: err.name || 'Error',
    message: err.message || String(err),
    stack: err.stack || null,
    // Include additional error properties (e.g., from axios, http-errors)
    ...(err.code && { code: err.code }),
    ...(err.status && { status: err.status }),
    ...(err.statusCode && { statusCode: err.statusCode }),
    ...(err.config && { config: { url: err.config?.url, method: err.config?.method } })
  };
}

/**
 * Structured logger class for a specific module/scope
 */
class Logger {
  /**
   * Create a new Logger instance
   * @param {string} name - The module/scope name (e.g., 'scheduler', 'task.controller')
   * @param {Object} config - Configuration options
   * @param {string} config.level - Log level threshold (error, warn, info, debug, trace)
   * @param {boolean} config.json - Output as JSON (default: true in production)
   * @param {boolean} config.colors - Use ANSI colors (default: auto-detect)
   * @param {Function} config.output - Output function (default: console.log)
   * @param {Function} config.errorOutput - Error output function (default: console.error)
   */
  constructor(name, config = {}) {
    this.name = name;
    this.level = config.level || DEFAULT_LOG_LEVEL;
    this.json = config.json !== undefined ? config.json : process.env.NODE_ENV === 'production';
    this.colors = config.colors !== undefined ? config.colors : supportsColors();
    this.output = config.output || console.log;
    this.errorOutput = config.errorOutput || console.error;
  }

  /**
   * Format and output a log message
   * @private
   * @param {string} level - Log level
   * @param {string} message - Message string
   * @param {Object} [meta] - Additional structured data
   */
  _log(level, message, meta = {}) {
    if (!shouldLog(this.level, level)) return;

    const timestamp = formatTimestamp();
    const record = {
      timestamp,
      level: level.toUpperCase(),
      module: this.name,
      message,
      ...meta
    };

    // Handle error objects specially - serialize them
    if (meta.error instanceof Error) {
      record.error = serializeError(meta.error);
    }

    // Handle Error objects passed as 'err' (common pattern)
    if (meta.err instanceof Error) {
      record.err = serializeError(meta.err);
    }

    if (this.json) {
      // JSON output for production / structured logs
      this.output(JSON.stringify(record));
    } else {
      // Human-readable output for development
      const color = this.colors ? LEVEL_COLORS[level] || '' : '';
      const reset = this.colors ? COLORS.reset : '';
      const gray = this.colors ? COLORS.gray : '';
      const cyan = this.colors ? COLORS.cyan : '';

      const levelStr = level.toUpperCase().padEnd(5);
      const prefix = `${gray}[${timestamp}]${reset} ${color}${levelStr}${reset} ${cyan}${this.name}:${reset}`;

      // Format additional metadata
      let metaStr = '';
      const metaEntries = Object.entries(meta)
        .filter(([key, value]) => value !== undefined && !(value instanceof Error));

      if (metaEntries.length > 0) {
        metaStr = ' ' + JSON.stringify(Object.fromEntries(metaEntries));
      }

      // Print error stack below message if present
      const errorObj = meta.error || meta.err;
      if (errorObj && (errorObj.stack || errorObj.stack === null)) {
        // Serialized error from above
        this.output(`${prefix} ${message}${metaStr}`);
        if (errorObj.stack) {
          this.errorOutput(errorObj.stack);
        }
      } else {
        const useOutput = level === 'error' ? this.errorOutput : this.output;
        useOutput(`${prefix} ${message}${metaStr}`);
      }
    }
  }

  /**
   * Log a fatal error (always output)
   * @param {string} message - Error message
   * @param {Object} [meta] - Additional metadata
   */
  error(message, meta) {
    this._log('error', message, meta);
  }

  /**
   * Log a warning
   * @param {string} message - Warning message
   * @param {Object} [meta] - Additional metadata
   */
  warn(message, meta) {
    this._log('warn', message, meta);
  }

  /**
   * Log informational message
   * @param {string} message - Info message
   * @param {Object} [meta] - Additional metadata
   */
  info(message, meta) {
    this._log('info', message, meta);
  }

  /**
   * Log debug message (verbose)
   * @param {string} message - Debug message
   * @param {Object} [meta] - Additional metadata
   */
  debug(message, meta) {
    this._log('debug', message, meta);
  }

  /**
   * Log trace message (very verbose)
   * @param {string} message - Trace message
   * @param {Object} [meta] - Additional metadata
   */
  trace(message, meta) {
    this._log('trace', message, meta);
  }

  /**
   * Create a child logger with additional default metadata
   * Useful for sub-components within a module
   * @param {string} subName - Sub-component name
   * @param {Object} defaultMeta - Default metadata to include in all logs
   * @returns {Logger}
   */
  child(subName, defaultMeta = {}) {
    const childName = `${this.name}.${subName}`;
    const childLogger = new Logger(childName, {
      level: this.level,
      json: this.json,
      colors: this.colors,
      output: this.output,
      errorOutput: this.errorOutput
    });

    // Wrap _log to inject defaultMeta
    const originalLog = childLogger._log.bind(childLogger);
    childLogger._log = (level, message, meta = {}) => {
      originalLog(level, message, { ...defaultMeta, ...meta });
    };

    return childLogger;
  }
}

// Cache of loggers to avoid recreating them
const loggerCache = new Map();

/**
 * Create or retrieve a named logger instance
 *
 * Creates loggers cached by name. Use consistent names to get the same
 * logger instance across requires.
 *
 * @param {string} name - Logger name/scope (e.g., 'scheduler', 'task.controller')
 * @param {Object} [config] - Configuration options
 * @param {string} [config.level] - Log level (defaults to LOG_LEVEL env or 'debug')
 * @param {boolean} [config.json] - JSON output mode (auto-detected from NODE_ENV)
 * @param {boolean} [config.colors] - Use ANSI colors (auto-detected)
 * @param {Function} [config.output] - Output function (defaults to console.log)
 * @param {Function} [config.errorOutput] - Error output function (defaults to console.error)
 * @returns {Logger}
 *
 * @example
 * // In a controller
 * const logger = createLogger('task.controller');
 * logger.info('Task created', { taskId: 'abc123' });
 * logger.error('Task creation failed', { error: err });
 *
 * @example
 * // In scheduler
 * const logger = createLogger('scheduler.runSchedule');
 * logger.debug('Starting scheduler', { userId, taskCount: tasks.length });
 *
 * @example
 * // With custom config (useful for tests)
 * const mockLogger = createLogger('test', {
 *   level: 'error',
 *   output: jest.fn(),
 *   errorOutput: jest.fn()
 * });
 */
function createLogger(name, config) {
  // Create cache key from name + JSON-stringified config (for same config = same logger)
  const cacheKey = name + (config ? ':' + JSON.stringify(config) : '');

  if (!loggerCache.has(cacheKey)) {
    loggerCache.set(cacheKey, new Logger(name, config));
  }

  return loggerCache.get(cacheKey);
}

/**
 * Clear the logger cache (useful for tests)
 */
function clearLoggerCache() {
  loggerCache.clear();
}

