/**
 * Microsoft Calendar API wrapper using Microsoft Graph REST API
 * Uses direct OAuth2 REST calls with PKCE (no MSAL dependency).
 */

var crypto = require('crypto');
var { libMsftLogger } = require('./logger');

var GRAPH_BASE = 'https://graph.microsoft.com/v1.0';
var TOKEN_URL = 'https://login.microsoftonline.com/common/oauth2/v2.0/token';
var AUTH_URL = 'https://login.microsoftonline.com/common/oauth2/v2.0/authorize';

var SCOPES = 'Calendars.ReadWrite offline_access User.Read';

function getRedirectUri() {
  return process.env.MSFT_CAL_REDIRECT_URI || 'http://localhost:5002/api/msft-cal/callback';
}

/**
 * Generate PKCE code_verifier and code_challenge (S256).
 * Required by Azure AD for apps registered with /common endpoint.
 */
function generatePkce() {
  var verifier = crypto.randomBytes(32).toString('base64url');
  var challenge = crypto.createHash('sha256').update(verifier).digest('base64url');
  return { codeVerifier: verifier, codeChallenge: challenge };
}

function getAuthUrl(state, codeChallenge) {
  var params = new URLSearchParams({
    client_id: process.env.MICROSOFT_CLIENT_ID,
    response_type: 'code',
    redirect_uri: getRedirectUri(),
    scope: SCOPES,
    state: state,
    prompt: 'select_account',
    code_challenge: codeChallenge,
    code_challenge_method: 'S256'
  });
  return AUTH_URL + '?' + params.toString();
}

async function getTokensFromCode(code, codeVerifier) {
  var body = new URLSearchParams({
    client_id: process.env.MICROSOFT_CLIENT_ID,
    client_secret: process.env.MICROSOFT_CLIENT_SECRET,
    code: code,
    redirect_uri: getRedirectUri(),
    grant_type: 'authorization_code',
    scope: SCOPES,
    code_verifier: codeVerifier
  });

  libMsftLogger.debug('MSFT token exchange', { redirectUri: getRedirectUri() });

  var res = await fetch(TOKEN_URL, {
    method: 'POST',
    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    body: body.toString()
  });

  var data = await res.json();
  if (!res.ok) {
    libMsftLogger.error('MSFT token exchange failed', { error: data.error, errorDescription: data.error_description });
    throw new Error('Token exchange error: ' + (data.error_description || data.error || res.status));
  }
  libMsftLogger.info('MSFT token exchange succeeded');

  return {
    accessToken: data.access_token,
    refreshToken: data.refresh_token || null,
    expiresIn: data.expires_in,
    expiresOn: new Date(Date.now() + data.expires_in * 1000)
  };
}

async function refreshAccessToken(refreshToken) {
  var body = new URLSearchParams({
    client_id: process.env.MICROSOFT_CLIENT_ID,
    client_secret: process.env.MICROSOFT_CLIENT_SECRET,
    refresh_token: refreshToken,
    grant_type: 'refresh_token',
    scope: SCOPES
  });

  var res = await fetch(TOKEN_URL, {
    method: 'POST',
    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    body: body.toString()
  });

  var data = await res.json();
  if (!res.ok) {
    throw new Error('Token refresh error: ' + (data.error_description || data.error || res.status));
  }

  return {
    accessToken: data.access_token,
    refreshToken: data.refresh_token || refreshToken,
    expiresOn: new Date(Date.now() + data.expires_in * 1000)
  };
}

async function graphFetch(accessToken, path, options) {
  options = options || {};
  var url = GRAPH_BASE + path;
  var headers = {
    'Authorization': 'Bearer ' + accessToken,
    'Content-Type': 'application/json',
    'Prefer': 'outlook.body-content-type="text"'
  };

  var fetchOpts = { method: options.method || 'GET', headers: headers };
  if (options.body) {
    fetchOpts.body = JSON.stringify(options.body);
  }

  var maxRetries = 3;
  for (var attempt = 0; attempt <= maxRetries; attempt++) {
    var res = await fetch(url, fetchOpts);
    if (res.status === 429 || res.status === 503) {
      if (attempt === maxRetries) {
        var text = await res.text();
        throw new Error('Graph API rate limited (status ' + res.status + ' after ' + (maxRetries + 1) + ' attempts): ' + text);
      }
      var retryAfter = parseInt(res.headers.get('Retry-After'), 10);
      var delayMs = Math.min((retryAfter && retryAfter > 0 ? retryAfter * 1000 : Math.pow(2, attempt) * 1000), 30000);
      libMsftLogger.warn('MSFT API rate limited, retrying', { 
        status: res.status,
        method: options.method || 'GET',
        path,
        attempt: attempt + 1,
        maxRetries,
        delayMs
      });
      await new Promise(function(r) { setTimeout(r, delayMs); });
      continue;
    }
    if (!res.ok) {
      var text = await res.text();
      throw new Error('Graph API error ' + res.status + ': ' + text);
    }
    if (res.status === 204) return null;
    return res.json();
  }
}

async function listEvents(accessToken, startDateTime, endDateTime) {
  var allItems = [];
  var params = new URLSearchParams({
    startDateTime: startDateTime,
    endDateTime: endDateTime,
    '$top': '1000',
    '$orderby': 'start/dateTime',
    '$select': 'id,subject,start,end,isAllDay,showAs,lastModifiedDateTime,body,type,seriesMasterId,isCancelled,sensitivity,responseStatus'
  });

  var path = '/me/calendarView?' + params.toString();

  do {
    var data = await graphFetch(accessToken, path);
    if (data && data.value) {
      allItems = allItems.concat(data.value);
    }
    if (data && data['@odata.nextLink']) {
      var nextUrl = data['@odata.nextLink'];
      if (nextUrl.startsWith(GRAPH_BASE)) {
        path = nextUrl.substring(GRAPH_BASE.length);
      } else {
        break;
      }
    } else {
      path = null;
    }
  } while (path);

  return { items: allItems };
}

async function insertEvent(accessToken, event) {
  return graphFetch(accessToken, '/me/events', {
    method: 'POST',
    body: event
  });
}

async function patchEvent(accessToken, eventId, patch) {
  return graphFetch(accessToken, '/me/events/' + encodeURIComponent(eventId), {
    method: 'PATCH',
    body: patch
  });
}

async function deleteEvent(accessToken, eventId) {
  return graphFetch(accessToken, '/me/events/' + encodeURIComponent(eventId), {
    method: 'DELETE'
  });
}

/**
 * Lightweight check using Microsoft Graph delta query.
 * Returns { hasChanges, deltaLink }.
 * If the deltaLink is invalid/expired, returns { hasChanges: true, tokenInvalid: true }.
 */
async function checkForChanges(accessToken, deltaLink) {
  try {
    // deltaLink is a full URL — extract the path after the Graph base
    var path = deltaLink;
    if (path.startsWith(GRAPH_BASE)) {
      path = path.substring(GRAPH_BASE.length);
    }

    var data = await graphFetch(accessToken, path);
    var items = (data && data.value) || [];
    var newDeltaLink = data && data['@odata.deltaLink'] ? data['@odata.deltaLink'] : deltaLink;

    return {
      hasChanges: items.length > 0,
      changedCount: items.length,
      deltaLink: newDeltaLink
    };
  } catch (err) {
    // Expired delta token — need full sync
    if (err.message && (err.message.includes('410') || err.message.includes('syncStateNotFound'))) {
      return { hasChanges: true, tokenInvalid: true };
    }
    throw err;
  }
}

/**
 * Batch API: send up to 20 requests in a single HTTP call.
 * Microsoft Graph uses JSON $batch endpoint.
 *
 * @param {string} accessToken
 * @param {Array<{method, url, body?, id?}>} requests — each is one sub-request
 * @returns {Array<{id, status, body}>} — parsed responses
 */
async function batchRequest(accessToken, requests) {
  if (requests.length === 0) return [];

  var batchBody = {
    requests: requests.map(function(req, i) {
      var item = {
        id: req.id || String(i),
        method: req.method || 'GET',
        url: req.url
      };
      if (req.body) {
        item.body = req.body;
        item.headers = { 'Content-Type': 'application/json' };
      }
      return item;
    })
  };

  var res = await fetch(GRAPH_BASE + '/$batch', {
    method: 'POST',
    headers: {
      'Authorization': 'Bearer ' + accessToken,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify(batchBody)
  });

  var data = await res.json();
  if (!res.ok) {
    throw new Error('Graph batch error ' + res.status + ': ' + JSON.stringify(data));
  }

  return (data.responses || []).map(function(r) {
    return { id: r.id, status: r.status, body: r.body || null };
  });
}

module.exports = {
  generatePkce,
  getAuthUrl,
  getTokensFromCode,
  refreshAccessToken,
  listEvents,
  checkForChanges,
  insertEvent,
  patchEvent,
  deleteEvent,
  batchRequest
};

/**
 * Reconcile split chunks as persistent task_instances rows.
 *
 * A master with split=1 is supposed to decompose each occurrence into
 * N chunks of ~split_min minutes (last chunk may be shorter/merged).
 * Historically the scheduler computed those chunks ephemerally at runtime
 * and forgot them between runs. This helper makes them real rows:
 * each chunk is an instance row with the same occurrence_ordinal and
 * its own split_ordinal / split_total / per-chunk dur.
 *
 * Why persist: per-chunk calendar sync (each chunk becomes its own
 * gcal event), per-chunk status (user marks a single chunk done), and
 * the original product vision that split chunks are first-class tasks.
 *
 * Reconciliation is diff-based and per-occurrence: for each existing
 * occurrence_ordinal on the master, compute the desired chunk count N
 * from master.dur and master.split_min, then insert missing chunks and
 * delete extras. Survivors keep their ids (so cal_sync_ledger bindings
 * persist across re-chunking).
 *
 * Called at the start of each scheduler transaction for non-recurring splits.
 */

var MIN_CHUNK_DEFAULT = 15;

/**
 * Compute the desired chunk plan for a master + occurrence.
 * Returns an array of { splitOrdinal, dur } of length N.
 * Mirrors unifiedSchedule.js:314-338 (includes the "merge tiny last
 * chunk into previous" rule so chunk counts match scheduler expectations).
 */
function computeChunks(totalDur, splitMin) {
  var chunk = splitMin || MIN_CHUNK_DEFAULT;
  if (!totalDur || totalDur <= 0) return [];
  var numChunks = Math.ceil(totalDur / chunk);
  var result = [];
  for (var ci = 0; ci < numChunks; ci++) {
    var isLast = ci === numChunks - 1;
    var chunkDur = (isLast && totalDur % chunk !== 0) ? totalDur % chunk : chunk;
    if (chunkDur < chunk && ci > 0) {
      // Merge tiny last remainder into previous
      result[result.length - 1].dur += chunkDur;
      break;
    }
    result.push({ splitOrdinal: ci + 1, dur: chunkDur });
  }
  // Re-stamp split_total on all chunks
  result.forEach(function(r) { r.splitTotal = result.length; });
  return result;
}

/**
 * Reconcile chunk rows for one master. Returns counts of inserts/deletes/updates.
 *
 * Contract:
 *   - If master.split is falsy: collapse all instances back to split_ordinal=1,
 *     split_total=1 (undo any previous chunking).
 *   - If master.split is true: for each distinct occurrence_ordinal the master
 *     already has an instance for, materialize N chunk rows with split_ordinal 1..N.
 *
 * Uses deterministic ids for new chunk rows: `masterId-<splitOrdinal>`.
 */
async function reconcileSplitsForMaster(trx, masterId) {
  var master = await trx('task_masters').where('id', masterId).first();
  if (!master) return { inserted: 0, deleted: 0, updated: 0, skipped: 'master_not_found' };

  var existing = await trx('task_instances')
    .where('master_id', masterId)
    .orderBy([{ column: 'occurrence_ordinal' }, { column: 'split_ordinal' }]);

  // Collapse mode: master is not (or no longer) split.
  if (!master.split) {
    return collapseChunks(trx, masterId, master, existing);
  }

  // Expand mode: group existing by occurrence and reconcile each.
  var byOcc = {};
  existing.forEach(function(r) {
    var k = r.occurrence_ordinal;
    if (!byOcc[k]) byOcc[k] = [];
    byOcc[k].push(r);
  });

  var inserted = 0, deleted = 0, updated = 0;
  var occKeys = Object.keys(byOcc);
  for (var oi = 0; oi < occKeys.length; oi++) {
    var occOrd = Number(occKeys[oi]);
    var rows = byOcc[occKeys[oi]];
    var r = await reconcileOccurrence(trx, masterId, master, occOrd, rows);
    inserted += r.inserted;
    deleted += r.deleted;
    updated += r.updated;
  }
  return { inserted: inserted, deleted: deleted, updated: updated };
}

async function reconcileOccurrence(trx, masterId, master, occOrd, existingRows) {
  // Desired chunk plan derived from master
  var desired = computeChunks(master.dur, master.split_min);
  if (desired.length === 0) return { inserted: 0, deleted: 0, updated: 0 };

  // Sort existing by split_ordinal
  existingRows.sort(function(a, b) { return a.split_ordinal - b.split_ordinal; });

  var inserted = 0, deleted = 0, updated = 0;

  // Update survivors (matching split_ordinal 1..min(existing, desired))
  var overlap = Math.min(existingRows.length, desired.length);
  for (var i = 0; i < overlap; i++) {
    var e = existingRows[i];
    var d = desired[i];
    if (e.split_ordinal !== d.splitOrdinal ||
        Number(e.split_total) !== desired.length ||
        Number(e.dur) !== d.dur) {
      await trx('task_instances')
        .where('id', e.id)
        .update({
          split_ordinal: d.splitOrdinal,
          split_total: desired.length,
          dur: d.dur,
          updated_at: trx.fn.now()
        });
      updated++;
    }
  }

  // Insert missing chunks (when desired > existing)
  if (desired.length > existingRows.length) {
    var template = existingRows[0]; // carry scheduling fields from occurrence's primary row
    for (var j = existingRows.length; j < desired.length; j++) {
      var d2 = desired[j];
      await trx('task_instances').insert({
        id: masterId + '-occ' + occOrd + '-' + d2.splitOrdinal,
        master_id: masterId,
        user_id: master.user_id,
        occurrence_ordinal: occOrd,
        split_ordinal: d2.splitOrdinal,
        split_total: desired.length,
        split_group: masterId,
        dur: d2.dur,
        // Placement left null — scheduler assigns on next run
        scheduled_at: null,
        status: '',
        time_remaining: null,
        unscheduled: null,
        generated: 0,
        created_at: trx.fn.now(),
        updated_at: trx.fn.now()
      });
      inserted++;
    }
  }

  // Delete extras (when existing > desired) — delete from the tail (highest split_ordinal)
  if (existingRows.length > desired.length) {
    var toDel = existingRows.slice(desired.length).map(function(r) { return r.id; });
    await trx('task_instances').whereIn('id', toDel).del();
    deleted += toDel.length;
  }

  return { inserted: inserted, deleted: deleted, updated: updated };
}

/**
 * Collapse: master is no longer split. Keep split_ordinal=1 rows, delete the rest.
 * Reset split_total=1 on survivors.
 */
async function collapseChunks(trx, masterId, master, existing) {
  var deleted = 0, updated = 0;
  var survivors = [];
  var toDel = [];
  existing.forEach(function(r) {
    if (r.split_ordinal === 1) survivors.push(r);
    else toDel.push(r.id);
  });
  if (toDel.length > 0) {
    await trx('task_instances').whereIn('id', toDel).del();
    deleted = toDel.length;
  }
  for (var i = 0; i < survivors.length; i++) {
    var s = survivors[i];
    if (Number(s.split_total) !== 1 || Number(s.dur) !== Number(master.dur)) {
      await trx('task_instances')
        .where('id', s.id)
        .update({
          split_total: 1,
          dur: master.dur,
          updated_at: trx.fn.now()
        });
      updated++;
    }
  }
  return { inserted: 0, deleted: deleted, updated: updated };
}

/**
 * Per-user batched reconcile: load all NON-RECURRING split masters + their
 * instances in two queries, then reconcile in memory.
 *
 * Restricted to non-recurring tasks (recurring: 0) because recurring split
 * tasks are managed by the Phase 1 upfront INSERT path in runSchedule.js
 * (step 5b). Calling this on recurring masters would create secondary chunks
 * that conflict with the scheduler's <primaryId>-<ordinal>-N naming scheme.
 *
 * Called at the start of each scheduler transaction (before the task load)
 * so that newly created or config-changed non-recurring split tasks have
 * their secondary chunk rows materialized before the scheduler tries to
 * place them.
 */
async function reconcileSplitsForUser(trx, userId) {
  var masters = await trx('task_masters')
    .where({ user_id: userId, split: 1, recurring: 0 })
    .whereNull('disabled_at')
    .select();
  if (masters.length === 0) {
    return { inserted: 0, deleted: 0, updated: 0, mastersTouched: 0, touchedMasterIds: [] };
  }

  var masterIds = masters.map(function(m) { return m.id; });
  var allInstances = await trx('task_instances')
    .whereIn('master_id', masterIds)
    .orderBy([{ column: 'master_id' }, { column: 'occurrence_ordinal' }, { column: 'split_ordinal' }]);

  var byMaster = {};
  allInstances.forEach(function(r) {
    if (!byMaster[r.master_id]) byMaster[r.master_id] = [];
    byMaster[r.master_id].push(r);
  });

  var inserted = 0, deleted = 0, updated = 0;
  var touchedMasterIds = [];
  for (var mi = 0; mi < masters.length; mi++) {
    var master = masters[mi];
    var existing = byMaster[master.id] || [];
    var r = await reconcileMasterFromLoaded(trx, master, existing);
    inserted += r.inserted;
    deleted += r.deleted;
    updated += r.updated;
    if ((r.inserted + r.deleted + r.updated) > 0) touchedMasterIds.push(master.id);
  }
  return {
    inserted: inserted, deleted: deleted, updated: updated,
    mastersTouched: touchedMasterIds.length,
    touchedMasterIds: touchedMasterIds
  };
}

/**
 * Like reconcileSplitsForMaster but takes pre-loaded master + instances
 * to avoid the 2 queries per master. Used by reconcileSplitsForUser.
 */
async function reconcileMasterFromLoaded(trx, master, existing) {
  if (!master.split) {
    return collapseChunks(trx, master.id, master, existing);
  }
  var byOcc = {};
  existing.forEach(function(r) {
    var k = r.occurrence_ordinal;
    if (!byOcc[k]) byOcc[k] = [];
    byOcc[k].push(r);
  });
  var inserted = 0, deleted = 0, updated = 0;
  var occKeys = Object.keys(byOcc);
  for (var oi = 0; oi < occKeys.length; oi++) {
    var occOrd = Number(occKeys[oi]);
    var rows = byOcc[occKeys[oi]];
    var r = await reconcileOccurrence(trx, master.id, master, occOrd, rows);
    inserted += r.inserted;
    deleted += r.deleted;
    updated += r.updated;
  }
  return { inserted: inserted, deleted: deleted, updated: updated };
}

module.exports = {
  computeChunks: computeChunks,
  reconcileSplitsForMaster: reconcileSplitsForMaster,
  reconcileSplitsForUser: reconcileSplitsForUser,
};

/**
 * Shared helpers for the rolling-cadence recurring task anchor update logic.
 * Used by task.controller.js, cal-history-cron.js, and mcp/tools/tasks.js.
 */

/**
 * Returns true if the given task_masters row uses recur.type = 'rolling'.
 * @param {Object} masterRow - row from task_masters (recur is JSON string or object)
 */
function isRollingMaster(masterRow) {
  if (!masterRow || !masterRow.recur) return false;
  try {
    var recur = typeof masterRow.recur === 'string'
      ? JSON.parse(masterRow.recur)
      : masterRow.recur;
    return recur && recur.type === 'rolling';
  } catch (e) {
    return false;
  }
}

/**
 * Compute the new rolling_anchor for a terminal status event.
 *
 * Rules:
 *   done   → instanceDate (anchor from when task was scheduled/done)
 *   skip   → instanceDate (full reanchor from skip date)
 *   missed → instanceDate + 1 day (soft nudge)
 *   cancel → null (no anchor change)
 *
 * Guard: if instanceDate < currentAnchor, return null (stale event, skip).
 *
 * @param {string} status - 'done' | 'skip' | 'missed' | 'cancel'
 * @param {string} instanceDate - ISO date string 'YYYY-MM-DD' of the instance
 * @param {string|null} currentAnchor - current rolling_anchor from task_masters
 * @returns {string|null} new anchor ISO date, or null if no update needed
 */
function computeRollingAnchor(status, instanceDate, currentAnchor) {
  if (!instanceDate) return null;
  if (status === 'cancel') return null;
  if (!['done', 'skip', 'missed'].includes(status)) return null;

  // Guard: stale event
  if (currentAnchor && instanceDate < currentAnchor) return null;

  if (status === 'done' || status === 'skip') {
    return instanceDate;
  }

  // missed: +1 day
  var d = new Date(instanceDate + 'T00:00:00');
  d.setDate(d.getDate() + 1);
  var y = d.getFullYear();
  var m = d.getMonth() + 1;
  var day = d.getDate();
  return y + '-' + (m < 10 ? '0' : '') + m + '-' + (day < 10 ? '0' : '') + day;
}

module.exports = { isRollingMaster, computeRollingAnchor };

/**
 * SSE Event Emitter — multi-instance safe via Redis pub/sub.
 *
 * Each instance holds its own in-memory client map (for response writing).
 * Events are published to Redis channel `sse:{userId}` so all instances
 * receive them regardless of which instance handled the mutation.
 *
 * Falls back to direct local-only emit if Redis is unavailable (single-instance OK).
 */

const Redis = require('ioredis');

const CHANNEL_PREFIX = 'sse:';

// Local SSE response objects — own-instance only
var clients = {};

// Lazy subscriber client — separate connection required for Redis pub/sub
var subscriber = null;

function getSubscriber() {
  if (subscriber) return subscriber;
  if (!process.env.REDIS_URL) return null;  // no-op when Redis not configured
  subscriber = new Redis(process.env.REDIS_URL, {
    maxRetriesPerRequest: 1,
    enableOfflineQueue: false,
    retryStrategy: function(times) {
      if (times > 3) return null;
      return Math.min(times * 200, 2000);
    }
  });
  subscriber.on('message', function(channel, message) {
    var userId = channel.slice(CHANNEL_PREFIX.length);
    var subs = clients[userId];
    if (!subs || subs.size === 0) return;
    subs.forEach(function(res) {
      try { res.write(message); }
      catch (e) { subs.delete(res); }
    });
  });
  subscriber.on('error', function(err) {
    logger.warn('[sse-emitter] Redis subscriber error (falling back to local-only):', err.message);
  });
  subscriber.on('end', function() {
    logger.warn('[sse-emitter] Redis subscriber connection ended; will recreate on next use');
    subscriber = null;
  });
  return subscriber;
}

// Publisher client — reuse the same connection pattern as redis.js but separate client
var publisher = null;
function getPublisher() {
  if (publisher) return publisher;
  if (!process.env.REDIS_URL) return null;  // no-op when Redis not configured
  publisher = new Redis(process.env.REDIS_URL, {
    maxRetriesPerRequest: 1,
    enableOfflineQueue: false,
    retryStrategy: function(times) {
      if (times > 3) return null;
      return Math.min(times * 200, 2000);
    }
  });
  publisher.on('error', function(err) {
    logger.warn('[sse-emitter] Redis publisher error (falling back to local-only):', err.message);
  });
  publisher.on('end', function() {
    logger.warn('[sse-emitter] Redis publisher connection ended; will recreate on next use');
    publisher = null;
  });
  return publisher;
}

function addClient(userId, res) {
  if (!clients[userId]) clients[userId] = new Set();
  clients[userId].add(res);

  // Subscribe to this user's channel if this is the first local client
  if (clients[userId].size === 1) {
    try {
      var subP = getSubscriber().subscribe(CHANNEL_PREFIX + userId);
      if (subP && typeof subP.catch === 'function') {
        subP.catch(function(e) {
          logger.warn('[sse-emitter] subscribe failed for', userId + ':', e.message);
        });
      }
    } catch (e) { /* Redis unavailable — local-only mode */ }
  }

  res.on('close', function() {
    if (clients[userId]) {
      clients[userId].delete(res);
      if (clients[userId].size === 0) {
        delete clients[userId];
        try {
          var unsubP = getSubscriber().unsubscribe(CHANNEL_PREFIX + userId);
          if (unsubP && typeof unsubP.catch === 'function') {
            unsubP.catch(function(e) {
              logger.warn('[sse-emitter] unsubscribe failed:', e.message);
            });
          }
        } catch (e) { /* ignore */ }
      }
    }
  });
}

function emit(userId, event, data) {
  var payload = 'event: ' + event + '\n';
  payload += 'data: ' + JSON.stringify(data || {}) + '\n\n';

  // Publish to Redis — all instances receive it (including this one via subscriber)
  var pub = getPublisher();
  if (pub && pub.status === 'ready') {
    pub.publish(CHANNEL_PREFIX + userId, payload).catch(function(err) {
      logger.warn('[sse-emitter] publish failed, falling back to local:', err.message);
      _emitLocal(userId, payload);
    });
  } else {
    // Redis unavailable — direct local emit
    _emitLocal(userId, payload);
  }
}

function _emitLocal(userId, payload) {
  var subs = clients[userId];
  if (!subs || subs.size === 0) return;
  subs.forEach(function(res) {
    try { res.write(payload); }
    catch (e) { subs.delete(res); }
  });
}

function clientCount(userId) {
  return clients[userId] ? clients[userId].size : 0;
}

function getStats() {
  var total = 0;
  Object.keys(clients).forEach(function(userId) {
    total += clients[userId].size;
  });
  return { activeConnections: total };
}

module.exports = { addClient, emit, clientCount, getStats };

/**
 * Per-user lock backed by the database.
 *
 * Gates all scheduling-relevant writers: the scheduler, cal-sync,
 * and (via task-write-queue) user/MCP task mutations. Only one of
 * these can modify scheduling-relevant task fields at a time.
 *
 * Uses INSERT with duplicate-key rejection so the first writer wins
 * atomically. All time comparisons use MySQL NOW() to avoid timezone
 * mismatches between JS Date and the dateStrings knex config.
 *
 * Safety cap: heartbeat stops after MAX_LOCK_AGE so a stuck handler
 * can't hold the lock forever.
 */

var crypto = require('crypto');
var db = require('../db');

var LOCK_TTL_SECONDS = 30;           // short TTL — heartbeat keeps it alive
var REFRESH_TTL_SECONDS = 30;        // each heartbeat extends by 30s
var SWEEP_INTERVAL = 15 * 1000;      // sweep expired locks every 15s
var MAX_LOCK_AGE = 5 * 60 * 1000;    // stop heartbeat after 5 min

// ── core primitives ────────────────────────────────────────────────

async function acquireLock(userId) {
  var token = crypto.randomUUID();

  // Clear expired lock using MySQL's own clock — no JS Date timezone issues.
  // Kept (not deferred to the background sweep) because the sweep interval
  // (15s) plus the TTL window leaves up to ~45s where an expired-but-unswept
  // lock would spuriously reject new acquirers.
  //
  // No transaction wrapper: the DELETE + INSERT don't need atomicity. If
  // another process inserts between our DELETE and INSERT, our INSERT trips
  // ER_DUP_ENTRY and we correctly return not-acquired. Dropping BEGIN/COMMIT
  // saves two round-trips per lock acquisition.
  await db.raw(
    'DELETE FROM sync_locks WHERE user_id = ? AND expires_at <= NOW()',
    [userId]
  );

  try {
    await db.raw(
      'INSERT INTO sync_locks (user_id, lock_token, acquired_at, expires_at) VALUES (?, ?, NOW(), DATE_ADD(NOW(), INTERVAL ? SECOND))',
      [userId, token, LOCK_TTL_SECONDS]
    );
    return { acquired: true, token: token };
  } catch (err) {
    if (err.code === 'ER_DUP_ENTRY') {
      return { acquired: false };
    }
    throw err;
  }
}

async function releaseLock(userId, token) {
  await db('sync_locks')
    .where('user_id', userId)
    .where('lock_token', token)
    .del();
}

async function refreshLock(userId, token) {
  var updated = await db.raw(
    'UPDATE sync_locks SET expires_at = DATE_ADD(NOW(), INTERVAL ? SECOND) WHERE user_id = ? AND lock_token = ?',
    [REFRESH_TTL_SECONDS, userId, token]
  );
  return (updated[0].affectedRows || 0) > 0;
}

/**
 * Fast non-blocking check: is the lock currently held for this user?
 * PK lookup on a single-row table — sub-millisecond.
 */
async function isLocked(userId) {
  var row = await db.raw(
    'SELECT 1 FROM sync_locks WHERE user_id = ? AND expires_at > NOW() LIMIT 1',
    [userId]
  );
  return (row[0] && row[0].length > 0);
}

// ── middleware / wrappers ──────────────────────────────────────────

function withSyncLock(handler) {
  return async function(req, res) {
    var userId = req.user.id;
    var result = await acquireLock(userId);
    if (!result.acquired) {
      return res.status(409).json({ error: 'Sync already in progress', retryAfter: LOCK_TTL_SECONDS });
    }
    var token = result.token;
    var lockStart = Date.now();
    var lockLost = false;
    var heartbeat = setInterval(function() {
      if (Date.now() - lockStart > MAX_LOCK_AGE) {
        clearInterval(heartbeat);
        lockLost = true;
        logger.warn('[sync-lock] Heartbeat stopped — lock held over ' + Math.round(MAX_LOCK_AGE / 1000) + 's, allowing expiry');
        return;
      }
      refreshLock(userId, token).then(function(ok) {
        if (!ok) {
          lockLost = true;
          clearInterval(heartbeat);
          logger.warn('[sync-lock] Lock lost — refresh returned 0 rows (expired or stolen)');
        }
      }).catch(function(err) {
        lockLost = true;
        clearInterval(heartbeat);
        logger.error('[sync-lock] Lock refresh failed:', err.message);
      });
    }, 10 * 1000);
    req.syncLock = {
      token: token,
      get lost() { return lockLost; },
      refresh: function() { return refreshLock(userId, token); },
    };
    try {
      await handler(req, res);
    } finally {
      clearInterval(heartbeat);
      await releaseLock(userId, token);
    }
  };
}

async function withLock(userId, fn, opts) {
  var result = await acquireLock(userId);
  if (!result.acquired) return null;
  var token = result.token;
  var lockStart = Date.now();
  var lockLost = false;
  var heartbeat = setInterval(function() {
    if (Date.now() - lockStart > MAX_LOCK_AGE) {
      clearInterval(heartbeat);
      lockLost = true;
      return;
    }
    refreshLock(userId, token).then(function(ok) {
      if (!ok) {
        lockLost = true;
        clearInterval(heartbeat);
        logger.warn('[sync-lock] Lock lost in withLock — refresh returned 0 rows');
      }
    }).catch(function(err) {
      lockLost = true;
      clearInterval(heartbeat);
      logger.error('[sync-lock] Lock refresh failed in withLock:', err.message);
    });
  }, 10 * 1000);
  try {
    return await fn({
      get lost() { return lockLost; },
      refresh: function() { return refreshLock(userId, token); },
    });
  } finally {
    clearInterval(heartbeat);
    // Flush pending task writes BEFORE releasing the lock so the scheduler
    // can't grab the lock between release and flush.
    if (!opts || opts.flushOnRelease !== false) {
      try {
        var twq = require('./task-write-queue');
        await twq.flushQueueInLock(userId);
      } catch (err) {
        logger.error('[sync-lock] pre-release flush error:', err.message);
      }
    }
    await releaseLock(userId, token);
  }
}

// ── background sweep using MySQL clock ─────────────────────────────
// Disabled in test environment — integration tests manage their own DB state

var sweepTimer;
if (process.env.NODE_ENV !== 'test') {
  sweepTimer = setInterval(function() {
    db.raw('DELETE FROM sync_locks WHERE expires_at <= NOW()')
      .then(function(result) {
        var count = result[0].affectedRows || 0;
        if (count > 0) logger.warn('[sync-lock] Swept ' + count + ' expired lock(s)');
      })
      .catch(function(err) {
        logger.error('[sync-lock] Sweep error:', err.message);
      });
  }, SWEEP_INTERVAL);
  sweepTimer.unref();
}

module.exports = { withSyncLock, withLock, acquireLock, releaseLock, refreshLock, isLocked };

/**
 * task-write-queue.js — Durable queue for scheduling-relevant task writes.
 *
 * When the per-user lock is held (scheduler or cal-sync running), mutation
 * endpoints queue scheduling-relevant field changes here instead of writing
 * directly to the tasks table. Non-scheduling fields (text, notes, project)
 * always write directly.
 *
 * The queue flushes when the lock releases: entries are coalesced per task,
 * applied in a single transaction, and a schedule run is enqueued.
 */

var db = require('../db');
var { createLogger } = require('@resume-optimizer/lib-logger');
var logger = createLogger('task-write-queue');
var tasksWrite = require('./tasks-write');

// Lazy require to avoid circular dependency
var _acquireLock, _releaseLock, _refreshLock;
function getAcquireLock() {
  if (!_acquireLock) _acquireLock = require('./sync-lock').acquireLock;
  return _acquireLock;
}
function getReleaseLock() {
  if (!_releaseLock) _releaseLock = require('./sync-lock').releaseLock;
  return _releaseLock;
}
function getRefreshLock() {
  if (!_refreshLock) _refreshLock = require('./sync-lock').refreshLock;
  return _refreshLock;
}

var _enqueueScheduleRun;
function getEnqueueScheduleRun() {
  if (!_enqueueScheduleRun) _enqueueScheduleRun = require('../scheduler/scheduleQueue').enqueueScheduleRun;
  return _enqueueScheduleRun;
}

var _sseEmitter;
function getSseEmitter() {
  if (!_sseEmitter) _sseEmitter = require('./sse-emitter');
  return _sseEmitter;
}

var _cache;
function getCache() {
  if (!_cache) _cache = require('./redis');
  return _cache;
}

// ── Field classification ─────────────────────────────────────────────
// Non-scheduling fields: safe to write while lock is held.
// Everything else is considered scheduling-relevant (conservative default).
var NON_SCHEDULING_FIELDS = new Set([
  'text', 'notes', 'project', 'section',
  'gcal_event_id', 'msft_event_id',
  'tz', 'updated_at'
]);

/**
 * Split a DB row fragment into scheduling and non-scheduling fields.
 * Any field NOT in NON_SCHEDULING_FIELDS is classified as scheduling.
 */
function splitFields(row) {
  var scheduling = {};
  var nonScheduling = {};
  Object.keys(row).forEach(function(k) {
    if (NON_SCHEDULING_FIELDS.has(k)) {
      nonScheduling[k] = row[k];
    } else {
      scheduling[k] = row[k];
    }
  });
  return { schedulingFields: scheduling, nonSchedulingFields: nonScheduling };
}

// ── Lock check ───────────────────────────────────────────────────────

/**
 * Fast check: is the per-user lock currently held?
 * PK lookup on a single-row table — sub-millisecond.
 */
async function isLocked(userId) {
  var row = await db.raw(
    'SELECT 1 FROM sync_locks WHERE user_id = ? AND expires_at > NOW() LIMIT 1',
    [userId]
  );
  return (row[0] && row[0].length > 0);
}

// ── Queue operations ─────────────────────────────────────────────────

/**
 * Insert a pending write into the queue.
 * `fields` is a pre-converted DB row fragment (output of taskToRow with
 * user_id/created_at stripped). All timezone conversion and template
 * routing must happen BEFORE calling this.
 */
async function enqueueWrite(userId, taskId, operation, fields, source) {
  await db('task_write_queue').insert({
    user_id: userId,
    task_id: taskId,
    operation: operation,
    fields: JSON.stringify(fields),
    source: source || 'unknown'
  });
  logger.info('[WRITE-QUEUE] enqueued ' + operation + ' for task ' + taskId + ' user ' + userId + ' source=' + (source || 'unknown'));
}

// ── Coalescing ───────────────────────────────────────────────────────

async function hasQueuedWrites(userId) {
  var result = await db('task_write_queue')
    .where('user_id', userId)
    .count('id as cnt')
    .first();
  return result && parseInt(result.cnt, 10) > 0;
}

/**
 * Coalesce queue entries into a minimal set of DB operations.
 * Input: array of { id, task_id, operation, fields } ordered by created_at ASC.
 * Output: array of { taskId, operation, fields } ready to execute.
 */
function coalesceEntries(entries) {
  // Group by task_id, preserving order within each group
  var groups = {};
  var order = [];
  entries.forEach(function(e) {
    if (!groups[e.task_id]) {
      groups[e.task_id] = [];
      order.push(e.task_id);
    }
    groups[e.task_id].push(e);
  });

  var results = [];
  order.forEach(function(taskId) {
    var ops = groups[taskId];
    var finalOp = null;
    var mergedFields = {};

    for (var i = 0; i < ops.length; i++) {
      var op = ops[i];
      var fields = typeof op.fields === 'string' ? JSON.parse(op.fields) : op.fields;

      if (op.operation === 'delete') {
        // Delete cancels any prior create; otherwise delete wins
        if (finalOp === 'create') {
          finalOp = null; // create + delete = no-op
          mergedFields = {};
        } else {
          finalOp = 'delete';
          mergedFields = fields; // may contain { cascade: 'recurring' }
        }
      } else if (op.operation === 'create') {
        finalOp = 'create';
        mergedFields = fields;
      } else {
        // update — merge into whatever we have
        if (finalOp === null) finalOp = 'update';
        Object.assign(mergedFields, fields);
      }
    }

    if (finalOp !== null) {
      results.push({ taskId: taskId, operation: finalOp, fields: mergedFields });
    }
  });

  return results;
}

// ── Flush (with lock acquisition) ────────────────────────────────────

/**
 * Flush all pending writes for a user. Acquires the lock first.
 * Returns true if flushed, false if lock couldn't be acquired.
 */
async function flushQueue(userId) {
  // Quick check: anything to flush?
  var pending = await hasQueuedWrites(userId);
  if (!pending) return true;

  var lockResult = await getAcquireLock()(userId);
  if (!lockResult.acquired) return false;

  var token = lockResult.token;
  var lockStart = Date.now();
  var heartbeat = setInterval(function() {
    if (Date.now() - lockStart > 60000) { clearInterval(heartbeat); return; }
    getRefreshLock()(userId, token).catch(function() {});
  }, 10000);

  try {
    await _doFlush(userId);
  } finally {
    clearInterval(heartbeat);
    await getReleaseLock()(userId, token);
  }
  return true;
}

/**
 * Flush all pending writes for a user. Caller already holds the lock.
 * Used by scheduler and cal-sync inside their lock callbacks.
 */
async function flushQueueInLock(userId) {
  return _doFlush(userId);
}

/**
 * Internal flush implementation. Reads queue, coalesces, applies, cleans up.
 */
async function _doFlush(userId) {
  var entries = await db('task_write_queue')
    .where('user_id', userId)
    .orderBy('created_at', 'asc')
    .select('id', 'task_id', 'operation', 'fields', 'source');

  if (entries.length === 0) return;

  var entryIds = entries.map(function(e) { return e.id; });
  var coalesced = coalesceEntries(entries);
  var affectedIds = [];

  logger.info('[WRITE-QUEUE] flushing ' + entries.length + ' entries → ' + coalesced.length + ' ops for user ' + userId);

  await db.transaction(async function(trx) {
    for (var i = 0; i < coalesced.length; i++) {
      var op = coalesced[i];
      var fields = op.fields;
      // Fields came out of JSON, so datetime columns are ISO strings. MySQL
      // rejects those literally; rehydrate to Date so the driver formats them.
      var DATETIME_FIELDS = ['scheduled_at', 'desired_at', 'deadline', 'start_after_at', 'disabled_at', 'recur_start', 'recur_end'];
      for (var dfi = 0; dfi < DATETIME_FIELDS.length; dfi++) {
        var f = DATETIME_FIELDS[dfi];
        if (fields && typeof fields[f] === 'string' && fields[f].length > 0) {
          var parsed = new Date(fields[f]);
          if (!isNaN(parsed.getTime())) fields[f] = parsed;
        }
      }

      if (op.operation === 'create') {
        fields.created_at = db.fn.now();
        fields.updated_at = db.fn.now();
        await tasksWrite.insertTask(trx, fields);
        affectedIds.push(op.taskId);

      } else if (op.operation === 'update') {
        fields.updated_at = db.fn.now();
        await tasksWrite.updateTaskById(trx, op.taskId, fields, userId);
        affectedIds.push(op.taskId);

      } else if (op.operation === 'delete') {
        var cascade = fields && fields.cascade;
        if (cascade === 'recurring') {
          // Delete template + pending instances
          var task = await trx('tasks_v').where({ id: op.taskId, user_id: userId }).first();
          if (task) {
            var templateId = task.source_id || op.taskId;
            // Delete pending instances + the template master (FK SET NULL preserves completed)
            await tasksWrite.deleteInstancesWhere(trx, userId, function(q) {
              return q.where({ master_id: templateId, status: '' });
            });
            await tasksWrite.deleteTaskById(trx, templateId, userId);
            affectedIds.push(templateId);
          }
        } else {
          await tasksWrite.deleteTaskById(trx, op.taskId, userId);
          affectedIds.push(op.taskId);
        }
      }
    }

    // Delete processed queue entries (by id, not user_id — new entries may have arrived)
    await trx('task_write_queue').whereIn('id', entryIds).del();
  });

  // Post-flush: invalidate cache, notify frontend, trigger schedule run
  if (affectedIds.length > 0) {
    getCache().invalidateTasks(userId).catch(function(err) {
      logger.error('[WRITE-QUEUE] cache invalidation error:', err.message);
    });
    // If any flushed id belongs to a recurring template or one of its
    // instances, broadcast a refresh for every sibling so the frontend
    // doesn't keep stale rows cached. Lazy require to avoid a circular
    // dependency with task.controller.
    var broadcastIds = affectedIds;
    try {
      var expand = require('../controllers/task.controller').expandToAllInstanceIds;
      if (typeof expand === 'function') broadcastIds = await expand(userId, affectedIds);
    } catch (e) { /* fall back to affectedIds */ }
    var payload = { source: 'write-queue-flush', timestamp: Date.now() };
    payload.ids = broadcastIds;
    getSseEmitter().emit(userId, 'tasks:changed', payload);
    getEnqueueScheduleRun()(userId, 'write-queue-flush');
  }
}

module.exports = {
  isLocked: isLocked,
  enqueueWrite: enqueueWrite,
  flushQueue: flushQueue,
  flushQueueInLock: flushQueueInLock,
  splitFields: splitFields,
  NON_SCHEDULING_FIELDS: NON_SCHEDULING_FIELDS
};

/**
 * Write-path for the master/instance task model. All application code
 * mutating tasks goes through this module.
 *
 * Row-shape contract:
 *   The `row` / `changes` object uses the same column names the former
 *   `tasks` table exposed (what `taskToRow()` in task.controller produces).
 *   This module routes those fields to master vs instance internally.
 *
 * Identity rules:
 *   - task_type = 'recurring_template' OR (recurring=1 AND task_type != 'recurring_instance')
 *       -> master row only. master.id = row.id. No instance.
 *   - task_type = 'recurring_instance'
 *       -> instance row only. instance.id = row.id. master_id = row.source_id.
 *          occurrence_ordinal = MAX(occurrence_ordinal for that master) + 1.
 *   - everything else ('task', '', null, 'generated')
 *       -> master + instance (both share row.id). ordinal (1, 1, 1).
 */

var { PLACEMENT_MODES } = require('./placementModes');

var MASTER_FIELDS = [
  'id', 'user_id', 'text', 'project', 'section', 'notes', 'url',
  'dur', 'pri',
  'desired_at', 'deadline', 'start_after_at',
  'when', 'day_req', 'time_flex', 'flex_when', 'placement_mode',
  'preferred_time_mins', 'tz',
  'recurring', 'recur', 'recur_start', 'recur_end',
  'split', 'split_min',
  'depends_on', 'location', 'tools', 'travel_before', 'travel_after',
  'disabled_at', 'disabled_reason',
  'weather_precip', 'weather_cloud', 'weather_temp_min', 'weather_temp_max',
  'weather_temp_unit', 'weather_humidity_min', 'weather_humidity_max',
  // status lives on BOTH master and instance: master.status carries
  // template-level lifecycle ('pause'); instance.status carries per-occurrence
  // state (done/wip/skip/''). insertTask + updateTaskById write both so the
  // value is visible regardless of which row class the consumer reads.
  'status',
  'created_at', 'updated_at'
];

// Fields that live on task_instances. `dur` lives on both — copied from
// master at insert, can be overridden per-chunk once splits are real rows.
var INSTANCE_FIELDS = [
  'id', 'master_id', 'user_id',
  'occurrence_ordinal', 'split_ordinal', 'split_total',
  'scheduled_at', 'dur',
  'status', 'time_remaining', 'unscheduled', 'overdue', 'generated',
  'created_at', 'updated_at'
];

// Fields in the `tasks`-shape row that update MASTER only (template fields).
var MASTER_UPDATE_FIELDS = [
  'text', 'project', 'section', 'notes', 'url', 'dur', 'pri',
  'desired_at', 'deadline', 'start_after_at',
  'when', 'day_req', 'time_flex', 'flex_when', 'placement_mode',
  'preferred_time_mins', 'tz',
  'recurring', 'recur', 'recur_start', 'recur_end',
  'split', 'split_min',
  'depends_on', 'location', 'tools', 'travel_before', 'travel_after',
  'disabled_at', 'disabled_reason',
  'weather_precip', 'weather_cloud', 'weather_temp_min', 'weather_temp_max',
  'weather_temp_unit', 'weather_humidity_min', 'weather_humidity_max',
  // status: also a master-level field (template lifecycle); see MASTER_FIELDS comment
  'status'
];

// Fields in the `tasks`-shape row that update INSTANCE only (placement fields).
var INSTANCE_UPDATE_FIELDS = [
  'scheduled_at', 'dur',
  'date', 'day', 'time',
  'status', 'time_remaining', 'unscheduled', 'overdue', 'generated',
  'split_group',
  // juggler-cal-history Plan A/C: completed_at column on task_instances.
  'completed_at'
];

function isTemplate(row) {
  if (!row) return false;
  if (row.task_type === 'recurring_template') return true;
  if (row.recurring && row.task_type !== 'recurring_instance') return true;
  return false;
}

function isInstance(row) {
  return row && row.task_type === 'recurring_instance';
}

function pickMaster(row, id) {
  var out = {};
  MASTER_FIELDS.forEach(function(f) {
    if (row[f] !== undefined) out[f] = row[f];
  });
  out.id = id;
  // Apply trigger-style defaults
  if (out.dur == null) out.dur = 30;
  if (!out.pri) out.pri = 'P3';
  if (out.status == null) out.status = '';
  out.flex_when = out.flex_when ? 1 : 0;
  out.recurring = out.recurring ? 1 : 0;
  return out;
}

function pickInstance(row, id, masterId, occOrdinal) {
  var out = {
    id: id,
    master_id: masterId,
    user_id: row.user_id,
    occurrence_ordinal: occOrdinal,
    split_ordinal: row.split_ordinal != null ? row.split_ordinal : 1,
    split_total: row.split_total != null ? row.split_total : 1,
    scheduled_at: row.scheduled_at || null,
    dur: row.dur != null ? row.dur : 30,
    status: row.status != null ? row.status : '',
    time_remaining: row.time_remaining != null ? row.time_remaining : null,
    unscheduled: row.unscheduled != null ? row.unscheduled : null,
    overdue: row.overdue != null ? row.overdue : 0,
    generated: row.generated ? 1 : 0
  };
  // Derived local-tz caches — written by the scheduler when placing chunks
  if (row.date !== undefined) out.date = row.date;
  if (row.day !== undefined) out.day = row.day;
  if (row.time !== undefined) out.time = row.time;
  if (row.split_group !== undefined) out.split_group = row.split_group;
  if (row.created_at !== undefined) out.created_at = row.created_at;
  if (row.updated_at !== undefined) out.updated_at = row.updated_at;
  return out;
}

function splitUpdateFields(changes) {
  var master = {};
  var instance = {};
  Object.keys(changes).forEach(function(k) {
    if (MASTER_UPDATE_FIELDS.indexOf(k) >= 0) master[k] = changes[k];
    if (INSTANCE_UPDATE_FIELDS.indexOf(k) >= 0) instance[k] = changes[k];
  });
  // updated_at and user_id mirror to both if present
  if (changes.updated_at !== undefined) {
    master.updated_at = changes.updated_at;
    instance.updated_at = changes.updated_at;
  }
  return { master: master, instance: instance };
}

/**
 * INSERT a task. `row` uses the legacy tasks column shape (what taskToRow
 * produces). Classification:
 *   - recurring_template (or legacy recurring=1 non-instance) -> master only
 *   - recurring_instance -> instance only (master_id = source_id, ordinal = MAX+1)
 *   - everything else -> master + instance (both share row.id)
 */
async function insertTask(dbOrTrx, row) {
  if (isTemplate(row)) {
    var masterRow = pickMaster(row, row.id);
    // Guarantee recurring=1 — templates must be visible in tasks_v WHERE recurring=1.
    // A task classified as template via task_type='recurring_template' alone (without
    // recurring:true in the body) would get recurring=0 from pickMaster and disappear
    // from the view, causing fetchTaskWithEventIds to return null.
    masterRow.recurring = 1;
    await dbOrTrx('task_masters').insert(masterRow);
    return;
  }
  if (isInstance(row)) {
    if (!row.source_id) {
      throw new Error('recurring_instance insert requires source_id');
    }
    var existing = await dbOrTrx('task_instances')
      .where('master_id', row.source_id)
      .max('occurrence_ordinal as max')
      .first();
    var nextOrd = (existing && existing.max ? Number(existing.max) : 0) + 1;
    await dbOrTrx('task_instances').insert(
      pickInstance(row, row.id, row.source_id, nextOrd)
    );
    return;
  }
  // Non-recurring: master + instance share row.id
  await dbOrTrx('task_masters').insert(pickMaster(row, row.id));
  await dbOrTrx('task_instances').insert(pickInstance(row, row.id, row.id, 1));
}

/**
 * UPDATE a task by id. `changes` uses the legacy tasks column shape; fields
 * are routed to master or instance based on which table owns them.
 * Pass `userId` for tenancy safety.
 *
 * Returns { masterUpdated, instanceUpdated } — row counts per table.
 */
async function updateTaskById(dbOrTrx, id, changes, userId) {
  var split = splitUpdateFields(changes);
  var masterUpdated = 0;
  var instanceUpdated = 0;
  var mWhere = { id: id };
  var iWhere = { id: id };
  if (userId) { mWhere.user_id = userId; iWhere.user_id = userId; }

  if (Object.keys(split.master).length > 0) {
    masterUpdated = await dbOrTrx('task_masters').where(mWhere).update(split.master);
  }
  if (Object.keys(split.instance).length > 0) {
    instanceUpdated = await dbOrTrx('task_instances').where(iWhere).update(split.instance);
  }
  return { masterUpdated: masterUpdated, instanceUpdated: instanceUpdated };
}

/**
 * DELETE a task by id (and optionally user_id for tenancy safety).
 * Works for masters, instances, or shared-id rows: deletes from both tables.
 * Master deletion cascades via FK to any instances sharing master_id.
 */
async function deleteTaskById(dbOrTrx, id, userId) {
  var instWhere = { id: id };
  if (userId) instWhere.user_id = userId;
  var instDeleted = await dbOrTrx('task_instances').where(instWhere).del();

  var masterWhere = { id: id };
  if (userId) masterWhere.user_id = userId;
  var masterDeleted = await dbOrTrx('task_masters').where(masterWhere).del();

  return { instanceDeleted: instDeleted, masterDeleted: masterDeleted };
}

/**
 * Batch INSERT for many tasks in one call. Replaces the per-row MAX(ordinal)+1
 * pattern with one MAX query per recurring source_id and one bulk INSERT per table.
 *
 * Accepts the same row shape as insertTask. Internally classifies each row as
 * template / recurring_instance / non-recurring and writes them in three batches:
 *   1. master rows (templates + non-recurring) into task_masters.
 *   2. instance rows for non-recurring (master_id = id, ordinal 1) into task_instances.
 *   3. instance rows for recurring_instance, with ordinals assigned per master_id
 *      after a single MAX-per-master lookup.
 *
 * Critical for scheduler hot path (recurring expansion of ~56 instances per template).
 */
async function insertTasksBatch(dbOrTrx, rows) {
  if (!rows || rows.length === 0) return;

  var masterRows = [];
  var instanceRowsNonRecurring = [];
  var recurringInstanceInputs = [];

  rows.forEach(function(row) {
    if (isTemplate(row)) {
      masterRows.push(pickMaster(row, row.id));
    } else if (isInstance(row)) {
      if (!row.source_id) {
        throw new Error('insertTasksBatch: recurring_instance row requires source_id (id=' + row.id + ')');
      }
      recurringInstanceInputs.push(row);
    } else {
      // Non-recurring: shared id pair
      masterRows.push(pickMaster(row, row.id));
      instanceRowsNonRecurring.push(pickInstance(row, row.id, row.id, 1));
    }
  });

  // Look up MAX(occurrence_ordinal) per distinct source_id, in one query.
  var sourceIds = recurringInstanceInputs
    .map(function(r) { return r.source_id; })
    .filter(function(v, i, arr) { return arr.indexOf(v) === i; });

  var maxByMaster = {};
  if (sourceIds.length > 0) {
    var rowsAgg = await dbOrTrx('task_instances')
      .whereIn('master_id', sourceIds)
      .select('master_id')
      .max('occurrence_ordinal as max_ord')
      .groupBy('master_id');
    rowsAgg.forEach(function(r) { maxByMaster[r.master_id] = Number(r.max_ord) || 0; });
  }
  // Source ids with zero existing instances (no row in the aggregate) start at 0.

  // Assign per-source incrementing ordinals while preserving input order.
  // Caller may supply r.occurrence_ordinal explicitly (used when inserting
  // multiple split chunks that must share one ordinal per occurrence).
  var nextByMaster = {};
  var recurringInstanceRows = recurringInstanceInputs.map(function(r) {
    var sid = r.source_id;
    var ord;
    if (r.occurrence_ordinal != null) {
      ord = r.occurrence_ordinal;
    } else {
      if (nextByMaster[sid] === undefined) nextByMaster[sid] = (maxByMaster[sid] || 0);
      nextByMaster[sid] += 1;
      ord = nextByMaster[sid];
    }
    return pickInstance(r, r.id, sid, ord);
  });

  if (masterRows.length > 0) {
    await dbOrTrx('task_masters').insert(masterRows);
  }
  var allInstanceRows = instanceRowsNonRecurring.concat(recurringInstanceRows);
  if (allInstanceRows.length > 0) {
    await dbOrTrx('task_instances').insert(allInstanceRows);
  }
}

/**
 * Per-user "__archived__" master used to host completed instances of
 * a deleted recurring template. Creates the archival master lazily on first
 * use. Returns its id.
 *
 * Why: prior to this, the FK ON DELETE SET NULL would orphan completed
 * instances with master_id=NULL, and the view's LEFT JOIN would return
 * NULL for text/pri/project — a poor user experience. Re-parenting to an
 * archival master gives those rows consistent non-null fields.
 */
var ARCHIVED_TEXT = '[Archived]';
async function getOrCreateArchivedMasterId(dbOrTrx, userId) {
  requireUserId(userId, 'getOrCreateArchivedMasterId');
  // Convention: archival master id = '__archived__:<userId>'. Idempotent lookup.
  var archivedId = '__archived__:' + userId;
  var existing = await dbOrTrx('task_masters').where('id', archivedId).first();
  if (existing) return archivedId;
  await dbOrTrx('task_masters').insert({
    id: archivedId,
    user_id: userId,
    text: ARCHIVED_TEXT,
    pri: 'P4',
    recurring: 0,
    flex_when: 0, placement_mode: PLACEMENT_MODES.ANYTIME,
    dur: 30,
    created_at: dbOrTrx.fn.now(),
    updated_at: dbOrTrx.fn.now()
  });
  return archivedId;
}

/**
 * Re-parent a list of instance ids to the user's archival master.
 * Assigns new sequential occurrence_ordinals starting after the current
 * MAX so the unique (master_id, occurrence_ordinal, split_ordinal) constraint
 * is preserved.
 */
async function archiveInstances(dbOrTrx, userId, instanceIds) {
  requireUserId(userId, 'archiveInstances');
  if (!instanceIds || instanceIds.length === 0) return 0;
  var archivedId = await getOrCreateArchivedMasterId(dbOrTrx, userId);
  var maxRow = await dbOrTrx('task_instances')
    .where('master_id', archivedId)
    .max('occurrence_ordinal as max_ord')
    .first();
  var nextOrd = (maxRow && maxRow.max_ord ? Number(maxRow.max_ord) : 0) + 1;
  // Per-row updates because each gets a unique new ordinal. For 100s of
  // archived rows this is O(N) writes — acceptable for a one-time-per-delete cost.
  for (var i = 0; i < instanceIds.length; i++) {
    await dbOrTrx('task_instances')
      .where({ id: instanceIds[i], user_id: userId })
      .update({
        master_id: archivedId,
        occurrence_ordinal: nextOrd + i,
        updated_at: dbOrTrx.fn.now()
      });
  }
  return instanceIds.length;
}

function requireUserId(userId, fn) {
  if (!userId || typeof userId !== 'string') {
    throw new Error(fn + ': userId is required (tenancy safety). Got: ' + JSON.stringify(userId));
  }
}

/**
 * Bulk UPDATE via a where-builder callback, with field routing.
 * `applyWhere` is applied to the knex builder for BOTH tables on top of
 * an enforced `.where('user_id', userId)` filter the helper adds itself.
 *
 * Signature: updateTasksWhere(dbOrTrx, userId, applyWhere, changes)
 *
 * For updates whose filter references instance-only columns (e.g. `master_id`,
 * `status`), use `updateInstancesWhere` instead.
 */
async function updateTasksWhere(dbOrTrx, userId, applyWhere, changes, opts) {
  requireUserId(userId, 'updateTasksWhere');
  var split = splitUpdateFields(changes);
  var masterUpdated = 0;
  var instanceUpdated = 0;
  // Skip the instance-side update if the only "change" is updated_at —
  // in that case no real instance state changed, and the caller's where
  // filter may reference master-only columns (e.g. `project`) that would
  // error against task_instances.
  var instanceKeys = Object.keys(split.instance);
  var instanceHasRealChange = instanceKeys.some(function(k) { return k !== 'updated_at'; });
  // Same bail-out on the master side. The scheduler's persist path only
  // mutates instance-side columns (scheduled_at / date / time / unscheduled /
  // dur). Its batched UPDATE arrives here with master keys == only
  // updated_at. Running the master UPDATE in that case is a pure round-trip
  // cost — cache-staleness detection already picks up the instance-side
  // updated_at bump via the tasks_v UNION.
  var masterKeys = Object.keys(split.master);
  var masterHasRealChange = masterKeys.some(function(k) { return k !== 'updated_at'; });
  // instanceOnly: skip master writes entirely (used by scheduler to prevent
  // overwriting user-set master.dur with effectiveDuration / time_remaining).
  var instanceOnly = opts && opts.instanceOnly;
  if (masterHasRealChange && !instanceOnly) {
    masterUpdated = await applyWhere(dbOrTrx('task_masters').where('user_id', userId)).update(split.master);
  }
  if (instanceHasRealChange) {
    instanceUpdated = await applyWhere(dbOrTrx('task_instances').where('user_id', userId)).update(split.instance);
  }
  return { masterUpdated: masterUpdated, instanceUpdated: instanceUpdated };
}

/**
 * Bulk DELETE via a where-builder callback. Helper enforces user_id filter.
 *
 * Signature: deleteTasksWhere(dbOrTrx, userId, applyWhere)
 */
async function deleteTasksWhere(dbOrTrx, userId, applyWhere) {
  requireUserId(userId, 'deleteTasksWhere');
  var instanceDeleted = await applyWhere(dbOrTrx('task_instances').where('user_id', userId)).del();
  var masterDeleted = await applyWhere(dbOrTrx('task_masters').where('user_id', userId)).del();
  return { instanceDeleted: instanceDeleted, masterDeleted: masterDeleted };
}

/**
 * Delete only the instance rows matching a filter. Helper enforces user_id.
 *
 * Signature: deleteInstancesWhere(dbOrTrx, userId, applyWhere)
 */
async function deleteInstancesWhere(dbOrTrx, userId, applyWhere) {
  requireUserId(userId, 'deleteInstancesWhere');
  return await applyWhere(dbOrTrx('task_instances').where('user_id', userId)).del();
}

/**
 * Update only the instance rows matching a filter. Helper enforces user_id
 * and applies field routing (only INSTANCE_UPDATE_FIELDS are written).
 *
 * Signature: updateInstancesWhere(dbOrTrx, userId, applyWhere, changes)
 */
async function updateInstancesWhere(dbOrTrx, userId, applyWhere, changes) {
  requireUserId(userId, 'updateInstancesWhere');
  var split = splitUpdateFields(changes);
  if (Object.keys(split.instance).length === 0) return 0;
  return await applyWhere(dbOrTrx('task_instances').where('user_id', userId)).update(split.instance);
}

/**
 * Delete all pending (status='') instances for a recurring template, cleaning
 * the cal_sync_ledger first so the next sync doesn't re-ingest their events.
 * Returns the number of instances deleted.
 */
async function resetRecurringInstances(dbOrTrx, userId, masterId, logTag) {
  requireUserId(userId, 'resetRecurringInstances');
  var pendingIds = await dbOrTrx('task_instances')
    .where({ master_id: masterId, user_id: userId, status: '' })
    .pluck('id');
  if (pendingIds.length === 0) return 0;
  await dbOrTrx('cal_sync_ledger')
    .where('user_id', userId)
    .whereIn('task_id', pendingIds)
    .where('status', 'active')
    .update({ status: 'deleted_local', task_id: null, synced_at: dbOrTrx.fn.now() })
    .catch(function(err) { logger.error('[silent-catch]', err.message); });
  await deleteInstancesWhere(dbOrTrx, userId, function(q) {
    return q.whereIn('id', pendingIds);
  });
  if (logTag) logger.info(logTag + ': deleted ' + pendingIds.length + ' pending instances for ' + masterId);
  return pendingIds.length;
}

/**
 * Re-parent all completed (done/cancel/skip) instances for a recurring template
 * to the archival master. Used when recurring is turned off so history doesn't
 * display as orphaned task-type rows in the main list.
 * Returns the number of instances re-parented.
 */
async function archiveCompletedInstances(dbOrTrx, userId, masterId) {
  requireUserId(userId, 'archiveCompletedInstances');
  var doneIds = await dbOrTrx('task_instances')
    .where({ master_id: masterId, user_id: userId })
    .whereIn('status', ['done', 'cancel', 'skip'])
    .pluck('id');
  if (doneIds.length === 0) return 0;
  return await archiveInstances(dbOrTrx, userId, doneIds);
}

module.exports = {
  insertTask: insertTask,
  insertTasksBatch: insertTasksBatch,
  archiveInstances: archiveInstances,
  archiveCompletedInstances: archiveCompletedInstances,
  resetRecurringInstances: resetRecurringInstances,
  updateTaskById: updateTaskById,
  deleteTaskById: deleteTaskById,
  updateTasksWhere: updateTasksWhere,
  deleteTasksWhere: deleteTasksWhere,
  deleteInstancesWhere: deleteInstancesWhere,
  updateInstancesWhere: updateInstancesWhere,
  // Exposed for tests; not part of the public API surface.
  splitUpdateFields: splitUpdateFields,
  isTemplate: isTemplate,
  isInstance: isInstance
};

/**
 * Usage Reporter — batches usage events and sends to payment service
 *
 * Uses ServiceJWT authentication for service-to-service calls.
 * Falls back to X-Internal-Key if service-auth not initialized.
 */

const { getProductId, PRODUCT_LABEL } = require('../middleware/plan-features.middleware');
const { libUsageReporterLogger } = require('./logger');
const FLUSH_INTERVAL = 30000;
const FLUSH_SIZE = 50;

const buffer = [];
let flushTimer = null;
let _serviceAuthReady = false;

try {
const { initServiceAuth } = require('../../vendor/service-auth');
initServiceAuth({ serviceName: PRODUCT_LABEL }).then(() => {
  _serviceAuthReady = true;
}).catch(err => {
  libUsageReporterLogger.warn('Service auth init failed, using legacy key', { error: err });
});
} catch { /* service-auth not available */ }

function reportUsage({ userId, planId, featureKey, eventType, quantity, inputTokens, outputTokens, endpoint }) {
  buffer.push({
    user_id: userId,
    planId: planId || 'free',
    feature_key: featureKey,
    event_type: eventType || 'used',
    quantity: quantity || 1,
    input_tokens: inputTokens || null,
    output_tokens: outputTokens || null,
    endpoint: endpoint || null,
    timestamp: new Date().toISOString()
  });

  if (buffer.length >= FLUSH_SIZE) {
    flush();
  }
}

async function flush() {
  if (buffer.length === 0) return;

  const events = buffer.splice(0);

  try {
    if (_serviceAuthReady) {
      const { serviceRequest } = require('../../vendor/service-auth');
      await serviceRequest('payment-service', '/api/usage/report', {
        method: 'POST',
        body: { productId: await getProductId() || PRODUCT_LABEL, events }
      });
    } else {
      const PAYMENT_URL = process.env.PAYMENT_SERVICE_URL || 'http://localhost:5020';
      const INTERNAL_KEY = process.env.INTERNAL_SERVICE_KEY;
      if (!INTERNAL_KEY) return;
      await fetch(`${PAYMENT_URL}/api/usage/report`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'X-Internal-Key': INTERNAL_KEY
        },
        body: JSON.stringify({ productId: await getProductId() || PRODUCT_LABEL, events }),
        signal: AbortSignal.timeout(30000)
      });
    }
  } catch (err) {
    libUsageReporterLogger.warn('Failed to flush events', { eventCount: events.length, error: err });
  }
}

if (!flushTimer) {
  flushTimer = setInterval(flush, FLUSH_INTERVAL);
  if (flushTimer.unref) flushTimer.unref();
}

process.on('beforeExit', flush);

module.exports = { reportUsage, flush };

/**
 * MCP Config Tools — expose user config as MCP tools
 */

const { z } = require('zod');
const safeStringify = require('../safeStringify');
const db = require('../../db');
const tasksWrite = require('../../lib/tasks-write');

function registerConfigTools(server, userId) {

  // ── get_config ──
  server.tool(
    'get_config',
    'Get user configuration including locations, tools, projects, time blocks, tool matrix, location schedules, and preferences.',
    {},
    async () => {
      const [locations, tools, projects, configRows] = await Promise.all([
        db('locations').where('user_id', userId).orderBy('sort_order'),
        db('tools').where('user_id', userId).orderBy('sort_order'),
        db('projects').where('user_id', userId).orderBy('sort_order'),
        db('user_config').where('user_id', userId)
      ]);

      const config = {};
      configRows.forEach(row => {
        const val = typeof row.config_value === 'string' ? (function() { try { return JSON.parse(row.config_value); } catch(e) { return row.config_value; } })() : row.config_value;
        config[row.config_key] = val;
      });

      const result = {
        locations: locations.map(l => ({ id: l.location_id, name: l.name, icon: l.icon })),
        tools: tools.map(t => ({ id: t.tool_id, name: t.name, icon: t.icon })),
        projects: projects.map(p => ({ id: p.id, name: p.name, color: p.color, icon: p.icon })),
        toolMatrix: config.tool_matrix || null,
        timeBlocks: config.time_blocks || null,
        locSchedules: config.loc_schedules || null,
        locScheduleDefaults: config.loc_schedule_defaults || null,
        locScheduleOverrides: config.loc_schedule_overrides || null,
        hourLocationOverrides: config.hour_location_overrides || null,
        preferences: config.preferences || null
      };

      return { content: [{ type: 'text', text: safeStringify(result) }] };
    }
  );

  // ── list_projects ──
  server.tool(
    'list_projects',
    'List all projects, optionally filtered by name. Returns project name, color, icon, and task count.',
    {
      name: z.string().optional().describe('Filter by project name (exact match)')
    },
    async ({ name }) => {
      let query = db('projects').where('user_id', userId).orderBy('sort_order');
      if (name) query = query.where('name', name);
      const projects = await query;

      // Get task counts per project
      const projectNames = projects.map(p => p.name);
      const counts = await db('tasks_v')
        .where('user_id', userId)
        .whereIn('project', projectNames)
        .groupBy('project')
        .select('project', db.raw('COUNT(*) as total'), db.raw("SUM(CASE WHEN status = 'done' THEN 1 ELSE 0 END) as done"));

      const countMap = {};
      counts.forEach(c => { countMap[c.project] = { total: c.total, done: c.done }; });

      const result = projects.map(p => ({
        id: p.id,
        name: p.name,
        color: p.color,
        icon: p.icon,
        taskCount: countMap[p.name]?.total || 0,
        doneCount: countMap[p.name]?.done || 0
      }));

      return { content: [{ type: 'text', text: safeStringify(result) }] };
    }
  );
  // ── create_project ──
  server.tool(
    'create_project',
    'Create a new project with optional color and icon.',
    {
      name: z.string().describe('Project name (must be unique)'),
      color: z.string().optional().describe('Project color (e.g. "#4A90D9")'),
      icon: z.string().optional().describe('Project icon identifier')
    },
    async ({ name, color, icon }) => {
      const maxOrder = await db('projects').where('user_id', userId).max('sort_order as max').first();
      const [id] = await db('projects').insert({
        user_id: userId,
        name,
        color: color || null,
        icon: icon || null,
        sort_order: (maxOrder?.max || 0) + 1
      });

      return { content: [{ type: 'text', text: safeStringify({ id, name, color, icon }) }] };
    }
  );

  // ── update_project ──
  server.tool(
    'update_project',
    'Update a project name, color, or icon. Renaming a project updates all associated tasks.',
    {
      id: z.number().describe('Project ID'),
      name: z.string().optional().describe('New project name'),
      color: z.string().optional().describe('New project color'),
      icon: z.string().optional().describe('New project icon')
    },
    async ({ id, name, color, icon }) => {
      const existing = await db('projects').where({ id, user_id: userId }).first();
      if (!existing) return { content: [{ type: 'text', text: safeStringify({ error: 'Project not found' }) }] };

      const updates = {};
      if (name !== undefined) updates.name = name;
      if (color !== undefined) updates.color = color;
      if (icon !== undefined) updates.icon = icon;
      updates.updated_at = db.fn.now();

      let renamed = null;
      await db.transaction(async (trx) => {
        await trx('projects').where({ id, user_id: userId }).update(updates);
        if (name && existing.name !== name) {
          // Project is a master-level field; helper routes accordingly
          await tasksWrite.updateTasksWhere(trx, userId, function(q) {
            return q.where('project', existing.name);
          }, { project: name, updated_at: db.fn.now() });
          renamed = { from: existing.name, to: name };
        }
      });

      return { content: [{ type: 'text', text: safeStringify({
        project: { id, name: name || existing.name, color: color !== undefined ? color : existing.color, icon: icon !== undefined ? icon : existing.icon },
        renamed
      }) }] };
    }
  );

  // ── delete_project ──
  server.tool(
    'delete_project',
    'Delete a project. Tasks in this project are kept but lose their project association.',
    {
      id: z.number().describe('Project ID to delete')
    },
    async ({ id }) => {
      const existing = await db('projects').where({ id, user_id: userId }).first();
      if (!existing) return { content: [{ type: 'text', text: safeStringify({ error: 'Project not found' }) }] };

      await db('projects').where({ id, user_id: userId }).del();
      return { content: [{ type: 'text', text: safeStringify({ message: 'Project deleted', id, name: existing.name }) }] };
    }
  );

  // ── update_config ──
  server.tool(
    'update_config',
    'Update a user configuration value. Valid keys: time_blocks, preferences, loc_schedules, loc_schedule_defaults, loc_schedule_overrides, hour_location_overrides, tool_matrix.',
    {
      key: z.enum(['time_blocks', 'preferences', 'loc_schedules', 'loc_schedule_defaults', 'loc_schedule_overrides', 'hour_location_overrides', 'tool_matrix']).describe('Configuration key to update'),
      value: z.any().describe('New configuration value (object or array)')
    },
    async ({ key, value }) => {
      const existing = await db('user_config').where({ user_id: userId, config_key: key }).first();

      if (existing) {
        await db('user_config').where({ user_id: userId, config_key: key }).update({
          config_value: JSON.stringify(value),
          updated_at: db.fn.now()
        });
      } else {
        await db('user_config').insert({
          user_id: userId,
          config_key: key,
          config_value: JSON.stringify(value)
        });
      }

      // Trigger reschedule for schedule-affecting keys
      const { enqueueScheduleRun } = require('../../scheduler/scheduleQueue');
      enqueueScheduleRun(userId, 'mcp:config');

      return { content: [{ type: 'text', text: safeStringify({ key, value }) }] };
    }
  );
}

module.exports = { registerConfigTools };

/**
 * MCP Data & Calendar Tools — export/import and calendar sync
 */

const { z } = require('zod');
const safeStringify = require('../safeStringify');
const db = require('../../db');
const { rowToTask } = require('../../controllers/task.controller');

function registerDataTools(server, userId) {

  // Helper: get user timezone
  async function getUserTimezone() {
    var user = await db('users').where('id', userId).select('timezone').first();
    return (user && user.timezone) || 'America/New_York';
  }

  // ── export_data ──
  server.tool(
    'export_data',
    'Export all user data as JSON (tasks, projects, locations, tools, config). Useful for backups.',
    {},
    async () => {
      var tz = await getUserTimezone();

      var { fetchTasksWithEventIds } = require('../../controllers/task.controller');
      var [taskRows, locationRows, toolRows, projectRows, configRows] = await Promise.all([
        fetchTasksWithEventIds(db, userId, function(q) { q.orderBy('created_at', 'asc'); }),
        db('locations').where('user_id', userId).orderBy('sort_order'),
        db('tools').where('user_id', userId).orderBy('sort_order'),
        db('projects').where('user_id', userId).orderBy('sort_order'),
        db('user_config').where('user_id', userId)
      ]);

      var tasks = taskRows.map(function(r) { return rowToTask(r, tz); });
      var config = {};
      configRows.forEach(function(row) {
        config[row.config_key] = typeof row.config_value === 'string'
          ? JSON.parse(row.config_value) : row.config_value;
      });

      var result = {
        tasks: tasks,
        locations: locationRows.map(function(l) { return { id: l.location_id, name: l.name, icon: l.icon }; }),
        tools: toolRows.map(function(t) { return { id: t.tool_id, name: t.name, icon: t.icon }; }),
        projects: projectRows.map(function(p) { return { id: p.id, name: p.name, color: p.color, icon: p.icon }; }),
        config: config,
        exported: new Date().toISOString()
      };

      return { content: [{ type: 'text', text: safeStringify(result) }] };
    }
  );

  // ── get_calendar_status ──
  server.tool(
    'get_calendar_status',
    'Check Google Calendar and Microsoft Calendar connection status, last sync time, and auto-sync settings.',
    {},
    async () => {
      var user = await db('users').where('id', userId).first();

      var gcalConnected = !!(user && user.gcal_refresh_token);
      var gcalLastSynced = (user && user.gcal_last_synced_at) || null;
      var msftConnected = !!(user && user.msft_cal_refresh_token);
      var msftLastSynced = (user && user.msft_cal_last_synced_at) || null;

      var autoSyncRow = await db('user_config')
        .where({ user_id: userId, config_key: 'auto_sync' })
        .first();
      var autoSync = autoSyncRow
        ? (typeof autoSyncRow.config_value === 'string' ? JSON.parse(autoSyncRow.config_value) : autoSyncRow.config_value)
        : null;

      return { content: [{ type: 'text', text: safeStringify({
        googleCalendar: { connected: gcalConnected, lastSyncedAt: gcalLastSynced, autoSync: autoSync },
        microsoftCalendar: { connected: msftConnected, lastSyncedAt: msftLastSynced }
      }) }] };
    }
  );

  // ── sync_calendar ──
  server.tool(
    'sync_calendar',
    'Trigger a calendar sync (push local changes to calendar and pull remote changes). Syncs all connected calendar providers via the unified sync engine.',
    {},
    async () => {
      var user = await db('users').where('id', userId).first();
      if (!user) {
        return { content: [{ type: 'text', text: 'Error: User not found' }], isError: true };
      }

      if (!user.gcal_refresh_token && !user.msft_cal_refresh_token) {
        return { content: [{ type: 'text', text: 'No calendar provider connected. Connect Google or Microsoft Calendar in the app first.' }] };
      }

      try {
        var calSyncController = require('../../controllers/cal-sync.controller');
        var result = await new Promise(function(resolve, reject) {
          var fakeReq = { user: user };
          var fakeRes = {
            json: function(data) { resolve(data); },
            status: function(code) { return { json: function(data) { reject(new Error(data.error || 'Sync failed')); } }; }
          };
          calSyncController.sync(fakeReq, fakeRes);
        });
        return { content: [{ type: 'text', text: safeStringify(result) }] };
      } catch (err) {
        return { content: [{ type: 'text', text: 'Sync error: ' + err.message }], isError: true };
      }
    }
  );
  // ── integrity_check ──
  server.tool(
    'integrity_check',
    'Scan for data integrity issues: orphaned instances, empty text, broken dependencies, impossible constraints, duplicate instances. Returns a report with counts and details.',
    {
      autoFix: z.boolean().optional().describe('If true, auto-fix safe issues (delete orphans, clear broken deps). Default: false (report only).')
    },
    async ({ autoFix }) => {
      var fix = !!autoFix;
      var issues = [];
      var fixed = [];

      // 1. Orphaned instances: source_id points to non-existent master
      var orphaned = await db('task_instances as i')
        .leftJoin('task_masters as m', 'i.master_id', 'm.id')
        .where('i.user_id', userId)
        .whereNull('m.id')
        .select('i.id', 'i.master_id');
      if (orphaned.length > 0) {
        issues.push({ type: 'orphaned_instance', count: orphaned.length, ids: orphaned.map(function(r) { return r.id; }).slice(0, 20) });
        if (fix) {
          await db('task_instances').whereIn('id', orphaned.map(function(r) { return r.id; })).del();
          fixed.push('Deleted ' + orphaned.length + ' orphaned instances');
        }
      }

      // 2. Tasks with empty/null text
      var nameless = await db('task_masters').where('user_id', userId)
        .where(function() { this.whereNull('text').orWhere('text', ''); })
        .select('id');
      if (nameless.length > 0) {
        issues.push({ type: 'empty_text', count: nameless.length, ids: nameless.map(function(r) { return r.id; }).slice(0, 20) });
      }

      // 3. Instances with split_ordinal > split_total
      var badSplit = await db('task_instances').where('user_id', userId)
        .whereRaw('split_ordinal > split_total')
        .select('id', 'split_ordinal', 'split_total');
      if (badSplit.length > 0) {
        issues.push({ type: 'split_ordinal_exceeds_total', count: badSplit.length, ids: badSplit.map(function(r) { return r.id; }).slice(0, 20) });
      }

      // 4. Orphaned calendar_sync rows (task deleted but sync record remains)
      var orphanedSync = await db('calendar_sync as cs')
        .leftJoin('task_instances as i', 'cs.task_id', 'i.id')
        .where('cs.user_id', userId)
        .whereNull('cs.deleted_at')
        .whereNull('i.id')
        .select('cs.id', 'cs.task_id', 'cs.provider');
      if (orphanedSync.length > 0) {
        issues.push({ type: 'orphaned_sync', count: orphanedSync.length, details: orphanedSync.slice(0, 20).map(function(r) { return { syncId: r.id, taskId: r.task_id, provider: r.provider }; }) });
        if (fix) {
          await db('calendar_sync').whereIn('id', orphanedSync.map(function(r) { return r.id; })).update({ deleted_at: db.fn.now() });
          fixed.push('Soft-deleted ' + orphanedSync.length + ' orphaned sync records');
        }
      }

      // 5. Duplicate active instances (same source_id + date with status='')
      var dupes = await db('task_instances').where('user_id', userId)
        .where('status', '')
        .whereNotNull('master_id')
        .whereNotNull('date')
        .groupBy('master_id', 'date')
        .havingRaw('COUNT(*) > 1')
        .select('master_id', 'date', db.raw('COUNT(*) as cnt'));
      if (dupes.length > 0) {
        issues.push({ type: 'duplicate_instances', count: dupes.length, details: dupes.slice(0, 20).map(function(r) { return { masterId: r.master_id, date: r.date, count: r.cnt }; }) });
      }

      // 6. dependsOn referencing non-existent tasks
      var allMasters = await db('task_masters').where('user_id', userId).select('id', 'depends_on');
      var masterIds = new Set(allMasters.map(function(r) { return r.id; }));
      var brokenDeps = [];
      allMasters.forEach(function(r) {
        if (!r.depends_on) return;
        var deps;
        try { deps = typeof r.depends_on === 'string' ? JSON.parse(r.depends_on) : r.depends_on; } catch(e) { return; }
        if (!Array.isArray(deps)) return;
        var broken = deps.filter(function(d) { return !masterIds.has(d); });
        if (broken.length > 0) brokenDeps.push({ taskId: r.id, brokenIds: broken });
      });
      if (brokenDeps.length > 0) {
        issues.push({ type: 'broken_dependencies', count: brokenDeps.length, details: brokenDeps.slice(0, 20) });
        if (fix) {
          for (var bi = 0; bi < brokenDeps.length; bi++) {
            var bd = brokenDeps[bi];
            var master = allMasters.find(function(m) { return m.id === bd.taskId; });
            if (!master) continue;
            var deps2;
            try { deps2 = typeof master.depends_on === 'string' ? JSON.parse(master.depends_on) : master.depends_on; } catch(e) { continue; }
            var cleaned = deps2.filter(function(d) { return masterIds.has(d); });
            await db('task_masters').where('id', bd.taskId).update({ depends_on: JSON.stringify(cleaned), updated_at: db.fn.now() });
          }
          fixed.push('Cleaned broken deps from ' + brokenDeps.length + ' tasks');
        }
      }

      // 7. Orphaned masters: non-recurring masters with no instance row
      var orphanedMasters = await db('task_masters as m')
        .leftJoin('task_instances as i', 'i.master_id', 'm.id')
        .where('m.user_id', userId)
        .where('m.recurring', 0)
        .whereNull('i.id')
        .select('m.id', 'm.text', 'm.status');
      if (orphanedMasters.length > 0) {
        issues.push({ type: 'orphaned_master', count: orphanedMasters.length, details: orphanedMasters.slice(0, 20).map(function(r) { return { id: r.id, text: r.text, status: r.status }; }) });
        if (fix) {
          // Recreate instance rows for orphaned one-off masters
          var insertRows = orphanedMasters.map(function(m) {
            return {
              id: m.id, master_id: m.id, user_id: userId,
              occurrence_ordinal: 1, split_ordinal: 1, split_total: 1,
              dur: 30, status: m.status || '',
              generated: 0, created_at: db.fn.now(), updated_at: db.fn.now()
            };
          });
          for (var oi = 0; oi < insertRows.length; oi += 50) {
            await db('task_instances').insert(insertRows.slice(oi, oi + 50));
          }
          fixed.push('Recreated ' + orphanedMasters.length + ' instance rows for orphaned masters');
        }
      }

      // 8. Impossible constraints: startAfter > deadline
      var impossible = await db('task_masters').where('user_id', userId)
        .whereNotNull('start_after_at')
        .whereNotNull('deadline')
        .whereRaw('start_after_at > deadline')
        .select('id', 'text', 'start_after_at', 'deadline');
      if (impossible.length > 0) {
        issues.push({ type: 'impossible_constraint', count: impossible.length, details: impossible.slice(0, 20).map(function(r) { return { id: r.id, text: r.text, startAfter: r.start_after_at, deadline: r.deadline }; }) });
      }

      return {
        content: [{
          type: 'text',
          text: safeStringify({
            healthy: issues.length === 0,
            issueCount: issues.length,
            issues: issues,
            fixed: fix ? fixed : undefined
          })
        }]
      };
    }
  );
}

