              .where('user_id', userId)
              .whereIn('id', srcIds)
              .select('id', 'gcal_event_id', 'msft_event_id', 'apple_event_id');
            tmplRows.forEach(function(r) { templateById[r.id] = r; });
          }

          for (var i = 0; i < updates.length; i++) {
            var update = updates[i];
            var id = update.id;
            if (!id || !existingById[id]) continue;

            var fields = {};
            Object.keys(update).forEach(function(k) { if (k !== 'id') fields[k] = update[k]; });
            var existing = existingById[id];
            if (fields.placementMode === 'fixed') {
              var _txHasDate = fields.date !== undefined && fields.date !== null && fields.date !== '';
              var _txHasTime = fields.time !== undefined && fields.time !== null && fields.time !== '';
              var _txHasScheduledAt = fields.scheduledAt !== undefined && fields.scheduledAt !== null && fields.scheduledAt !== '';
              if (!_txHasDate && !_txHasTime && !_txHasScheduledAt && !existing.scheduled_at) {
                txErrors.push({ id: id, error: 'Validation error: placementMode "fixed" requires a date, time, or scheduledAt' });
                continue;
              }
            }
            var row = taskToRow(fields, userId, tz, existing);
            delete row.user_id;
            delete row.created_at;
            delete row._pendingTimeOnly;
            // PHASE 19 D-04: batch_update_tasks transaction path — same ALL_DAY backstop as update_task
            var _txTimeWasSet = fields.time !== undefined || fields.scheduledAt !== undefined;
            if (!_txTimeWasSet && fields.date !== undefined && row.placement_mode === undefined) {
              row.placement_mode = PLACEMENT_MODES.ALL_DAY;
            }

            // Guard: don't let calendar-linked fixed tasks lose their 'fixed' tag.
            var _guardOpts = { allowUnfix: !!fields._allowUnfix };
            if (existing.task_type === 'recurring_instance' && existing.source_id && templateById[existing.source_id]) {
              guardFixedCalendarWhen(row, templateById[existing.source_id], _guardOpts);
            }
            guardFixedCalendarWhen(row, existing, _guardOpts);

            var taskType = existing.task_type || 'task';

            if (taskType === 'recurring_instance' && existing.source_id) {
              var templateUpdate = {};
              var instanceUpdate = {};
              Object.keys(row).forEach(function(k) {
                if (k === 'updated_at') return;
                if (TEMPLATE_FIELDS.indexOf(k) >= 0) {
                  templateUpdate[k] = row[k];
                } else {
                  instanceUpdate[k] = row[k];
                }
              });
              if (Object.keys(templateUpdate).length > 0) {
                templateUpdate.updated_at = db.fn.now();
                await tasksWrite.updateTaskById(trx, existing.source_id, templateUpdate, userId);
              }
              if (Object.keys(instanceUpdate).length > 0) {
                instanceUpdate.updated_at = db.fn.now();
                await tasksWrite.updateTaskById(trx, id, instanceUpdate, userId);
              } else {
                await tasksWrite.updateTaskById(trx, id, { updated_at: db.fn.now() }, userId);
              }
            } else {
              await tasksWrite.updateTaskById(trx, id, row, userId);
            }
            updatedCount++;
          }
          if (txErrors.length > 0) {
            throw new Error(txErrors.map(function(e) { return e.id + ': ' + e.error; }).join('; '));
          }
        });
      } catch (err) {
        if (txErrors.length > 0) {
          return { content: [{ type: 'text', text: err.message }], isError: true };
        }
        throw err;
      }

      enqueueScheduleRun(userId, 'mcp:batch_update_tasks', updates.map(function(u) { return u.id; }).filter(Boolean));
      return { content: [{ type: 'text', text: safeStringify({ updated: updatedCount }) }] };
    }
  );
}

module.exports = { registerTaskTools };

/**
 * MCP Transport — Stateless Streamable HTTP handler for Express
 *
 * Each POST /mcp creates a fresh McpServer + transport, authenticated by Bearer JWT.
 * No session tracking needed — works across Cloud Run instances.
 *
 * Authentication delegated to shared mcp-auth module (JWT via JWKS + auto-provisioning).
 */

var StreamableHTTPServerTransport = require('@modelcontextprotocol/sdk/server/streamableHttp.js').StreamableHTTPServerTransport;
var { createMcpServerForUser } = require('./server');
var { authenticateMcpRequest, sendMcpUnauthorized } = require('auth-client/mcp-auth');
var db = require('../db');

var MCP_TIMEOUT = 120000; // 2 minutes max per MCP request
var PUBLIC_URL = process.env.PUBLIC_URL || process.env.MCP_ISSUER_URL || '';
var { APP_ID } = require('../service-identity');

/**
 * Check if user has an active plan for this app.
 * Uses JWT claims first (fast), falls back gracefully if no plan info.
 */
async function planCheck(authResult) {
  var plan = authResult.plans && authResult.plans[APP_ID];
  if (plan) return { hasActivePlan: true, planId: plan };
  return { hasActivePlan: false };
}

/**
 * Extract Bearer token from request.
 */
function extractBearerToken(req) {
  var authHeader = req.headers.authorization;
  if (authHeader && authHeader.startsWith('Bearer ')) {
    return authHeader.substring(7);
  }
  return null;
}

/**
 * POST /mcp — handle MCP request (stateless mode)
 */
async function handlePost(req, res) {
  var server;
  var transport;
  var timeout;

  function cleanup() {
    clearTimeout(timeout);
    if (transport) transport.close().catch(function() {});
    if (server) server.close().catch(function() {});
  }

  try {
    var token = extractBearerToken(req);
    var authResult;

    if (token) {
      if (token === 'dev-token' && (process.env.NODE_ENV === 'development' || process.env.MCP_DEV_NO_AUTH === 'true') && process.env.NODE_ENV !== 'production') {
        authResult = { userId: 'dev-user' };
      } else {
        authResult = await authenticateMcpRequest(token, db, { planCheck: planCheck });
        if (!authResult) {
          return res.status(401).json({
            jsonrpc: '2.0',
            error: { code: -32000, message: 'Invalid or expired token' },
            id: null
          });
        }
      }
    } else if ((process.env.NODE_ENV === 'development' || process.env.MCP_DEV_NO_AUTH === 'true') && process.env.NODE_ENV !== 'production') {
      authResult = { userId: 'dev-user' };
    } else {
      return sendMcpUnauthorized(res, PUBLIC_URL || req.protocol + '://' + req.get('host'));
    }

    server = createMcpServerForUser(authResult.userId);
    transport = new StreamableHTTPServerTransport({
      sessionIdGenerator: undefined // stateless — no session tracking
    });

    // Timeout: kill the request if it takes too long
    timeout = setTimeout(function() {
      logger.warn('[mcp] Request timeout after ' + MCP_TIMEOUT + 'ms');
      cleanup();
      if (!res.headersSent) {
        res.status(504).json({
          jsonrpc: '2.0',
          error: { code: -32000, message: 'Request timed out' },
          id: null
        });
      }
    }, MCP_TIMEOUT);

    await server.connect(transport);
    await transport.handleRequest(req, res, req.body);

    // Clean up after response is sent
    res.on('finish', cleanup);
  } catch (error) {
    cleanup();
    if (!res.headersSent) {
      var status = error.status || 500;
      res.status(status).json({
        jsonrpc: '2.0',
        error: { code: -32000, message: error.message },
        id: null
      });
    }
  }
}

/**
 * GET/DELETE /mcp — not supported in stateless mode
 */
function handleMethodNotAllowed(req, res) {
  res.status(405).json({
    jsonrpc: '2.0',
    error: { code: -32000, message: 'Method not allowed (stateless mode — use POST)' },
    id: null
  });
}

module.exports = { handlePost, handleMethodNotAllowed };

/**
 * Calendar Provider Limit Middleware
 *
 * Checks how many calendar providers are connected and blocks
 * new connections if the user's plan limit is reached.
 * Free: 1 provider, Pro+: unlimited (-1).
 */

const db = require('../db');

function getNestedValue(obj, path) {
  return path.split('.').reduce((o, key) => o?.[key], obj);
}

/**
 * Middleware factory for calendar connection routes.
 * @param {string} provider - 'google' or 'microsoft' — the provider being connected
 */
function checkCalendarLimit(provider) {
  return async (req, res, next) => {
    if (!req.planFeatures) {
      return next(); // No plan features resolved — allow (fail open)
    }

    const limit = getNestedValue(req.planFeatures, 'calendar.max_providers');

    // -1 or undefined = unlimited
    if (limit === -1 || limit === undefined) {
      return next();
    }

    const userId = req.user?.id;
    if (!userId) {
      return next();
    }

    try {
      const user = await db('users').where('id', userId).first();
      if (!user) return next();

      // Count connected providers
      let connectedCount = 0;
      if (user.gcal_access_token) connectedCount++;
      if (user.msft_cal_access_token) connectedCount++;

      // If this provider is already connected, allow reconnect
      if (provider === 'google' && user.gcal_access_token) return next();
      if (provider === 'microsoft' && user.msft_cal_access_token) return next();

      // Check if adding this provider would exceed the limit
      if (connectedCount >= limit) {
        return res.status(403).json({
          error: 'Calendar provider limit reached',
          code: 'CALENDAR_LIMIT_REACHED',
          connected: connectedCount,
          limit,
          current_plan: req.planId || 'free',
          upgrade_required: true,
          message: `Your plan allows ${limit} calendar provider${limit > 1 ? 's' : ''}. Upgrade to connect additional providers.`
        });
      }

      next();
    } catch (err) {
      logger.error('[calendar-limit] Check failed:', err.message);
      next(); // Fail open
    }
  };
}

module.exports = { checkCalendarLimit };

/**
 * Entity Limit Middleware
 *
 * Enforces count-based limits on entities (tasks, recurringTasks, projects, locations, schedule templates).
 * Unlike rate limits (per_month), these check total active count vs plan limit.
 */

const db = require('../db');

function getNestedValue(obj, path) {
  return path.split('.').reduce((o, key) => o?.[key], obj);
}

/**
 * Check if user can create more of an entity type.
 * @param {string} limitKey - Feature path, e.g. 'limits.active_tasks'
 * @param {Function} countFn - async (userId, trx?) => number — returns current count
 * @param {Object} options
 * @param {number} options.batchCountFn - (req) => number of items being created (for batch ops)
 */
function checkEntityLimit(limitKey, countFn, options = {}) {
  return async (req, res, next) => {
    if (!req.planFeatures) {
      return res.status(500).json({ error: 'Plan features not resolved' });
    }

    const limit = getNestedValue(req.planFeatures, limitKey);
    if (limit === -1 || limit === undefined || limit === null) {
      return next(); // unlimited
    }

    const userId = req.user?.id;
    if (!userId) {
      return res.status(401).json({ error: 'Authentication required' });
    }

    try {
      const currentCount = await countFn(userId);
      const batchSize = options.batchCountFn ? options.batchCountFn(req) : 1;

      if (currentCount + batchSize > limit) {
        return res.status(403).json({
          error: `You've reached the limit for your plan`,
          code: 'ENTITY_LIMIT_REACHED',
          limit_key: limitKey,
          current_count: currentCount,
          limit,
          attempting_to_add: batchSize,
          current_plan: req.planId || 'free',
          upgrade_required: true
        });
      }

      next();
    } catch (err) {
      logger.error('[entity-limits] Check failed:', err.message);
      next(); // fail open
    }
  };
}

// --- Count functions for each entity type ---

async function countActiveTasks(userId) {
  const result = await db('tasks_v')
    .where('user_id', userId)
    .whereNotIn('status', ['done', 'cancel', 'skip', 'disabled'])
    .where(function () {
      this.whereNull('task_type').orWhereNot('task_type', 'recurring_template');
    })
    .count('* as count')
    .first();
  return parseInt(result.count, 10);
}

async function countRecurringTemplates(userId) {
  const result = await db('tasks_v')
    .where('user_id', userId)
    .where('task_type', 'recurring_template')
    .whereNotIn('status', ['done', 'cancel', 'skip', 'disabled'])
    .count('* as count')
    .first();
  return parseInt(result.count, 10);
}

async function countProjects(userId) {
  const result = await db('projects')
    .where('user_id', userId)
    .count('* as count')
    .first();
  return parseInt(result.count, 10);
}

async function countLocations(userId) {
  const result = await db('locations')
    .where('user_id', userId)
    .count('* as count')
    .first();
  return parseInt(result.count, 10);
}

async function countScheduleTemplates(userId) {
  const row = await db('user_config')
    .where({ user_id: userId, config_key: 'time_blocks' })
    .first();
  if (!row || !row.config_value) return 0;
  try {
    const blocks = typeof row.config_value === 'string'
      ? JSON.parse(row.config_value) : row.config_value;
    // Count unique day configurations that have blocks defined
    return Object.keys(blocks).filter(k => {
      const v = blocks[k];
      return Array.isArray(v) ? v.length > 0 : !!v;
    }).length;
  } catch {
    return 0;
  }
}

// --- Pre-built middleware for each entity ---

const checkTaskLimit = checkEntityLimit(
  'limits.active_tasks',
  countActiveTasks
);

const checkRecurringLimit = checkEntityLimit(
  'limits.recurring_templates',
  countRecurringTemplates
);

const checkProjectLimit = checkEntityLimit(
  'limits.projects',
  countProjects
);

const checkLocationLimit = (req, res, next) => {
  // Locations use PUT (replace all), so check the incoming count vs limit
  const limit = getNestedValue(req.planFeatures, 'limits.locations');
  if (limit === -1 || limit === undefined || limit === null) return next();

  const locations = Array.isArray(req.body) ? req.body : (req.body?.locations || []);
  if (locations.length > limit) {
    return res.status(403).json({
      error: `You've reached the limit for your plan`,
      code: 'ENTITY_LIMIT_REACHED',
      limit_key: 'limits.locations',
      current_count: locations.length,
      limit,
      current_plan: req.planId || 'free',
      upgrade_required: true
    });
  }
  next();
};

const checkScheduleTemplateLimit = checkEntityLimit(
  'limits.schedule_templates',
  countScheduleTemplates
);

/**
 * For task creation: checks if the task is a recurring_template and enforces that limit,
 * otherwise enforces the active_tasks limit.
 */
function checkTaskOrRecurringLimit(req, res, next) {
  const taskType = req.body?.task_type || req.body?.taskType;
  if (taskType === 'recurring_template') {
    return checkRecurringLimit(req, res, next);
  }
  return checkTaskLimit(req, res, next);
}

/**
 * For batch task creation: separates recurringTasks vs regular tasks and checks both limits.
 */
async function checkBatchTaskLimits(req, res, next) {
  if (!req.planFeatures) {
    return res.status(500).json({ error: 'Plan features not resolved' });
  }

  const userId = req.user?.id;
  if (!userId) return res.status(401).json({ error: 'Authentication required' });

  const items = Array.isArray(req.body) ? req.body : (req.body?.tasks || []);
  const recurringTasks = items.filter(t => (t.task_type || t.taskType) === 'recurring_template');
  const tasks = items.filter(t => (t.task_type || t.taskType) !== 'recurring_template');

  try {
    // Check task limit
    const taskLimit = getNestedValue(req.planFeatures, 'limits.active_tasks');
    if (taskLimit !== -1 && taskLimit !== undefined && tasks.length > 0) {
      const currentTasks = await countActiveTasks(userId);
      if (currentTasks + tasks.length > taskLimit) {
        return res.status(403).json({
          error: `You've reached the task limit for your plan`,
          code: 'ENTITY_LIMIT_REACHED',
          limit_key: 'limits.active_tasks',
          current_count: currentTasks,
          limit: taskLimit,
          attempting_to_add: tasks.length,
          current_plan: req.planId || 'free',
          upgrade_required: true
        });
      }
    }

    // Check recurring limit
    const recurringLimit = getNestedValue(req.planFeatures, 'limits.recurring_templates');
    if (recurringLimit !== -1 && recurringLimit !== undefined && recurringTasks.length > 0) {
      const currentRecurrings = await countRecurringTemplates(userId);
      if (currentRecurrings + recurringTasks.length > recurringLimit) {
        return res.status(403).json({
          error: `You've reached the recurring task template limit for your plan`,
          code: 'ENTITY_LIMIT_REACHED',
          limit_key: 'limits.recurring_templates',
          current_count: currentRecurrings,
          limit: recurringLimit,
          attempting_to_add: recurringTasks.length,
          current_plan: req.planId || 'free',
          upgrade_required: true
        });
      }
    }

    next();
  } catch (err) {
    logger.error('[entity-limits] Batch check failed:', err.message);
    next();
  }
}

module.exports = {
  checkProjectLimit,
  checkLocationLimit,
  checkScheduleTemplateLimit,
  checkTaskOrRecurringLimit,
  checkBatchTaskLimits,
  countActiveTasks,
  countRecurringTemplates,
  countProjects,
  countLocations,
  countScheduleTemplates
};

/**
 * JWT Authentication Middleware for Juggler
 *
 * Delegates to shared auth-client which verifies RS256 JWTs via JWKS
 * from the centralized auth-service. No local secret needed.
 *
 * Maintains the same export interface so all route files work unchanged.
 */

const { authenticateJWT: createAuthMiddleware } = require('auth-client');
const { createRemoteJWKSet, jwtVerify } = require('jose');
const { createLogger } = require('@resume-optimizer/lib-logger');
const db = require('../db');
const { APP_ID } = require('../service-identity');

const logger = createLogger('jwt-auth');

// Verify JWT via auth-client, then resolve local user by email
// (auth-service user IDs may differ from local user IDs)
const jwtMiddleware = createAuthMiddleware(APP_ID);
const authenticateJWT = async (req, res, next) => {
  jwtMiddleware(req, res, async (err) => {
    if (err) return next(err);
    if (!req.user?.email) return; // jwtMiddleware already sent 401
    try {
      const localUser = await db('users').where('email', req.user.email).first();
      if (localUser) {
        req.user = { ...localUser, authServiceId: req.user.id };
      }
    } catch (dbErr) {
      // DB lookup failed — continue with JWT-only user data
    }
    next();
  });
};

// JWKS fetcher for MCP transport verification
let _jwks = null;
function getJWKS() {
  if (!_jwks) {
    const jwksUrl = process.env.AUTH_JWKS_URL || 'http://localhost:5010/.well-known/jwks.json';
    _jwks = createRemoteJWKSet(new URL(jwksUrl));
  }
  return _jwks;
}

/**
 * Verify a token using auth-service JWKS (used by MCP transport)
 */
async function verifyToken(token) {
  const { payload } = await jwtVerify(token, getJWKS(), { issuer: 'raike-auth' });
  return payload;
}

/**
 * No-op — secrets loaded via JWKS from auth-service, not local
 */
async function loadJWTSecrets() {
  logger.info('JWT verification via auth-service JWKS (no local secret needed)');
}

/**
 * Validate refresh token — now delegates to auth-service API
 * Kept for backwards compatibility but refresh should go through auth-service
 */
const validateRefreshToken = async (req, res, next) => {
  // Refresh tokens are now handled by auth-service directly
  // This middleware should not be called in the new flow
  return res.status(410).json({
    error: 'Refresh via auth-service',
    message: 'Token refresh is handled by auth-service. POST to AUTH_SERVICE_URL/api/auth/refresh'
  });
};

module.exports = {
  loadJWTSecrets,
  authenticateJWT,
  validateRefreshToken,
  verifyToken
};

/**
 * Plan Features Middleware for StriveRS
 *
 * Resolves the user's subscription plan into a features object.
 * Fetches plan catalog from payment service (cached 5 min).
 * Fetches user's actual plan from payment service internal API (cached 2 min)
 * so it stays accurate even when the JWT is stale.
 *
 * Product identity: uses the product UUID as the canonical ID.
 * UUID is discovered at startup via payment service and cached for the
 * lifetime of the process.
 */

const { createLogger } = require('@resume-optimizer/lib-logger');
const logger = createLogger('plan-features');

const { PRODUCT_LABEL } = require('../service-identity');
const _proxyConfig = require('../proxy-config');
const CATALOG_CACHE_TTL_MS = 5 * 60 * 1000;
const USER_PLAN_CACHE_TTL_MS = 2 * 60 * 1000;

// ─── Product UUID discovery ─────────────────────────────────────────────
let _productId = null; // Resolved UUID
let _productDiscoveryPromise = null;

async function getProductId() {
  if (_productId) return _productId;
  if (_productDiscoveryPromise) return _productDiscoveryPromise;

  _productDiscoveryPromise = (async () => {
    const paymentUrl = process.env.PAYMENT_SERVICE_URL || 'http://localhost:5020';
    const internalKey = process.env.INTERNAL_SERVICE_KEY || '';
    try {
      const res = await fetch(`${paymentUrl}/internal/products/${PRODUCT_LABEL}`, {
        headers: { 'X-Internal-Key': internalKey, 'Content-Type': 'application/json' },
        signal: AbortSignal.timeout(30000)
      });
      if (!res.ok) throw new Error(`Product discovery failed (${res.status})`);
      const data = await res.json();
      _productId = data.product.id;
      logger.info(`[plan-features] Product "${PRODUCT_LABEL}" -> ${_productId}`);
      return _productId;
    } catch (err) {
      _productDiscoveryPromise = null;
      logger.error(`[plan-features] Product discovery failed:`, { error: err });
      return null;
    }
  })();

  return _productDiscoveryPromise;
}

// ─── Plan catalog cache (all plans + features) ─────────────────────────
let _planFeaturesCache = null;
let _cacheTimestamp = 0;
let _fetchPromise = null;

async function fetchPlanFeatures() {
  const paymentUrl = process.env.PAYMENT_SERVICE_URL || 'http://localhost:5020';
  const productId = await getProductId();
  const filter = productId ? `?product=${productId}` : `?product=${PRODUCT_LABEL}`;
  const response = await fetch(`${paymentUrl}/api/plans${filter}&include_all=true`, {
    headers: { 'Content-Type': 'application/json' },
    signal: AbortSignal.timeout(30000)
  });

  if (!response.ok) throw new Error(`Payment service returned ${response.status}`);

  const data = await response.json();
  const cache = {};
  for (const plan of data.plans || []) {
    if (plan.features) {
      cache[plan.planId] = typeof plan.features === 'string' ? JSON.parse(plan.features) : plan.features;
    }
  }
  return cache;
}

async function getCachedPlanFeatures() {
  const now = Date.now();
  if (_planFeaturesCache && (now - _cacheTimestamp) < CATALOG_CACHE_TTL_MS) {
    return _planFeaturesCache;
  }

  if (_fetchPromise) return _fetchPromise;

  _fetchPromise = fetchPlanFeatures().then(cache => {
    _planFeaturesCache = cache;
    _cacheTimestamp = Date.now();
    _fetchPromise = null;
    return cache;
  }).catch(err => {
    _fetchPromise = null;
    logger.error('[plan-features] Failed to fetch from payment service:', { error: err });
    if (_planFeaturesCache) return _planFeaturesCache;
    throw err;
  });

  return _fetchPromise;
}

// ─── User plan cache (real-time from payment service) ──────────────────
const _userPlanCache = new Map();

async function getUserPlanId(userId) {
  const cached = _userPlanCache.get(userId);
  if (cached && (Date.now() - cached.timestamp) < USER_PLAN_CACHE_TTL_MS) {
    return cached.planId;
  }

  try {
    const paymentUrl = process.env.PAYMENT_SERVICE_URL || 'http://localhost:5020';
    const internalKey = process.env.INTERNAL_SERVICE_KEY || '';
    const res = await fetch(`${paymentUrl}/internal/users/${userId}/active-plans`, {
      headers: { 'X-Internal-Key': internalKey, 'Content-Type': 'application/json' },
      signal: AbortSignal.timeout(30000)
    });
    if (!res.ok) throw new Error(`Payment service returned ${res.status}`);
    const data = await res.json();
    // active-plans returns a map keyed by products.productId (app slug),
    // so look up by PRODUCT_LABEL — same key used in JWT `plans` claims.
    const planId = data.plans?.[PRODUCT_LABEL] || null;
    // Only cache when user has an active plan — don't cache null so that
    // a user who just subscribed isn't blocked by stale cache
    if (planId) {
      _userPlanCache.set(userId, { planId, timestamp: Date.now() });
    } else {
      _userPlanCache.delete(userId);
    }
    return planId;
  } catch {
    return null;
  }
}

// Force refresh — called externally when plan changes
async function refreshPlanFeatures() {
  _cacheTimestamp = 0;
  return getCachedPlanFeatures();
}

function invalidateUserPlanCache(userId) {
  _userPlanCache.delete(userId);
}

// ─── Login reconciliation: enforce limits on stale plan changes ───────
// Runs at most once per user plan cache refresh (2 min) to catch missed webhooks.
const _reconciliationPending = new Map();

async function reconcileLimitsIfNeeded(userId, planFeatures) {
  const now = Date.now();
  const last = _reconciliationPending.get(userId);
  if (last && (now - last) < USER_PLAN_CACHE_TTL_MS) return; // debounce
  _reconciliationPending.set(userId, now);

  // Run async — don't block the request
  setImmediate(async () => {
    try {
      const { enforceDowngradeLimits } = require('../controllers/billing-webhooks.controller');
      await enforceDowngradeLimits(userId, planFeatures);
    } catch (err) {
      logger.error('[plan-features] Reconciliation failed for user', { userId, error: err });
    }
  });
}

// ─── Middleware ─────────────────────────────────────────────────────────
const resolvePlanFeatures = async (req, res, next) => {
  try {
    if (!req.user?.id) {
      return res.status(401).json({ error: 'Authentication required' });
    }

    const paymentUserId = req.user.authServiceId || req.user.id;
    const realPlanId = await getUserPlanId(paymentUserId);

    if (!realPlanId) {
      return res.status(402).json({
        error: 'Subscription required',
        code: 'SUBSCRIPTION_REQUIRED',
        message: 'You need an active subscription to use this app. Choose a plan to get started.',
        plans_url: `${_proxyConfig.services.billing.frontend}/plans`,
      });
    }

    req.planId = realPlanId;

    const allFeatures = await getCachedPlanFeatures();
    req.planFeatures = allFeatures[realPlanId];

    if (!req.planFeatures) {
      logger.warn(`[plan-features] No features found for plan "${realPlanId}", falling back to "free"`);
      req.planFeatures = allFeatures['free'];
      req.planId = 'free';
    }

    if (!req.planFeatures) {
      return res.status(503).json({ error: 'Plan configuration unavailable. Please try again.' });
    }

    // Background reconciliation: verify user isn't over limits (catches missed webhooks)
    reconcileLimitsIfNeeded(req.user.id, req.planFeatures);

    next();
  } catch (err) {
    logger.error('[plan-features] Error:', { error: err });
    return res.status(503).json({ error: 'Payment service unavailable. Please try again.' });
  }
};

module.exports = { resolvePlanFeatures, PRODUCT_LABEL, getProductId, refreshPlanFeatures, invalidateUserPlanCache, getCachedPlanFeatures };

/**
 * Service URL Resolution — Shared across all Raike frontends & backends
 *
 * Detects the environment (localhost, localdev, production) and resolves
 * all service URLs automatically. Single source of truth for the entire
 * platform — no hardcoded URLs needed in app code.
 *
 * Frontend usage (browser — detects via window.location.hostname):
 *   const { authServiceUrl, billingFrontendUrl } = require('./proxy-config');
 *
 * Backend usage (Node.js — detects via RAIKE_ENV or individual env vars):
 *   const { services } = require('./proxy-config');
 *   const paymentUrl = services.billing.backend;
 */

// ─── Environment definitions ────────────────────────────────────────────
// Add new environments here — no other files need to change.

const ENVIRONMENTS = {
  localdev: {
    suffix: '.localdev.raikegroup.com',
    services: {
      auth:    { url: 'https://auth.localdev.raikegroup.com' },
      juggler: { url: 'https://strivers.localdev.raikegroup.com' },
      resume:  { url: 'https://climbrs.localdev.raikegroup.com' },
      billing: { url: 'https://billing.localdev.raikegroup.com' },
      bugs:    { url: 'https://bugs.localdev.raikegroup.com' },
    },
    cookieDomain: '.raikegroup.com',
    homeUrl: 'https://auth.localdev.raikegroup.com',
  },
  production: {
    suffix: '.raikegroup.com',
    services: {
      auth:    { url: 'https://auth.raikegroup.com' },
      juggler: { url: 'https://strivers.raikegroup.com' },
      resume:  { url: 'https://climbrs.raikegroup.com' },
      billing: { url: 'https://billing.raikegroup.com' },
      bugs:    { url: 'https://bugs.raikegroup.com' },
    },
    cookieDomain: '.raikegroup.com',
    homeUrl: 'https://raikegroup.com',
  },
  localhost: {
    suffix: null,
    services: {
      auth:    { frontend: 'http://localhost:3001', backend: 'http://localhost:5010' },
      juggler: { frontend: 'http://localhost:3002', backend: 'http://localhost:5002' },
      resume:  { frontend: 'http://localhost:3000', backend: 'http://localhost:5001' },
      billing: { frontend: 'http://localhost:3003', backend: 'http://localhost:5020' },
      bugs:    { frontend: 'http://localhost:3004', backend: 'http://localhost:5030' },
    },
    cookieDomain: 'localhost',
    homeUrl: 'http://localhost:3001',
  },
};

// ─── Environment detection ──────────────────────────────────────────────

function detect() {
  // Browser: detect from hostname
  if (typeof window !== 'undefined' && window.location) {
    var hostname = window.location.hostname;
    if (hostname.indexOf('.localdev.raikegroup.com') >= 0) {
      return { name: 'localdev', ...ENVIRONMENTS.localdev };
    }
    if (hostname.indexOf('.raikegroup.com') >= 0) {
      return { name: 'production', ...ENVIRONMENTS.production };
    }
  }

  // Node.js backend: detect from RAIKE_ENV or NODE_ENV
  if (typeof process !== 'undefined' && process.env) {
    var envName = process.env.RAIKE_ENV;
    if (envName && ENVIRONMENTS[envName]) {
      return { name: envName, ...ENVIRONMENTS[envName] };
    }
    if (process.env.NODE_ENV === 'production') {
      return { name: 'production', ...ENVIRONMENTS.production };
    }
  }

  return { name: 'localhost', ...ENVIRONMENTS.localhost };
}

const env = detect();
const isProxied = env.name !== 'localhost';

// ─── Service URL resolver ───────────────────────────────────────────────
// In proxied environments (localdev/production), frontend and backend share
// the same URL — Caddy routes /api/* to the backend, everything else to frontend.
// On localhost, they're separate ports.

function resolveService(name) {
  const svc = env.services[name];
  if (!svc) return { frontend: null, backend: null };

  if (svc.url) {
    // Proxied: single URL for both frontend and backend
    return { frontend: svc.url, backend: svc.url };
  }
  // Localhost: separate ports
  return { frontend: svc.frontend, backend: svc.backend };
}

const services = {
  auth:    resolveService('auth'),
  juggler: resolveService('juggler'),
  resume:  resolveService('resume'),
  billing: resolveService('billing'),
  bugs:    resolveService('bugs'),
};

// ─── Backwards-compatible exports ───────────────────────────────────────
// These match the original proxy-config API so existing code doesn't break.

function envVar(name) {
  return typeof process !== 'undefined' && process.env && process.env[name];
}

const authServiceUrl = services.auth.backend
  || envVar('REACT_APP_AUTH_SERVICE_URL')
  || 'http://localhost:5010';

const authFrontendUrl = services.auth.frontend
  || envVar('REACT_APP_AUTH_FRONTEND_URL')
  || 'http://localhost:3001';

const apiBase = isProxied
  ? '/api'
  : (envVar('REACT_APP_API_URL') || '/api');

/**
 * Origins where Google OAuth is configured and authorized.
 */
const googleAuthorizedOrigins = [
  'http://localhost:3001',
  ...Object.keys(ENVIRONMENTS)
    .filter(k => k !== 'localhost')
    .map(k => ENVIRONMENTS[k].services.auth.url),
];

const isGoogleOrigin = typeof window !== 'undefined'
  && googleAuthorizedOrigins.includes(window.location.origin);

// ─── Product label → service key mapping ────────────────────────────────
// Maps the database productId (label) to the proxy-config service key.
// Used by payment frontend to route users to the correct app after checkout.
const productLabelToServiceKey = {
  'juggler': 'juggler',
  'resume-optimizer': 'resume',
};

// Detect which app we are based on hostname (browser) or APP_ID env var (Node)
const appId = (() => {
  const fromEnv = typeof process !== 'undefined' && process.env && process.env.APP_ID;
  if (fromEnv) return fromEnv;
  if (typeof window === 'undefined') return null;
  const host = window.location.hostname;
  if (host.includes('strivers') || host.includes('juggler') || host === 'localhost' && window.location.port === '3002') return 'juggler';
  if (host.includes('climbrs') || host.includes('resume') || host === 'localhost' && window.location.port === '3000') return 'resume-optimizer';
  if (host.includes('billing') || host === 'localhost' && window.location.port === '3003') return 'billing';
  if (host.includes('bugs') || host === 'localhost' && window.location.port === '3004') return 'bug-reporter';
  if (host.includes('auth') || host === 'localhost' && window.location.port === '3001') return 'auth';
  return null;
})();

// ─── Exports ────────────────────────────────────────────────────────────

module.exports = {
  services,
  environment: env.name,
  cookieDomain: env.cookieDomain,
  homeUrl: env.homeUrl,
  ENVIRONMENTS,
  productLabelToServiceKey,
  appId,
  isProxied,
  authServiceUrl,
  authFrontendUrl,
  apiBase,
  googleAuthorizedOrigins,
  isGoogleOrigin,
};

const express = require('express');
const crypto = require('crypto');
const router = express.Router();
const { handleWebhook } = require('../controllers/billing-webhooks.controller');

// Verify HMAC-SHA256 signature from payment service + reject stale replays.
// Signs req.rawBody (the original wire bytes captured by express.raw() in app.js).
// If rawBody is absent, the middleware in app.js failed — reject immediately.
// This matches what payment-service signs on the sending side.
const FRESHNESS_WINDOW_MS = 5 * 60 * 1000;
function verifySignature(req, res, next) {
  const sig = req.headers['x-billing-signature'];
  const secret = process.env.BILLING_WEBHOOK_SECRET || process.env.INTERNAL_SERVICE_KEY;

  if (!secret) {
    logger.error('[billing-webhook] No BILLING_WEBHOOK_SECRET or INTERNAL_SERVICE_KEY configured — cannot verify webhooks');
    return res.status(500).json({ error: 'Webhook signature verification not configured' });
  }

  if (!sig) {
    return res.status(401).json({ error: 'Missing X-Billing-Signature header' });
  }

  const rawBody = req.rawBody;
  if (!rawBody) {
    return res.status(500).json({ error: 'Internal: rawBody unavailable' });
  }
  const expectedSig = 'sha256=' + crypto
    .createHmac('sha256', secret)
    .update(rawBody)
    .digest('hex');

  // Hash both sides to equal length so timingSafeEqual gets no length side-channel.
  try {
    const sigHash = crypto.createHash('sha256').update(Buffer.from(sig)).digest();
    const expectedHash = crypto.createHash('sha256').update(Buffer.from(expectedSig)).digest();
    if (!crypto.timingSafeEqual(sigHash, expectedHash)) {
      return res.status(401).json({ error: 'Invalid signature' });
    }
  } catch {
    return res.status(401).json({ error: 'Invalid signature format' });
  }

  // Replay protection: payment-service puts a `timestamp` in the signed body
  // (notification.service.js:59). Reject anything outside the freshness window.
  if (req.body && typeof req.body.timestamp === 'string') {
    const ts = Date.parse(req.body.timestamp);
    if (!Number.isNaN(ts) && Math.abs(Date.now() - ts) > FRESHNESS_WINDOW_MS) {
      return res.status(401).json({ error: 'Webhook timestamp outside freshness window' });
    }
  }

  next();
}

router.post('/', verifySignature, handleWebhook);

module.exports = router;

