    var want = desiredById[r.id];
    if (!want) return;
    var curSo = Number(r.split_ordinal) || 1;
    var curSt = Number(r.split_total) || 1;
    var curDur = Number(r.dur);
    if (curSo !== want.split_ordinal || curSt !== want.split_total || curDur !== want.dur) {
