    await db('task_instances').whereIn('id', toDeleteIds).update({ unscheduled: 1, updated_at: db.fn.now() });
    await tasksWrite.deleteTasksWhere(trx, userId, function(q) { return q.whereIn('id', toDeleteIds); });
