      sourceId: row.sourceId,
      generated: true,
      date: row.date,
      day: row.date ? DAY_NAMES[parseDate(row.date).getDay()] : null,
      time: row.split_ordinal === 1 ? row.time : null,
      status: '',
      splitOrdinal: row.split_ordinal,
      splitTotal: row.split_total,
