      if (p._overdue || (p.task && p.task._overdue)) entry.overdue = true;
      return entry;
    });
  });
  newCache.unplaced = result.unplaced.map(function(t) { return t.id; });
  var unplacedMeta2 = {};
  result.unplaced.forEach(function(t) {
    if (t._unplacedDetail || t._suggestions || t._unplacedReason) {
      var meta = {};
      if (t._unplacedDetail) meta.detail = t._unplacedDetail;
      if (t._unplacedReason) meta.reason = t._unplacedReason;
      if (t._suggestions) meta.suggestions = t._suggestions;
      if (t._whenBlocked) meta.whenBlocked = true;
      unplacedMeta2[t.id] = meta;
    }
  });
  newCache.unplacedMeta = unplacedMeta2;
  var cacheJson = JSON.stringify(newCache);
  var existingRow = await db('user_config').where({ user_id: userId, config_key: 'schedule_cache' }).first();
  if (existingRow) {
    await db('user_config').where({ user_id: userId, config_key: 'schedule_cache' }).update({ config_value: cacheJson });
  } else {
    await db('user_config').insert({ user_id: userId, config_key: 'schedule_cache', config_value: cacheJson });
  }

  // Add scheduledAtUtc to placements for timezone-independent frontend display
  var outPlacements2 = {};
  Object.keys(result.dayPlacements).forEach(function(dk) {
    outPlacements2[dk] = result.dayPlacements[dk].map(function(p) {
      var hh4 = Math.floor(p.start / 60);
      var mm4 = p.start % 60;
      var ampm4 = hh4 >= 12 ? 'PM' : 'AM';
      var dh4 = hh4 > 12 ? hh4 - 12 : (hh4 === 0 ? 12 : hh4);
      var ts4 = dh4 + ':' + (mm4 < 10 ? '0' : '') + mm4 + ' ' + ampm4;
      var utc4 = localToUtc(dk, ts4, TIMEZONE);
      if (utc4) p.scheduledAtUtc = utc4.toISOString();
      return p;
    });
  });

  await injectTerminalPlacements(outPlacements2, userId, TIMEZONE);
  return {
    dayPlacements: outPlacements2,
    unplaced: result.unplaced.filter(function(t) {
      if (t.generated && !t._unplacedReason) return false;
      return true;
    }),
    score: result.score,
    warnings: result.warnings || [],
    hasPastTasks: hasPastTasks
  };
}

module.exports = { runScheduleAndPersist, getSchedulePlacements, computeWindowCloseUtc };

/**
 * scheduleQueue.js — DB-backed event queue + debounced scheduler runner
 *
 * Mutation controllers call enqueueScheduleRun(userId) after their DB write.
 * This inserts a row into schedule_queue and marks the user dirty in memory.
 *
 * A poll loop checks the DB for unclaimed rows on a short interval. For each
 * unclaimed user, it atomically claims the row (claimed_by + claimed_at), then
 * runs the scheduler if the quiet period has elapsed.
 *
 * The dirty set is retained as a write-side advisory hint: enqueue() marks the
 * user dirty so the poll loop checks immediately on this instance. It is NOT the
 * authoritative gate for processing — the DB claim is. This prevents the
 * multi-instance double-run described in RESEARCH.md Category 2 / Pitfall 3.
 *
 * Reference pattern: cal-history-cron.js uses the same DB-based claim approach
 * (sync_locks shard leader election). The claiming here is lighter-weight —
 * a direct UPDATE on the schedule_queue row instead of an INSERT-based mutex —
 * because schedule_queue rows are per-user and naturally deduplicated.
 *
 * Single-flight per user within one instance: the `running` Map prevents one
 * instance from racing itself if the poll interval fires faster than processUser
 * completes. The DB claim prevents cross-instance races.
 *
 * Crash recovery: if an instance crashes mid-run, claimed_by stays set but
 * claimed_at stops refreshing. After CLAIM_TTL_SECONDS, another instance
 * reclaims the row and runs the scheduler. (T-07-07 mitigation)
 */

var db = require('../db');
var crypto = require('crypto');
var { createLogger } = require('@resume-optimizer/lib-logger');
var logger = createLogger('scheduleQueue');

// Lazy requires to avoid circular dependency
var _flushQueueInLock;
function getFlushQueueInLock() {
  if (!_flushQueueInLock) _flushQueueInLock = require('../lib/task-write-queue').flushQueueInLock;
  return _flushQueueInLock;
}
var _runScheduleAndPersist;
function getRunScheduleAndPersist() {
  if (!_runScheduleAndPersist) _runScheduleAndPersist = require('./runSchedule').runScheduleAndPersist;
  return _runScheduleAndPersist;
}
var _withLock;
function getWithLock() {
  if (!_withLock) _withLock = require('../lib/sync-lock').withLock;
  return _withLock;
}
var _sseEmitter;
function getSseEmitter() {
  if (!_sseEmitter) _sseEmitter = require('../lib/sse-emitter');
  return _sseEmitter;
}

// ── Configuration ──
var DEBOUNCE_MS    = 2000;   // quiet period before scheduler runs
var POLL_MS        = 3000;   // how often the poll loop checks the DB (was 1s; 3s reduces idle DB load)
var LOCK_RETRY_MS  = 2000;   // wait between lock acquisition retries

// ── Multi-instance claiming constants (FIX-04) ──────────────────────────────

var POLL_LOOP_INSTANCE;
var INSTANCE_ID = crypto.randomUUID();
var POLL_ACTIVE = false;

// ── State ──
var _dirty = new Set();               // users with pending changes (write-side hint)
var _lastEnqueueTime = new Map();       // user_id → timestamp
var _running = new Map();             // user_id → promise (single-flight within instance)
var _lastPollTime = 0;

// Poll loop tracking for health checks
function getPollLoopState() {
  return {
    active: POLL_ACTIVE,
    lastPollTime: _lastPollTime,
    runningCount: _running.size,
    dirtyCount: _dirty.size
  };
}

// ── Public API ──

/**
 * Mark a user as needing a schedule run. Debounced: if called repeatedly
 * within DEBOUNCE_MS, only the last call matters.
 *
 * The DB row is the source of truth; the _dirty set is just an optimization
 * so we don't have to poll the DB for every local mutation.
 */
async function enqueueScheduleRun(userId, source, options) {
  var now = Date.now();
  _dirty.add(userId);
  _lastEnqueueTime.set(userId, now);

  // Insert or update queue row (the actual work queue)
  var shouldRun = options && options.immediate;
  var row = {
    user_id: userId,
    source: source || 'unknown',
    created_at: new Date()
  };

  try {
    // Upsert: on conflict, only update if the row is old enough that we might
    // have lost a claimed worker (crash recovery), otherwise leave it alone.
    // FIX-04: Use INSERT with ON DUPLICATE KEY so we can detect conflicts cleanly.
    await db('schedule_queue')
      .insert(row)
      .onConflict('user_id')
      .merge(['source', 'created_at']);
  } catch (e) {
    // Conflict resolution failed — log and continue; the poll loop will pick it up
    logger.error('[SCHED-QUEUE] Failed to enqueue for user', { userId, error: e });
  }

  // Immediate trigger for test environments or urgent updates
  if (shouldRun) {
    processUser(userId);
  }

  logger.info('[SCHED-QUEUE] enqueued for ' + userId + ' source=' + (source || 'unknown'));
}

/**
 * Remove a user from the dirty set and queue.
 * Called by the scheduler when it finishes a run (success or failure).
 */
async function dequeueScheduleRun(userId) {
  _dirty.delete(userId);
  _lastEnqueueTime.delete(userId);
  _running.delete(userId);

  try {
    // Delete the queue row for this user
    var swept = await db('schedule_queue')
      .where('user_id', userId)
      .del();
    logger.info('[SCHED-QUEUE] swept ' + swept + ' entry(ies) for ' + userId);
  } catch (e) {
    logger.error('[SCHED-QUEUE] Failed to dequeue for user', { userId, error: e });
  }
}

// ── DB Claiming (FIX-04) ────────────────────────────────────────────────────

// Claim a work item with multi-instance safety.
// Returns { claimed: true, row } or { claimed: false, reason }.
async function claimAndRun(userId) {
  var claimedAt = new Date();
  var ttlExpiry = new Date(Date.now() - (CLAIM_TTL_SECONDS * 1000));

  // Try to claim this user's row: either unclaimed, or an expired claim.
  // We use user_id as the WHERE to ensure atomicity (single row UPDATE).
  var updated = await db('schedule_queue')
    .where('user_id', userId)
    .andWhere(function() {
      this.whereNull('claimed_by')
          .orWhere('claimed_at', '<', ttlExpiry);
    })
    .update({
      claimed_by: INSTANCE_ID,
      claimed_at: claimedAt
    });

  if (updated === 0) {
    var existing = await db('schedule_queue').where('user_id', userId).first();
    if (existing && existing.claimed_by && existing.claimed_by !== INSTANCE_ID) {
      return { claimed: false, reason: 'already_claimed', by: existing.claimed_by, since: existing.claimed_at };
    }
    return { claimed: false, reason: 'no_row' };
  }

  // We claimed it. Now run the scheduler within the sync lock.
  var row = await db('schedule_queue').where('user_id', userId).first();
  if (!row) {
    return { claimed: false, reason: 'row_missing_after_claim' };
  }

  // Start heartbeat for long-running scheduler jobs
  var heartbeat = startClaimHeartbeat(userId);
  try {
    var runWithLock = getWithLock();
    var runScheduleAndPersist = getRunScheduleAndPersist();
    var flushQueueInLock = getFlushQueueInLock();

    await runWithLock(userId, SOURCE_APP, async function() {
      // Flush any pending writes before scheduler reads task state
      await flushQueueInLock(userId);
      // Run the scheduler
      await runScheduleAndPersist(userId, row.source);
    });

    // Success: sweep the queue
    await dequeueScheduleRun(userId);
    return { claimed: true, success: true };
  } catch (err) {
    // On failure, release the claim so someone else can retry
    await releaseClaim(userId);
    return { claimed: true, success: false, error: err.message };
  } finally {
    clearInterval(heartbeat);
  }
}

/**
 * Process a user: claim from DB, run scheduler, sweep queue.
 * This is the main entry point called by the poll loop.
 */
async function processUser(userId) {
  // Single-flight within this instance
  if (_running.has(userId)) {
    var attempt = 0;
    var MAX_LOCK_RETRIES = 5;
    while (_running.has(userId) && attempt < MAX_LOCK_RETRIES) {
      attempt++;
      logger.info('[SCHED-QUEUE] lock held for ' + userId + ', retry ' + attempt + '/' + MAX_LOCK_RETRIES);
      await new Promise(function(r) { setTimeout(r, LOCK_RETRY_MS); });
    }
    if (_running.has(userId)) {
      logger.warn('[SCHED-QUEUE] Giving up on ' + userId + ' after ' + MAX_LOCK_RETRIES + ' retries');
      return { ran: false, reason: 'lock_timeout' };
    }
  }

  // Check debounce: minimum quiet period before running
  var last = _lastEnqueueTime.get(userId);
  if (last && (Date.now() - last) < DEBOUNCE_MS) {
    return { ran: false, reason: 'debounce', wait: DEBOUNCE_MS - (Date.now() - last) };
  }

  var promise = (async function() {
    try {
      var result = await claimAndRun(userId);
      if (!result.claimed) {
        return { ran: false, reason: result.reason, details: result };
      }
      if (!result.success) {
        return { ran: false, reason: 'scheduler_failed', error: result.error };
      }
      return { ran: true };
    } catch (e) {
      logger.error('[SCHED-QUEUE] Unexpected error processing user ' + userId, { error: e });
      return { ran: false, reason: 'exception', error: e.message };
    }
  })();

  _running.set(userId, promise);
  try {
    var result = await promise;
    _running.delete(userId);
    return result;
  } catch (e) {
    _running.delete(userId);
    throw e;
  }
}

// ── Claim maintenance ──

function startClaimHeartbeat(userId) {
  return setInterval(async function() {
    try {
      await db('schedule_queue')
        .where('user_id', userId)
        .where('claimed_by', INSTANCE_ID)
        .update({ claimed_at: new Date() });
    } catch (e) {
      logger.error('[SCHED-QUEUE] Heartbeat failed for user ' + userId, { error: e });
    }
  }, 30000); // every 30s
}

async function releaseClaim(userId) {
  try {
    await db('schedule_queue')
      .where('user_id', userId)
      .where('claimed_by', INSTANCE_ID)
      .update({ claimed_by: null, claimed_at: null });
  } catch (e) {
    logger.error('[SCHED-QUEUE] Failed to release claim for user ' + userId, { error: e });
  }
}

// ── Poll loop ───────────────────────────────────────────────────────────────

async function pollOnce() {
  _lastPollTime = Date.now();

  // Fast path: process dirty users first (local optimization)
  var dirtyUsers = Array.from(_dirty).slice(0, MAX_DIRTY_USERS_PER_POLL);
  for (var i = 0; i < dirtyUsers.length; i++) {
    await processUser(dirtyUsers[i]);
  }

  // Safety sweep: also poll the DB for any unclaimed rows that might have
  // been left behind if this instance crashed and restarted.
  try {
    var stale = new Date(Date.now() - (CLAIM_TTL_SECONDS * 1000));
    var pending = await db('schedule_queue')
      .whereNull('claimed_by')
      .orWhere('claimed_at', '<', stale)
      .orderBy('created_at', 'asc')
      .limit(MAX_DIRTY_USERS_PER_POLL)
      .select('user_id');

    for (var j = 0; j < pending.length; j++) {
      var user = pending[j].user_id;
      _dirty.add(user); // Mark dirty so we process it next poll
    }

    var schedPending = await db('schedule_queue').whereNull('claimed_by').orWhere('claimed_at', '<', stale).count('* as c');
    var writePending = await db('task_write_queue').count('* as c');
    var total = await db('tasks_v').distinct('user_id');
    if (pending.length > 0 || schedPending[0].c > 0) {
      logger.info('[SCHED-QUEUE] startup scan: ' + total.length + ' user(s) with pending entries (schedule=' + schedPending[0].c + ' writes=' + writePending[0].c + ')');
    }
  } catch (e) {
    logger.error('[SCHED-QUEUE] DB poll failed', { error: e });
  }
}

function startPollLoop() {
  // Start the scheduler poll loop. Returns cleanup function.
  POLL_ACTIVE = true;
  POLL_LOOP_INSTANCE = setInterval(pollOnce, POLL_MS);
  logger.info('[SCHED-QUEUE] Poll loop started (instance=' + INSTANCE_ID + ')');
  return function() {
    POLL_ACTIVE = false;
    clearInterval(POLL_LOOP_INSTANCE);
  };
}

function stopPollLoop() {
  POLL_ACTIVE = false;
  if (POLL_LOOP_INSTANCE) {
    clearInterval(POLL_LOOP_INSTANCE);
    POLL_LOOP_INSTANCE = null;
  }
}

// ── Constants ──
var SOURCE_APP = 'scheduleQueue';
var MAX_DIRTY_USERS_PER_POLL = 50;
var CLAIM_TTL_SECONDS = 60; // Reclaim after 60s of no heartbeat

module.exports = {
  enqueueScheduleRun,
  dequeueScheduleRun,
  processUser,
  startPollLoop,
  stopPollLoop,
  getPollLoopState,
  // Internal exports for tests
  _dirty,
  _lastEnqueueTime,
  _running
};

/**
 * schedulerSession — DB-backed session store for the admin Stepper UI.
 *
 * A session pre-runs unifiedScheduleV2() once with cfg._stepRecorder enabled,
 * producing a full snapshots[] array (one entry per placement commit). The
 * admin UI then walks forward/backward through snapshots indexically; the
 * server doesn't re-run the scheduler per step. V2 emits steps tagged with
 * phases 'V2: Immovable' / 'V2: Constrained' / 'V2: Unconstrained' /
 * 'V2: Retry' — corresponding to the immovable pass, the slack-sorted main
 * loop (finite vs Infinity slack), and the dep-deferred retry pass.
 *
 * Dry-run only: sessions never call runScheduleAndPersist or any
 * tasksWrite.*Task function. The scheduler output is never persisted from
 * this path.
 *
 * Sessions are keyed by a random id, scoped to the admin who started them,
 * and expire after 1h. The DB sweep deletes expired rows every 5 minutes.
 */

var crypto = require('crypto');
var db = require('../db');
var { createLogger } = require('@resume-optimizer/lib-logger');
var logger = createLogger('schedulerSession');

var SESSION_TTL_MS = 60 * 60 * 1000; // 1h
var SWEEP_INTERVAL_MS = 5 * 60 * 1000; // 5m

function newSessionId() {
  return crypto.randomBytes(16).toString('hex');
}

async function sweep() {
  try {
    await db('scheduler_sessions').where('expires_at', '<', new Date()).delete();
  } catch (e) {
    logger.warn('[schedulerSession] sweep error:', { error: e });
  }
}

// Start a background sweeper. Unref so it doesn't block process shutdown.
var sweepTimer = setInterval(function() { sweep(); }, SWEEP_INTERVAL_MS);
if (sweepTimer.unref) sweepTimer.unref();

/**
 * Create a new stepper session for the given user. Loads the user's tasks
 * + config, runs unifiedSchedule in recorder mode, stores snapshots.
 *
 * Returns { sessionId, totalSteps, todayKey, nowMins, timezone, summary }.
 */
async function startSession(userId, options) {
  var opts = options || {};
  var unifiedSchedule = require('./unifiedScheduleV2');
  var constants = require('./constants');
  var rowToTask = require('../controllers/task.controller').rowToTask;

  var TIMEZONE = opts.timezone || 'America/New_York';
  var nowDt = new Date();
  var parts = new Intl.DateTimeFormat('en-US', {
    timeZone: TIMEZONE, year: 'numeric', month: 'numeric', day: 'numeric',
    hour: 'numeric', minute: 'numeric', hourCycle: 'h23'
  }).formatToParts(nowDt);
  var vals = {};
  parts.forEach(function(p) { vals[p.type] = parseInt(p.value, 10); });
  var _m = vals.month, _d = vals.day;
  var todayKey = vals.year + '-' + (_m < 10 ? '0' : '') + _m + '-' + (_d < 10 ? '0' : '') + _d;
  var nowMins = (vals.hour % 24) * 60 + vals.minute;

  // Match runSchedule.js's schedulable-row filter: open/wip instances,
  // NULL-status rows, and ALL recurring templates (templates have
  // status=NULL in the view, so a naive `whereNot('status', 'disabled')`
  // excludes them via SQL three-valued logic — stepper would see zero
  // templates and never expand any recurrings).
  var tasks = await db('tasks_v').where('user_id', userId)
    .where(function() {
      this.where('status', '').orWhere('status', 'wip').orWhereNull('status')
        .orWhere('task_type', 'recurring_template');
    })
    .select();
  var configRows = await db('user_config').where({ user_id: userId });
  var cfg = {};
  configRows.forEach(function(r) {
    try { cfg[r.config_key] = JSON.parse(r.config_value); }
    catch (e) { cfg[r.config_key] = r.config_value; }
  });

  var stepRecorder = [];
  var schedCfg = {
    timeBlocks: cfg.timeBlocks || constants.DEFAULT_TIME_BLOCKS,
    toolMatrix: cfg.toolMatrix || constants.DEFAULT_TOOL_MATRIX,
    locSchedules: cfg.locSchedules || {},
    locScheduleDefaults: cfg.locScheduleDefaults || {},
    locScheduleOverrides: cfg.locScheduleOverrides || {},
    hourLocationOverrides: cfg.hourLocationOverrides || {},
    scheduleTemplates: cfg.scheduleTemplates || null,
    splitMinDefault: cfg.splitMinDefault || 15,
    preferences: cfg.preferences || {},
    timezone: TIMEZONE,
    _stepRecorder: stepRecorder
  };

  var statuses = {};
  tasks.forEach(function(t) { statuses[t.id] = t.status || ''; });

  var srcMap = {};
  tasks.forEach(function(t) {
    if (t.task_type === 'recurring_template' || (!t.generated && t.recur)) {
      srcMap[t.id] = t;
    }
  });
  var mapped = tasks.map(function(r) { return rowToTask(r, TIMEZONE, srcMap); });

  var result = unifiedSchedule(mapped, statuses, todayKey, nowMins, schedCfg);

  // Build a simple task-index for step explanations.
  var tasksById = {};
  mapped.forEach(function(t) { tasksById[t.id] = t; });

  var sessionId = newSessionId();
  var unplacedSummary = (result.unplaced || []).map(function(t) {
    return {
      id: t.id, text: t.text, project: t.project, pri: t.pri,
      reason: t._unplacedReason || null, detail: t._unplacedDetail || null
    };
  });

  await db('scheduler_sessions').insert({
    session_id: sessionId,
    user_id: userId,
    today_key: todayKey,
    now_mins: nowMins,
    timezone: TIMEZONE,
    snapshots: JSON.stringify(stepRecorder),
    tasks_by_id: JSON.stringify(tasksById),
    unplaced: JSON.stringify(unplacedSummary),
    score: JSON.stringify(result.score || {}),
    warnings: JSON.stringify(result.warnings || []),
    slack_by_task_id: JSON.stringify(result.slackByTaskId || {}),
    created_at: new Date(),
    expires_at: new Date(Date.now() + SESSION_TTL_MS)
  });

  return {
    sessionId: sessionId,
    totalSteps: stepRecorder.length,
    todayKey: todayKey,
    nowMins: nowMins,
    timezone: TIMEZONE,
    summary: {
      taskCount: mapped.length,
      placedCount: result.placedCount || 0,
      unplacedCount: (result.unplaced || []).length,
      score: result.score || {}
    }
  };
}

/**
 * Load a session from the DB. Returns a session object (camelCase fields)
 * or null if not found / expired. Also touches expires_at to extend TTL.
 */
async function getSession(sessionId) {
  var row = await db('scheduler_sessions')
    .where('session_id', sessionId)
    .where('expires_at', '>', new Date())
    .first();
  if (!row) return null;

  // Extend TTL on access.
  await db('scheduler_sessions')
    .where('session_id', sessionId)
    .update({ expires_at: new Date(Date.now() + SESSION_TTL_MS) });

  return {
    sessionId: row.session_id,
    userId: row.user_id,
    todayKey: row.today_key,
    nowMins: row.now_mins,
    timezone: row.timezone,
    snapshots: typeof row.snapshots === 'string' ? JSON.parse(row.snapshots) : row.snapshots,
    tasksById: typeof row.tasks_by_id === 'string' ? JSON.parse(row.tasks_by_id) : row.tasks_by_id,
    unplaced: typeof row.unplaced === 'string' ? JSON.parse(row.unplaced) : row.unplaced,
    score: typeof row.score === 'string' ? JSON.parse(row.score) : row.score,
    warnings: typeof row.warnings === 'string' ? JSON.parse(row.warnings) : row.warnings,
    slackByTaskId: typeof row.slack_by_task_id === 'string' ? JSON.parse(row.slack_by_task_id) : row.slack_by_task_id
  };
}

/**
 * Sync helper: compute a single step from an already-fetched session object.
 */
function _computeStep(s, stepIndex) {
  if (stepIndex < 0 || stepIndex >= s.snapshots.length) return null;
  var raw = s.snapshots[stepIndex];
  var task = s.tasksById[raw.taskId] || null;
  return Object.assign({}, raw, {
    totalSteps: s.snapshots.length,
    task: task ? {
      id: task.id, text: task.text, project: task.project, pri: task.pri,
      dur: task.dur, when: task.when, deadline: task.deadline,
      startAfter: task.startAfter, recurring: !!task.recurring,
      split: !!task.split, splitMin: task.splitMin,
      location: task.location, tools: task.tools,
      slackMins: s.slackByTaskId[task.id] != null ? s.slackByTaskId[task.id] : null
    } : null,
    // Preview of the next few tasks coming up in the queue.
    upcoming: s.snapshots.slice(stepIndex + 1, stepIndex + 6).map(function(next) {
      return {
        stepIndex: next.stepIndex,
        phase: next.phase,
        taskId: next.taskId,
        taskText: next.taskText,
        orderingSlack: next.orderingSlack
      };
    })
  });
}

/**
 * Sync helper: compute the summary from an already-fetched session object.
 */
function _computeSummary(s) {
  // Lightweight queue: one entry per step so the UI can render a scrollable
  // sidebar. Strips the heavy per-step dayPlacementsSnapshot; just the
  // labels needed for an "up next" list.
  var queue = s.snapshots.map(function(st) {
    return {
      stepIndex: st.stepIndex,
      phase: st.phase,
      taskId: st.taskId,
      taskText: st.taskText,
      project: st.project,
      pri: st.pri,
      orderingSlack: st.orderingSlack,
      placement: st.placement ? {
        dateKey: st.placement.dateKey,
        start: st.placement.start,
        dur: st.placement.dur
      } : null
    };
  });
  return {
    sessionId: s.sessionId,
    totalSteps: s.snapshots.length,
    todayKey: s.todayKey,
    nowMins: s.nowMins,
    timezone: s.timezone,
    unplaced: s.unplaced,
    score: s.score,
