async function syncPlans() {
  // Product label in URL — payment service accepts both UUID and label
  const url = `${PAYMENT_SERVICE_URL}/api/products/juggler/plans/sync`;

  console.log(`Syncing ${PLAN_CATALOG.length} plans to ${url}...`);

  const headers = { 'Content-Type': 'application/json' };
  if (PAYMENT_API_KEY) {
    headers['X-Service-Key'] = PAYMENT_API_KEY;
  }

  const response = await fetch(url, {
    method: 'PUT',
    headers,
    body: JSON.stringify({ plans: PLAN_CATALOG })
  });

  if (!response.ok) {
    const body = await response.text();
    throw new Error(`Sync failed (${response.status}): ${body}`);
  }

  const result = await response.json();
  console.log('Sync results:', JSON.stringify(result.results, null, 2));
  return result;
}

// ─── CLI entry point ───────────────────────────────────────────────────

if (require.main === module) {
  syncPlans()
    .then(() => {
      console.log('Plan registration complete.');
      process.exit(0);
    })
    .catch((err) => {
      console.error('Plan registration failed:', err.message);
      process.exit(1);
    });
}

module.exports = { PLAN_CATALOG, syncPlans };

/**
 * Raike & Sons Backend Server
 */

require('dotenv').config();
const { serverLogger } = require('./lib/logger');

// Kill any zombie server processes from previous nodemon restarts.
// Nodemon's SIGKILL doesn't reliably kill all child processes.
// Use lsof to find processes holding our port — specific to this server, won't kill other backends.
if (process.env.NODE_ENV !== 'production') {
  try {
    var myPid = process.pid;
    var port = process.env.PORT || 5002;
    var pids = require('child_process')
      .execSync('lsof -ti :' + port + ' 2>/dev/null || true')
      .toString().trim().split('\n').filter(Boolean).map(Number)
      .filter(function(p) { return p !== myPid && p > 0; });
    if (pids.length > 0) {
      pids.forEach(function(p) { try { process.kill(p, 'SIGKILL'); } catch (e) { /* already dead */ } });
      serverLogger.info('Killed zombie processes', { count: pids.length, port, pids: pids.join(', ') });
    }
  } catch (e) { /* lsof not available, skip */ }
}

const app = require('./app');
const { loadJWTSecrets } = require('./middleware/jwt-auth');
const db = require('./db');
const { enqueueScheduleRun, stopPollLoop } = require('./scheduler/scheduleQueue');

const PORT = process.env.PORT || 5002;

var server;

async function start() {
  serverLogger.info('Starting Raike & Sons backend', { 
    nodeEnv: process.env.NODE_ENV,
    dbHost: process.env.DB_HOST,
    dbName: process.env.DB_NAME,
    port: PORT
  });

  // Clear EXPIRED sync locks before accepting requests.
  // Uses a TTL-bounded sweep (acquired_at older than 10 minutes) so a rolling
  // deploy cannot steal active locks held by peer instances still serving traffic.
  // Rationale: MAX_LOCK_AGE = 5 min in sync-lock.js; any lock older than 10 min
  // is definitionally abandoned (heartbeat would have refreshed within 5 min if
  // the owner were still alive). See Phase 07 FIX-01.
  try {
    var cleared = await db('sync_locks')
      .where('acquired_at', '<', db.raw('DATE_SUB(NOW(), INTERVAL 10 MINUTE)'))
      .del();
    if (cleared > 0) serverLogger.info('Cleared expired sync locks', { count: cleared });
  } catch (e) { /* table might not exist yet */ }

  // Load JWT secrets
  await loadJWTSecrets();

  server = app.listen(PORT, () => {
    serverLogger.info('Raike & Sons backend running', { port: PORT });

    // Startup scheduler refresh: only enqueue for users who don't already
    // have pending queue entries. The scheduleQueue's own startup scan
    // picks up anything already in the queue via the in-memory dirty flag;
    // re-inserting here just duplicates rows on every restart.
    Promise.all([
      db('tasks_v').distinct('user_id'),
      db('schedule_queue').distinct('user_id')
    ]).then(function(results) {
      var existing = {};
      results[1].forEach(function(r) { existing[r.user_id] = true; });
      var newUsers = results[0].filter(function(r) { return !existing[r.user_id]; });
      newUsers.forEach(function(r) { enqueueScheduleRun(r.user_id, 'startup'); });
      if (newUsers.length > 0) serverLogger.info('Enqueued startup runs', { userCount: newUsers.length });
    }).catch(function(err) {
      serverLogger.error('Startup enqueue failed', { error: err });
    });
  });

  // Give in-flight requests time to finish on shutdown
  server.keepAliveTimeout = 65000;
  server.headersTimeout = 66000;

  // Start AI usage flusher
  try {
    const { createFlusher } = require('./services/ai-usage-flusher.service');
    const flusher = createFlusher({
      db,
      billingUrl: process.env.BILLING_SERVICE_URL || 'http://localhost:5020',
      serviceKey: process.env.INTERNAL_SERVICE_KEY || '',
      sourceApp:  process.env.AI_USAGE_SOURCE_APP  || 'juggler',
    });
    flusher.start();
    serverLogger.info('AI usage flusher started');
  } catch (err) {
    serverLogger.warn('AI usage flusher failed to start', { error: err });
  }

  // juggler-cal-history Plan D — sharded cron for missed auto-mark + 12mo purge.
  // Non-fatal: server continues if cron init fails.
  try {
    const calHistoryCron = require('./cron/cal-history-cron');
    calHistoryCron.start({
      db: db,
      cache: require('./lib/redis'),
      sseEmitter: require('./lib/sse-emitter')
    });
    serverLogger.info('cal-history-cron started');
  } catch (err) {
    serverLogger.warn('cal-history-cron failed to start', { error: err });
  }
}

// ── Graceful shutdown ──
var shuttingDown = false;

function shutdown(signal) {
  if (shuttingDown) return;
  shuttingDown = true;
  serverLogger.info(`${signal} received - shutting down`);

  stopPollLoop();

  if (process.env.NODE_ENV !== 'production') {
    // Dev mode: exit immediately. Graceful shutdown is pointless when
    // nodemon is about to spawn a replacement — lingering processes
    // create zombie server instances that hold DB locks and ports.
    process.exit(0);
    return;
  }

  // Production: graceful shutdown
  if (server) {
    server.close(function() {
      serverLogger.info('HTTP server closed');
      db.destroy().then(function() {
        serverLogger.info('Database pool destroyed');
        process.exit(0);
      }).catch(function(err) {
        serverLogger.error('Error destroying DB pool:', { error: err });
        process.exit(1);
      });
    });
  }

  setTimeout(function() {
    serverLogger.error('Graceful shutdown timed out - forcing exit');
    process.exit(1);
  }, 5000);
}

process.on('SIGTERM', function() { shutdown('SIGTERM'); });
process.on('SIGINT', function() { shutdown('SIGINT'); });

start().catch(err => {
  serverLogger.error('Fatal startup error:', { error: err });
  process.exit(1);
});

// Handle unhandled rejections — log but don't crash
process.on('unhandledRejection', (reason) => {
  serverLogger.error('Unhandled Rejection:', { reason });
});

// Uncaught exceptions — in production, shut down gracefully; in dev, log and keep running
process.on('uncaughtException', (error) => {
  serverLogger.error('Uncaught Exception:', { error });
  if (process.env.NODE_ENV === 'production') {
    shutdown('uncaughtException');
  }
});

const BATCH_SIZE     = 500;
const INTERVAL_MS    = 60_000;
const MAX_ATTEMPTS   = 10;
const HEALTH_TIMEOUT = 5_000;
const POST_TIMEOUT   = 30_000;

const { aiUsageFlusherLogger } = require('../lib/logger');

class AiUsageFlusher {
  constructor({ db, billingUrl, serviceKey, sourceApp }) {
    this._db         = db;
    this._billingUrl = billingUrl;
    this._serviceKey = serviceKey;
    this._sourceApp  = sourceApp;
    this._timer      = null;
  }

  start() {
    if (this._timer) return;
    this._timer = setInterval(() => { this._tick().catch(() => {}); }, INTERVAL_MS);
    setTimeout(() => { this._tick().catch(() => {}); }, 5_000);
  }

  stop() {
    if (this._timer) { clearInterval(this._timer); this._timer = null; }
  }

  async _tick() {
    try {
      const ctrl = new AbortController();
      const timer = setTimeout(() => ctrl.abort(), HEALTH_TIMEOUT);
      let health;
      try {
        health = await fetch(`${this._billingUrl}/health`, { signal: ctrl.signal });
      } finally {
        clearTimeout(timer);
      }
      if (!health.ok) return;
    } catch {
      return;
    }

    try {
      const rows = await this._db('ai_usage_outbox')
        .select('*')
        .where('flush_attempts', '<', MAX_ATTEMPTS)
        .orderBy('queued_at', 'asc')
        .limit(BATCH_SIZE);

      if (!rows || rows.length === 0) return;

      const ids    = rows.map(r => r.id);
      const events = rows.map(r => ({
        id:             r.id,
        user_id:        r.user_id,
        use_case:       r.use_case,
        model_name:     r.model_name,
        model_params:   r.model_params ? JSON.parse(r.model_params) : null,
        tokens_in:      r.tokens_in,
        tokens_out:     r.tokens_out,
        latency_ms:     r.latency_ms,
        error_flag:     Boolean(r.error_flag),
        error_type:     r.error_type,
        correlation_id: r.correlation_id,
        occurred_at:    r.occurred_at,
      }));

      try {
        const ctrl = new AbortController();
        const timer = setTimeout(() => ctrl.abort(), POST_TIMEOUT);
        let resp;
        try {
          resp = await fetch(`${this._billingUrl}/internal/ai-usage/ingest`, {
            method:  'POST',
            headers: { 'Content-Type': 'application/json', 'x-internal-key': this._serviceKey },
            body:    JSON.stringify({ source_app: this._sourceApp, events }),
            signal:  ctrl.signal,
          });
        } finally {
          clearTimeout(timer);
        }
        if (resp.ok) {
          await this._db('ai_usage_outbox').whereIn('id', ids).delete();
        } else {
          await this._db('ai_usage_outbox').whereIn('id', ids).increment('flush_attempts', 1);
        }
      } catch {
        await this._db('ai_usage_outbox').whereIn('id', ids).increment('flush_attempts', 1);
      }
    } catch (err) {
      aiUsageFlusherLogger.warn('Tick error', { error: err });
    }
  }
}

let _instance = null;

function createFlusher(deps) {
  _instance = new AiUsageFlusher(deps);
  return _instance;
}

module.exports = { AiUsageFlusher, createFlusher };

/**
 * AppleCalendarAdapter.js
 * CalendarPort implementation for Apple Calendar (iCloud CalDAV).
 *
 * Refactored from: lib/apple-cal-api.js + lib/cal-adapters/apple.adapter.js
 */

const crypto = require('crypto');

// Dependencies (resolved at runtime)
let appleCalApi, db, calSyncHelpers, localToUtc, PLACEMENT_MODES, decrypt;

const providerId = 'apple';

/**
 * Initialize adapter dependencies
 */
function initialize(deps = {}) {
  appleCalApi = deps.appleCalApi || require('../../../lib/apple-cal-api');
  db = deps.db || require('../../../db');
  calSyncHelpers = deps.calSyncHelpers || require('../../../controllers/cal-sync-helpers');
  localToUtc = deps.localToUtc || require('../../../scheduler/dateHelpers').localToUtc;
  PLACEMENT_MODES = deps.PLACEMENT_MODES || require('../../../lib/placementModes').PLACEMENT_MODES;
  decrypt = deps.decrypt || require('../../../lib/credential-encrypt').decrypt;
}

// --- Connection & Token Management ---

function isConnected(user) {
  return !!user.apple_cal_username && !!user.apple_cal_password && !!user.apple_cal_calendar_url;
}

async function getValidAccessToken(user) {
  if (!user.apple_cal_username || !user.apple_cal_password) {
    throw new Error('Apple Calendar not connected');
  }
  const password = decrypt(user.apple_cal_password);
  const serverUrl = user.apple_cal_server_url || appleCalApi.DEFAULT_SERVER_URL;
  return appleCalApi.createClient(serverUrl, user.apple_cal_username, password);
}

// --- Multi-Calendar Support ---

async function getEnabledCalendars(userId) {
  const calendars = await db('user_calendars')
    .where({ user_id: userId, provider: 'apple', enabled: true });

  if (calendars.length > 0) {
    return calendars;
  }

  // Fallback: legacy single-calendar from users table
  const user = await db('users').where('id', userId).first();
  if (user && user.apple_cal_calendar_url) {
    return [{
      id: null,
      calendar_id: user.apple_cal_calendar_url,
      display_name: null,
      sync_direction: 'full',
      ingest_mode: 'task'
    }];
  }

  return [];
}

async function getWriteCalendar(userId) {
  const calendars = await getEnabledCalendars(userId);
  const fullSync = calendars.filter(c => c.sync_direction === 'full');
  return fullSync.length > 0 ? fullSync[0] : null;
}

// --- Event CRUD Operations ---

async function getEvents(client, startDate, endDate, userId) {
  const calendars = await getEnabledCalendars(userId);
  if (calendars.length === 0) {
    throw new Error('Apple Calendar: no calendars enabled');
  }

  const allEvents = [];
  let hasPartialFailure = false;

  for (const cal of calendars) {
    try {
      const events = await appleCalApi.listEvents(client, cal.calendar_id, startDate, endDate);
      const normalized = events.map(e => {
        const ne = normalizeEvent(e);
        ne.calendarId = cal.calendar_id;
        return ne;
      });
      allEvents.push(...normalized);
    } catch (e) {
      hasPartialFailure = true;
      // Log error but continue with other calendars
    }
  }

  // Update sync tokens
  try {
    const fetchedCalendars = await client.fetchCalendars();
    for (let j = 0; j < calendars.length; j++) {
      const userCal = calendars[j];
      const remoteCal = fetchedCalendars.find(c => c.url === userCal.calendar_id);
      if (remoteCal && (remoteCal.syncToken || remoteCal.ctag)) {
        if (j === 0) {
          await db('users').where('id', userId).update({
            apple_cal_sync_token: remoteCal.syncToken || remoteCal.ctag
          });
        }
      }
    }
  } catch (e) {
    // Ignore sync token update failures
  }

  if (hasPartialFailure) {
    allEvents._hasPartialFailure = true;
  }
  return allEvents;
}

async function createEvent(client, event, userId, year, tz, opts) {
  const writeCal = await getWriteCalendar(userId);
  if (!writeCal) throw new Error('No Apple calendar available for writing');

  const calendarUrl = writeCal.calendar_id;
  const result = await appleCalApi.createEvent(client, calendarUrl, event, year, tz);
  return {
    providerEventId: result.providerEventId,
    calendarId: calendarUrl,
    raw: result
  };
}

async function updateEvent(client, eventId, event, userId, year, tz, opts) {
  await appleCalApi.updateEvent(client, eventId, event, year, tz);
}

async function deleteEvent(client, eventId) {
  await appleCalApi.deleteEvent(client, eventId);
}

async function sync(client, user) {
  const syncToken = user.apple_cal_sync_token;
  if (!syncToken) return { hasChanges: true };

  const calendarUrl = user.apple_cal_calendar_url;
  if (!calendarUrl) return { hasChanges: true };

  const result = await appleCalApi.checkForChanges(client, calendarUrl, syncToken);

  if (!result.hasChanges && result.syncToken && result.syncToken !== syncToken) {
    await db('users').where('id', user.id).update({
      apple_cal_sync_token: result.syncToken
    });
  }

  return result;
}

// --- Batch Operations (Sequential for CalDAV) ---

async function batchCreateEvents(client, taskEventPairs, year, tz) {
  const results = [];
  for (const pair of taskEventPairs) {
    const userId = pair.task.userId || pair.task.user_id;
    try {
      const result = await createEvent(client, pair.task, userId, year, tz);
      results.push({
        taskId: pair.task.id,
        providerEventId: result.providerEventId,
        raw: result.raw,
        error: null
      });
    } catch (e) {
      results.push({
        taskId: pair.task.id,
        providerEventId: null,
        raw: null,
        error: e.message
      });
    }
  }
  return results;
}

async function batchDeleteEvents(client, eventUrls) {
  const results = [];
  for (const eventUrl of eventUrls) {
    try {
      await deleteEvent(client, eventUrl);
      results.push({ eventId: eventUrl, error: null });
    } catch (e) {
      // Treat 404/410 as success
      if (e.message && (e.message.includes('404') || e.message.includes('410'))) {
        results.push({ eventId: eventUrl, error: null });
      } else {
        results.push({ eventId: eventUrl, error: e.message });
      }
    }
  }
  return results;
}

// --- Helper Functions ---

function normalizeEvent(event) {
  return {
    id: event.id || event._url || '',
    title: event.title || '(No title)',
    description: event.description || '',
    startDateTime: event.startDateTime || '',
    endDateTime: event.endDateTime || '',
    startTimezone: event.startTimezone || null,
    isAllDay: !!event.isAllDay,
    durationMinutes: event.durationMinutes || 30,
    lastModified: event.lastModified || null,
    isTransparent: !!event.isTransparent,
    _url: event._url || null,
    _etag: event._etag || null,
    _raw: event._raw || null
  };
}

function eventHash(event) {
  const str = [
    event.title || '',
    event.startDateTime || '',
    event.endDateTime || '',
    event.description || '',
    event.isTransparent ? 'transparent' : 'opaque',
    event.isAllDay ? 'allday' : 'timed'
  ].join('|');
  return crypto.createHash('sha256').update(str).digest('hex');
}

function applyEventToTaskFields(event, tz, currentTask) {
  const isAllDay = event.isAllDay;
  const jd = calSyncHelpers.isoToJugglerDate(event.startDateTime, tz);

  const fields = {
    text: event.title,
    dur: event.durationMinutes,
    updated_at: db.fn.now()
  };

  if (jd.date) {
    if (isAllDay) {
      fields.scheduled_at = localToUtc(jd.date, '12:00 AM', tz);
    } else if (jd.time) {
      fields.scheduled_at = localToUtc(jd.date, jd.time, tz);
    }
  }

  if (isAllDay) {
    fields.placement_mode = PLACEMENT_MODES.ALL_DAY;
  }

  if (event.isTransparent) {
    fields.placement_mode = PLACEMENT_MODES.REMINDER;
  }

  if (!event.isTransparent && currentTask?.placement_mode === PLACEMENT_MODES.REMINDER) {
    fields.placement_mode = PLACEMENT_MODES.ANYTIME;
  }

  if (!isAllDay) {
    const dateChanged = jd.date && jd.date !== currentTask?.date;
    const timeChanged = jd.time && jd.time !== currentTask?.time;
    if (dateChanged || timeChanged) {
      fields.placement_mode = PLACEMENT_MODES.FIXED;
    }
  }

  return fields;
}

function getEventIdColumn() {
  return 'apple_event_id';
}

function getLastSyncedColumn() {
  return 'apple_cal_last_synced_at';
}

